INSERT INTO questions (question_id, chapter, keyword, difficulty, bloom_level, question_text, choice_a, choice_b, choice_c, choice_d, correct_answer, explanation, incorrect_explanation, source)
VALUES
('Q1-001', '第1章', '人工知能（AI）の定義', '易', '記憶（知識）', '人工知能（AI）の説明として最も適切なものはどれか。', '人間の知的活動をコンピュータによって実現しようとする技術の総称', 'インターネットを介して複数のコンピュータを接続する技術', '大量のデータを高速に保存・管理するデータベース技術', 'コンピュータのハードウェアを小型化する技術', 'A', '人工知能（AI：Artificial Intelligence）とは、人間の知的活動（認識、判断、学習、推論など）をコンピュータによって実現しようとする技術の総称である。医療分野では画像診断支援、問診支援、医療文書作成支援など、さまざまな場面で活用されている。', 'B：インターネット接続技術はネットワーク技術の説明であり、AIとは異なる。\nC：データベース技術はデータ管理の手法であり、AIの定義には該当しない。\nD：ハードウェアの小型化は半導体技術や電子工学の領域であり、AIとは別の概念。', 'AI白書2024（IPA）'),
('Q1-002', '第1章', '機械学習（Machine Learning）', '易', '記憶（知識）', '機械学習における「教師あり学習」の説明として最も適切なものはどれか。', '正解ラベルのないデータからパターンを自動的に発見する学習手法', '報酬と罰則に基づいて最適な行動を学習する手法', '正解ラベル付きのデータを用いて入力と出力の関係を学習する手法', '人間の脳の神経回路を模倣した学習手法', 'C', '教師あり学習（Supervised Learning）とは、入力データと正解ラベル（教師データ）のペアを用いて、入力から正解を予測するモデルを学習する手法である。医療分野では、画像と診断結果のペアから画像診断モデルを学習する場合などに用いられる。', 'A：正解ラベルなしでパターンを発見するのは「教師なし学習」の説明。クラスタリングなどが該当する。\nB：報酬と罰則に基づく学習は「強化学習」の説明であり、教師あり学習とは異なる。\nD：脳の神経回路を模倣するのはニューラルネットワーク/深層学習の説明であり、学習手法の分類とは別の概念。', 'AI白書2024（IPA）'),
('Q1-003', '第1章', '深層学習（Deep Learning）', '標準', '理解', '深層学習（ディープラーニング）が従来の機械学習と比較して優れている点として最も適切なものはどれか。', '少量のデータでも高精度な予測が可能である', '特徴量を人間が設計する必要がなく、データから自動的に学習できる', '計算コストが低く、高速に処理できる', 'モデルの判断根拠が人間にとって理解しやすい', 'C', '深層学習の大きな特徴は、多層のニューラルネットワークによって、データから特徴量を自動的に抽出・学習できる点にある。従来の機械学習では人間が特徴量を設計する必要があったが、深層学習ではこの工程が不要となり、画像認識や自然言語処理などで飛躍的な性能向上を実現した。', 'A：深層学習は一般的に大量のデータを必要とし、少量データでの学習は苦手とされる。\nC：深層学習は多層構造のため計算コストが高く、GPUなどの高性能ハードウェアを必要とすることが多い。\nD：深層学習はブラックボックス性が高く、判断根拠の解釈が困難であることが課題として指摘されている。', 'AI白書2024（IPA）'),
('Q1-004', '第1章', '生成AI（Generative AI）', '易', '記憶（知識）', '生成AI（Generative AI）の説明として最も適切なものはどれか。', '入力データを分類・識別することを主目的としたAI', 'テキスト、画像、音声などの新しいコンテンツを生成することができるAI', 'センサーから得られたデータをリアルタイムで処理するAI', '過去のデータから将来の数値を予測することを主目的としたAI', 'B', '生成AI（Generative AI）とは、学習したデータのパターンをもとに、テキスト、画像、音声、プログラムコードなどの新しいコンテンツを生成できるAIの総称である。ChatGPTやClaude、画像生成AIなどが代表例であり、医療分野では医療文書の下書き作成や患者説明資料の生成などに活用されている。', 'A：分類・識別を主目的とするのは「識別系AI」であり、生成AIとは異なる機能を持つ。\nC：センサーデータのリアルタイム処理はIoTやエッジコンピューティングの領域であり、生成AIの定義には該当しない。\nD：数値予測を主目的とするのは「予測系AI」であり、生成AIとは異なる。', 'AI事業者ガイドライン（第1.1版）／AI白書2024（IPA）'),
('Q1-005', '第1章', '大規模言語モデル（LLM）', '標準', '理解', '大規模言語モデル（LLM）に関する説明として適切でないものはどれか。', '大量のテキストデータを用いて事前学習されている', '文章の生成、要約、翻訳など多様なタスクに対応できる', '医療分野の専門知識については常に正確な情報を出力する', 'GPT、Claude、Geminiなどが代表的なモデルとして知られている', 'C', '大規模言語モデル（LLM）は大量のテキストデータから言語パターンを学習しており、多様なタスクに対応できるが、医療分野の専門知識について常に正確とは限らない。ハルシネーション（事実と異なる情報の生成）のリスクがあり、医療情報の正確性については人間による検証が不可欠である。', 'A：LLMは数千億語以上のテキストデータで事前学習されており、この記述は正しい。\nB：LLMは文章生成、要約、翻訳、質問応答など多様なタスクに対応可能であり、この記述は正しい。\nD：GPT（OpenAI）、Claude（Anthropic）、Gemini（Google）は代表的なLLMであり、この記述は正しい。', 'AI白書2024（IPA）／AI事業者ガイドライン（第1.1版）'),
('Q1-006', '第1章', 'ハルシネーション（幻覚）', '易', '記憶（知識）', '生成AIが事実とは異なる情報をあたかも正しいかのように出力する現象を何と呼ぶか。', 'オーバーフィッティング', 'データポイズニング', 'プロンプトインジェクション', 'ハルシネーション', 'D', 'ハルシネーション（Hallucination：幻覚）とは、生成AIが学習データに基づいて尤もらしいが事実とは異なる情報を生成する現象である。医療分野では誤った薬剤名や用量、存在しないガイドラインの引用などが生じる可能性があり、特にリスクが高いため、AI出力の検証が必須である。', 'A：オーバーフィッティング（過学習）は、モデルが学習データに過度に適合し汎化性能が低下する現象であり、出力内容の正確性とは異なる概念。\nB：データポイズニングは学習データに不正なデータを混入させる攻撃手法であり、出力時の現象ではない。\nC：プロンプトインジェクションは悪意ある指示を入力に埋め込む攻撃手法であり、AI自身が自発的に誤情報を生成する現象とは異なる。', 'AI事業者ガイドライン（第1.1版）／AI白書2024（IPA）'),
('Q1-007', '第1章', 'RAG（検索拡張生成）', '標準', '理解', 'RAG（Retrieval-Augmented Generation：検索拡張生成）の特徴として最も適切なものはどれか。', 'モデル自体を再学習させることで精度を向上させる', '外部の知識ベースから情報を検索し、その結果をもとに回答を生成する', '人間のフィードバックをもとにモデルの出力を改善する', '複数のAIモデルを組み合わせてアンサンブル学習を行う', 'A', 'RAG（Retrieval-Augmented Generation：検索拡張生成）は、ユーザーの質問に対してまず外部の知識ベースやデータベースを検索し、取得した情報をコンテキストとしてLLMに渡すことで、より正確で最新の情報に基づいた回答を生成する手法である。医療分野では院内ガイドラインや薬剤データベースと連携することで、ハルシネーションの低減が期待される。', 'A：モデルの再学習はファインチューニングの説明であり、RAGはモデル自体を変更せず外部知識を参照する点が特徴。\nC：人間のフィードバックによる改善はRLHF（Reinforcement Learning from Human Feedback）の説明であり、RAGとは別の手法。\nD：複数モデルの組み合わせはアンサンブル学習の説明であり、RAGとは異なる。', 'AI白書2024（IPA）'),
('Q1-008', '第1章', 'Transformer', '標準', '理解', '大規模言語モデル（LLM）の基盤技術であるTransformerの特徴として最も適切なものはどれか。', '畳み込み演算により画像の特徴を抽出する', 'Attention機構により入力系列の各要素間の関連性を学習する', '決定木を複数組み合わせて予測精度を向上させる', '遺伝的アルゴリズムにより最適解を探索する', 'A', 'Transformerは2017年にGoogleが発表した深層学習アーキテクチャで、Self-Attention機構を用いて入力系列の各要素間の関連性を効率的に学習できることが特徴である。この技術がGPT、Claude、GeminiなどのLLMの基盤となっており、自然言語処理において革新的な性能向上をもたらした。', 'A：畳み込み演算による特徴抽出はCNN（畳み込みニューラルネットワーク）の特徴であり、Transformerとは異なる。\nC：決定木の組み合わせはランダムフォレストや勾配ブースティングの手法であり、Transformerとは関係がない。\nD：遺伝的アルゴリズムは進化計算の一種であり、Transformerのアーキテクチャとは異なる概念。', 'AI白書2024（IPA）'),
('Q1-009', '第1章', 'ファインチューニング', '標準', '理解', 'ファインチューニングの説明として最も適切なものはどれか。', '学習済みモデルを特定のドメインやタスクのデータで追加学習させる手法', 'モデルのパラメータ数を増やして性能を向上させる手法', '入力プロンプトを工夫することで出力の質を向上させる手法', '複数のモデルの出力を統合して最終的な回答を得る手法', 'A', 'ファインチューニング（Fine-tuning）とは、大量のデータで事前学習された汎用モデルを、特定のドメインやタスクに特化したデータでさらに追加学習させる手法である。医療分野では、医学論文や診療記録などの医療テキストでファインチューニングすることで、医療に特化したモデルを構築できる。', 'B：パラメータ数の増加はモデルのスケーリングに関する話であり、ファインチューニングとは異なる。\nC：入力プロンプトの工夫はプロンプトエンジニアリングの説明であり、モデル自体の学習を伴わない。\nD：複数モデルの出力統合はアンサンブル手法の説明であり、ファインチューニングとは異なる。', 'AI白書2024（IPA）'),
('Q1-010', '第1章', '主要生成AIサービス', '易', '記憶（知識）', '主要な生成AIサービスとその開発元の組み合わせとして正しいものはどれか。', 'ChatGPT — Google', 'Gemini — OpenAI', 'Claude — Anthropic', 'Copilot — Meta', 'C', 'Claudeは、AI安全性研究を重視するAnthropic社が開発した大規模言語モデルである。医療分野でも活用が進んでおり、長文の文脈理解や丁寧な応答が特徴として評価されている。', 'A：ChatGPTはGoogleではなくOpenAIが開発したサービスである。\nB：GeminiはOpenAIではなくGoogleが開発したモデルである。\nD：CopilotはMetaではなくMicrosoftのサービスであり、OpenAIのGPTモデルを基盤としている。', 'AI白書2024（IPA）'),
('Q1-011', '第1章', 'トークン／トークナイズ', '標準', '理解', '大規模言語モデルにおける「トークン」の説明として最も適切なものはどれか。', 'モデルの学習に使用するデータセットの単位', 'テキストを処理する際の分割単位であり、単語や部分文字列に相当する', 'AIサービスを利用するための認証キー', 'モデルのパラメータを格納するメモリ領域', 'D', 'トークンとは、大規模言語モデルがテキストを処理する際の基本単位である。英語では概ね単語単位、日本語では文字や部分文字列単位で分割（トークナイズ）される。トークン数はAPIの利用料金や処理可能な文章量（コンテキスト長）に影響するため、医療文書を扱う際はトークン数を意識する必要がある。', 'A：データセットの単位はサンプルやレコードと呼ばれ、トークンとは異なる概念。\nC：認証キーはAPIキーやアクセストークンと呼ばれるが、LLMのテキスト処理単位としてのトークンとは異なる。\nD：メモリ領域の話はハードウェアやシステム設計に関するものであり、トークンの定義とは異なる。', 'AI白書2024（IPA）'),
('Q1-012', '第1章', '事前学習（Pre-training）', '標準', '理解', '大規模言語モデルの事前学習（Pre-training）の説明として最も適切なものはどれか。', '特定のタスクに特化したデータで追加学習を行うこと', '大量のテキストデータを用いて言語の一般的なパターンを学習すること', 'モデルの出力を人間が評価してフィードバックを与えること', '学習済みモデルのパラメータを初期化すること', 'A', '事前学習（Pre-training）とは、大規模言語モデルをインターネット上の膨大なテキストデータ（書籍、ウェブページ、論文など）で学習させ、言語の一般的な構造やパターン、知識を獲得させる過程である。この事前学習によりモデルは汎用的な言語能力を獲得し、その後のファインチューニングで特定タスクに適応させることが可能となる。', 'A：特定タスクへの追加学習はファインチューニングの説明であり、事前学習とは異なる。\nC：人間のフィードバックによる学習はRLHFの説明であり、事前学習の後に行われる工程。\nD：パラメータの初期化は学習前の準備段階であり、事前学習そのものではない。', 'AI白書2024（IPA）'),
('Q1-013', '第1章', 'マルチモーダル', '易', '記憶（知識）', 'マルチモーダルAIの説明として最も適切なものはどれか。', 'テキスト、画像、音声など複数の種類のデータを統合的に処理できるAI', '複数の言語に対応した翻訳機能を持つAI', '複数のユーザーが同時にアクセスできるAIシステム', '複数のクラウドサービスで分散処理を行うAI', 'A', 'マルチモーダルAIとは、テキスト、画像、音声、動画など複数の種類のデータ（モダリティ）を統合的に入力・処理・出力できるAIのことである。医療分野では、患者の症状説明（テキスト）とレントゲン画像（画像）を組み合わせた診断支援など、複合的な情報処理への活用が期待されている。', 'B：多言語対応は翻訳AIや多言語モデルの特徴であり、マルチモーダルとは別の概念。\nC：複数ユーザーの同時アクセスはシステムのスケーラビリティに関する話であり、マルチモーダルとは異なる。\nD：クラウドでの分散処理はインフラ構成の話であり、マルチモーダルの定義には該当しない。', 'AI白書2024（IPA）'),
('Q1-014', '第1章', 'AIの種類と分類', '易', '記憶（知識）', 'AIの機能による分類において、「識別系AI」に該当するものはどれか。', '過去の売上データから将来の売上を予測するAI', '入力された画像が犬か猫かを判定するAI', '質問に対して文章で回答を生成するAI', 'チェスや囲碁で最適な一手を選択するAI', 'B', '識別系AIとは、入力されたデータを分類・識別することを目的としたAIである。画像認識（犬か猫かの判定、医療画像の病変検出など）、音声認識、スパムメール判定などが代表例である。医療分野では、画像診断支援（良性/悪性の判定など）に活用されている。', 'A：売上予測は「予測系AI」に分類される。時系列データから将来の数値を予測する。\nC：文章での回答生成は「生成系AI」に分類される。新しいコンテンツを作り出す機能を持つ。\nD：ゲームでの最適手選択は「実行系AI」または強化学習ベースのAIに分類される。', 'AI白書2024（IPA）'),
('Q1-015', '第1章', 'AIの歴史と発展', '標準', '理解', 'AI（人工知能）の歴史に関する説明として最も適切なものはどれか。', '第1次AIブームでは深層学習が発明され、画像認識精度が飛躍的に向上した', '第2次AIブームではエキスパートシステムが注目されたが、知識獲得のボトルネックが課題となった', '第3次AIブームは1990年代に始まり、インターネットの普及が主な要因であった', 'AIという用語は2000年代に初めて提唱された', 'B', '第2次AIブーム（1980年代）では、専門家の知識をルール化したエキスパートシステムが注目された。しかし、専門知識をルールとして記述・維持する作業（知識獲得のボトルネック）が困難であったことや、未知の状況に対応できない限界から、ブームは終息した。', 'A：深層学習が注目されたのは第3次AIブーム（2010年代〜）であり、第1次AIブーム（1950〜60年代）ではない。\nC：第3次AIブームは2010年代に深層学習の進展により始まった。1990年代はAI冬の時代とも呼ばれる停滞期であった。\nD：AI（Artificial Intelligence）という用語は1956年のダートマス会議で初めて使われた。', 'AI白書2024（IPA）'),
('Q1-016', '第1章', 'API（Application Programming Interface）', '易', '記憶（知識）', '生成AIサービスにおけるAPI（Application Programming Interface）の役割として最も適切なものはどれか。', 'AIモデルの学習データを暗号化して保護する', '外部のシステムやアプリケーションからAIモデルの機能を呼び出すためのインターフェース', 'AIモデルのパラメータを自動的に最適化する', 'ユーザーの入力データを自動的にバックアップする', 'B', 'API（Application Programming Interface）とは、外部のシステムやアプリケーションからAIモデルの機能を呼び出すためのインターフェースである。医療機関では、電子カルテシステムや院内システムからAPIを通じて生成AIを利用することで、業務システムとの連携が可能となる。', 'A：データの暗号化はセキュリティ機能であり、APIの主要な役割ではない。\nC：パラメータの自動最適化は学習アルゴリズムの機能であり、APIとは異なる。\nD：データのバックアップはストレージ管理の機能であり、APIの役割ではない。', 'AI白書2024（IPA）'),
('Q1-017', '第1章', 'クラウド／オンプレミス／エッジAI', '標準', '理解', '医療機関がAIを導入する際の実行環境として、オンプレミス環境を選択する主な理由はどれか。', '初期導入コストを最小限に抑えられるため', '常に最新のAIモデルに自動更新されるため', '患者データを院内に留め、外部へのデータ流出リスクを低減できるため', 'インターネット接続がない環境でも高性能なAI処理が保証されるため', 'C', 'オンプレミス環境とは、自組織内にサーバーやシステムを設置して運用する形態である。医療機関では、患者の診療情報（要配慮個人情報）を外部に送信せず院内で処理できるため、情報漏洩リスクの低減やデータガバナンスの確保を目的としてオンプレミスが選択されることがある。', 'A：オンプレミスは一般的にクラウドより初期導入コストが高い。ハードウェア購入や設置工事が必要となる。\nB：自動更新はクラウドサービスの特徴であり、オンプレミスでは手動での更新作業が必要。\nD：オンプレミスでもインターネット接続が不要とは限らず、また高性能が保証されるわけではない。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q1-018', '第1章', 'オープンソース／プロプライエタリモデル', '標準', '理解', 'オープンソースの大規模言語モデルを医療機関が利用する際の特徴として最も適切なものはどれか。', 'モデルの内部構造が非公開のため、セキュリティが高い', '利用料金が従量課金制であり、使用量に応じたコストが発生する', 'モデルを自組織のサーバーで運用でき、データを外部に送信せずに利用できる', '開発元の企業による24時間サポートが標準で提供される', 'C', 'オープンソースモデル（Llama、Mistralなど）は、モデルの重みが公開されているため、自組織のサーバーにダウンロードして運用することが可能である。これにより、患者データを外部のクラウドサービスに送信せずにAIを利用でき、医療情報の安全管理の観点から有利となる場合がある。', 'A：オープンソースは内部構造が公開されているため、この記述は誤り。ただし公開されていることでセキュリティ検証がしやすい利点もある。\nB：従量課金制は商用クラウドAPIサービスの特徴であり、オープンソースモデル自体には該当しない。\nD：オープンソースは通常、企業による公式サポートは提供されず、コミュニティサポートが中心となる。', 'AI白書2024（IPA）'),
('Q1-019', '第1章', '基盤モデル／Foundation Model', '易', '記憶（知識）', '基盤モデル（Foundation Model）の特徴として最も適切なものはどれか。', '特定のタスク専用に設計された小規模なモデル', '大量のデータで学習され、多様なタスクに適応可能な汎用性の高いモデル', '医療分野のみで使用される専門特化型のモデル', 'ルールベースで動作する従来型のエキスパートシステム', 'D', '基盤モデル（Foundation Model）とは、大量のデータで事前学習され、文章生成、翻訳、要約、質問応答など多様なタスクに適応可能な汎用性の高いAIモデルの総称である。GPT、Claude、Geminiなどが代表例であり、ファインチューニングやプロンプト設計により医療分野にも適応できる。', 'A：基盤モデルは大規模かつ汎用的であり、特定タスク専用の小規模モデルとは異なる。\nC：基盤モデルは医療に限定されず、多分野で活用できる汎用モデルである。\nD：基盤モデルは深層学習ベースであり、ルールベースのエキスパートシステムとは技術的に異なる。', 'AI白書2024（IPA）'),
('Q1-020', '第1章', '人工知能（AI）の定義', '難', '分析', '医療現場で使用されるAIシステムの分類として、「汎用型AI（AGI）」と「特化型AI」の違いに関する説明として最も適切なものはどれか。', '現在医療現場で実用化されているAIの多くは汎用型AIであり、あらゆる診療科の業務に対応できる', '特化型AIは特定のタスク（画像診断、問診支援など）に限定して高い性能を発揮するが、他のタスクには適用できない', '汎用型AIはすでに実用化されており、医師の業務をすべて代替することが可能である', '特化型AIと汎用型AIは技術的に同一であり、設定の変更だけで相互に切り替え可能である', 'A', '現在実用化されているAIは「特化型AI（Narrow AI）」であり、特定のタスク（画像診断支援、文書作成支援など）に特化して設計されている。一方、人間のようにあらゆる知的タスクに対応できる「汎用型AI（AGI：Artificial General Intelligence）」は研究段階であり、まだ実現していない。医療AIを導入する際は、そのAIが対応できるタスクの範囲を理解することが重要である。', 'A：現在医療現場で実用化されているAIの多くは特化型AIであり、汎用型AIはまだ実現していない。\nC：汎用型AIは研究段階であり実用化されていない。また、AIが医師の業務をすべて代替することは現時点では不可能。\nD：特化型AIと汎用型AIは技術的に異なり、設定変更で切り替えられるものではない。', 'AI白書2024（IPA）'),
('Q1-021', '第1章', '機械学習（Machine Learning）', '標準', '適用', '病院の医療情報部門が、過去の患者データを用いて再入院リスクを予測するAIモデルを開発する場合、最も適切な機械学習の手法はどれか。', '教師あり学習により、過去の再入院有無をラベルとして学習させる', '教師なし学習により、患者データのクラスタリングのみを行う', '強化学習により、報酬を設定してモデルを訓練する', '転移学習により、画像認識モデルをそのまま適用する', 'A', '再入院リスクの予測は、過去の患者データに「再入院した／しなかった」という正解ラベルが付与できるため、教師あり学習が適している。患者の属性（年齢、疾患、治療内容など）を入力として、再入院の有無を予測するモデルを学習することで、リスクの高い患者を早期に特定できる。', 'B：教師なし学習のクラスタリングは患者のグループ分けには有用だが、再入院の予測には直接使えない。予測タスクには正解ラベルが必要。\nC：強化学習は環境との相互作用を通じて学習する手法であり、再入院予測のような静的なデータからの予測には不向き。\nD：転移学習は有用だが、画像認識モデルをそのまま再入院予測に適用することはできない。', 'AI白書2024（IPA）'),
('Q1-022', '第1章', '深層学習（Deep Learning）', '易', '記憶（知識）', '深層学習で用いられるニューラルネットワークの構成要素として適切でないものはどれか。', '入力層', '隠れ層（中間層）', '出力層', '決定木層', 'D', 'ニューラルネットワークは、入力層、隠れ層（中間層）、出力層から構成される。深層学習（ディープラーニング）では、この隠れ層を多層に重ねることで複雑なパターンを学習できる。決定木は別の機械学習手法であり、ニューラルネットワークの構成要素ではない。', 'A：入力層はデータを受け取る最初の層であり、ニューラルネットワークの基本構成要素。\nB：隠れ層（中間層）は入力と出力の間で特徴を抽出する層であり、深層学習ではこれを多層化する。\nC：出力層は最終的な予測結果を出力する層であり、ニューラルネットワークの基本構成要素。', 'AI白書2024（IPA）'),
('Q1-023', '第1章', '生成AI（Generative AI）', '難', '分析', '医療機関が生成AIを業務に導入する際のリスク評価として、最も優先的に検討すべき事項はどれか。', '生成AIの導入によるシステム応答速度の低下', '生成AIが出力する情報の正確性と、患者安全への影響', '生成AIサービスのユーザーインターフェースの使いやすさ', '生成AIの導入に必要なスタッフのトレーニング時間', 'B', '医療分野で生成AIを導入する際、最優先で検討すべきは患者安全である。生成AIにはハルシネーション（誤情報の生成）のリスクがあり、誤った医療情報が患者の治療判断に影響すると重大な健康被害につながる可能性がある。そのため、出力の正確性検証体制と患者安全への影響評価を最優先で行う必要がある。', 'A：システム応答速度も考慮事項だが、患者安全と比較すると優先度は低い。\nC：UIの使いやすさは運用上重要だが、安全性の検討が先行すべきである。\nD：トレーニング時間も計画に含めるべきだが、患者安全のリスク評価が最優先。', 'AI事業者ガイドライン（第1.1版）／HAIPガイドライン（厚生労働省）'),
('Q1-024', '第1章', '大規模言語モデル（LLM）', '標準', '理解', '大規模言語モデル（LLM）の「コンテキスト長（コンテキストウィンドウ）」に関する説明として最も適切なものはどれか。', 'モデルが一度に処理できる入力と出力の合計トークン数の上限', 'モデルの学習に使用されたデータの総量', 'モデルが回答を生成するまでの処理時間', 'モデルのパラメータ数を表す指標', 'A', 'コンテキスト長（コンテキストウィンドウ）とは、LLMが一度の処理で参照できる入力テキストと出力テキストの合計トークン数の上限を指す。医療文書作成支援では、長い診療記録を参照する必要があるため、コンテキスト長が長いモデルが有利となることがある。', 'B：学習データの総量はコンテキスト長とは別の概念。コンテキスト長は推論時の制約。\nC：処理時間（レイテンシー）はコンテキスト長とは異なる性能指標。\nD：パラメータ数はモデルの規模を表す指標であり、コンテキスト長とは別の概念。', 'AI白書2024（IPA）'),
('Q1-025', '第1章', 'ハルシネーション（幻覚）', '難', '評価', '医師が生成AIを使用して患者への説明文書を作成する際、ハルシネーションによるリスクを低減するための対策として最も効果的なものはどれか。', 'より高価な生成AIサービスを利用する', '生成AIの出力をそのまま使用し、患者からのフィードバックを待つ', '生成AIの出力を医師が必ず確認し、医学的根拠に照らして内容を検証する', '生成AIへの入力文を短くして、出力の量を減らす', 'C', 'ハルシネーションのリスク低減には、AI出力の人間による検証が最も効果的である。医師は専門的知識に基づいて、生成された説明文書の内容が医学的に正確か、最新のエビデンスに沿っているかを確認し、必要に応じて修正を加えてから患者に提供すべきである。これはAI活用における「医師の最終判断原則」にも沿った対応である。', 'A：高価なサービスでもハルシネーションは発生し得る。価格と正確性は必ずしも比例しない。\nB：患者に未検証の情報を提供することは安全上許容されない。問題発生後の対応では遅い。\nD：入力を短くしても出力の正確性は保証されず、根本的な対策にはならない。', 'HAIPガイドライン（厚生労働省）／AI事業者ガイドライン（第1.1版）'),
('Q1-026', '第1章', 'RAG（検索拡張生成）', '難', '適用', '医療機関がRAG（検索拡張生成）を用いて院内の診療ガイドラインに基づく回答システムを構築する場合、最も重要な考慮事項はどれか。', 'AIモデルのパラメータ数を可能な限り大きくする', '参照する知識ベースの情報を常に最新かつ正確に保つ', 'ユーザーインターフェースのデザインを優先する', 'システムの応答速度を最優先で最適化する', 'A', 'RAGの精度は、参照する知識ベース（この場合は院内診療ガイドライン）の質に大きく依存する。ガイドラインが古い情報や誤った内容を含んでいると、AIの出力も不正確になる。そのため、知識ベースの定期的な更新と内容の正確性の担保が最も重要な考慮事項となる。', 'A：パラメータ数の増大は必ずしも精度向上につながらず、RAGでは知識ベースの質がより重要。\nC：UIデザインも重要だが、医療情報の正確性確保が優先される。\nD：応答速度も考慮事項だが、医療分野では正確性が速度より重要。', 'AI白書2024（IPA）'),
('Q1-027', '第1章', 'RLHF（人間のフィードバックによる強化学習）', '標準', '理解', 'RLHF（Reinforcement Learning from Human Feedback）の説明として最も適切なものはどれか。', '人間が作成した大量のテキストデータでモデルを事前学習させる手法', '人間の評価・フィードバックをもとにAIの出力品質を改善する強化学習の手法', '人間がプログラムコードを直接編集してモデルを調整する手法', '人間が選んだ特徴量を用いて機械学習モデルを訓練する手法', 'A', 'RLHF（Reinforcement Learning from Human Feedback）は、AIの出力に対して人間が評価（良い/悪いなど）を与え、その評価を報酬としてモデルを強化学習で最適化する手法である。これにより、人間の価値観や好みに沿った出力を生成するようモデルが改善される。ChatGPTなどの主要なLLMの開発で採用されている。', 'A：大量のテキストでの事前学習はPre-trainingの説明であり、RLHFとは異なる。\nC：プログラムコードの編集はソフトウェア開発の作業であり、RLHFとは無関係。\nD：特徴量エンジニアリングは従来の機械学習手法であり、RLHFとは異なる。', 'AI白書2024（IPA）'),
('Q1-028', '第1章', '主要生成AIサービス', '易', '記憶（知識）', '以下の生成AIサービスのうち、Microsoftが提供しているものはどれか。', 'ChatGPT', 'Gemini', 'Claude', 'Copilot', 'D', 'Microsoft Copilotは、Microsoftが提供する生成AIサービスであり、OpenAIのGPTモデルを基盤としている。Microsoft 365やWindows、Bingなどのマイクロソフト製品に統合されており、業務効率化ツールとして広く利用されている。', 'A：ChatGPTはOpenAIが開発・提供するサービスである。\nB：GeminiはGoogleが開発・提供するサービスである。\nC：ClaudeはAnthropicが開発・提供するサービスである。', 'AI白書2024（IPA）'),
('Q1-029', '第1章', 'パラメータ', '易', '記憶（知識）', '大規模言語モデル（LLM）における「パラメータ」の説明として最も適切なものはどれか。', 'ユーザーがAIに入力する指示文のこと', 'モデルが学習により獲得する数値の重みであり、モデルの規模を表す指標となる', 'AIサービスの利用料金を決定する単位', 'モデルが出力できる文章の最大文字数', 'D', 'パラメータとは、ニューラルネットワークにおいて学習により調整される数値の重み（ウェイト）のことである。LLMではパラメータ数が数十億〜数兆に及び、一般的にパラメータ数が多いほどモデルの表現能力が高くなる傾向がある。GPT-4は推定1兆以上のパラメータを持つとされる。', 'A：ユーザーの入力指示文はプロンプトと呼ばれ、パラメータとは異なる。\nC：利用料金はトークン数などに基づいて計算され、パラメータ数とは直接関係しない。\nD：出力の最大文字数はコンテキスト長やトークン上限に関連し、パラメータとは異なる概念。', 'AI白書2024（IPA）'),
('Q1-030', '第1章', '推論とコスト', '標準', '理解', '大規模言語モデル（LLM）の「推論」に関する説明として最も適切なものはどれか。', '大量のテキストデータを用いてモデルの重みを更新する処理', '学習済みモデルを用いてユーザーの入力に対する出力を生成する処理', 'モデルのアーキテクチャを設計する処理', '学習データからノイズを除去する前処理', 'A', '推論（Inference）とは、学習済みのAIモデルを用いて、新しい入力データに対する予測や出力を生成する処理のことである。LLMの場合、ユーザーのプロンプト（入力）を受け取り、それに対する回答（出力）を生成する処理が推論に該当する。推論には計算リソースが必要であり、APIの利用料金は推論コストに基づいて設定されることが多い。', 'A：モデルの重み更新は学習（Training）の処理であり、推論とは異なる。\nC：アーキテクチャ設計はモデル開発の工程であり、推論処理ではない。\nD：データの前処理は学習準備の工程であり、推論とは異なる。', 'AI白書2024（IPA）'),
('Q1-031', '第1章', 'クラウド／オンプレミス／エッジAI', '標準', '適用', '救急外来でリアルタイムにバイタルサインを解析してアラートを出すAIシステムを導入する場合、最も適した実行環境はどれか。', '海外のクラウドサービス', '院内のオンプレミスサーバー', '医療機器に組み込まれたエッジAI', 'スマートフォンアプリ', 'C', 'リアルタイム処理が求められる救急外来でのバイタルサイン解析には、通信遅延（レイテンシー）を最小化できるエッジAIが最も適している。エッジAIは医療機器やローカルデバイスで直接処理を行うため、ネットワーク障害時も動作を継続でき、患者データを外部に送信しないセキュリティ面でも利点がある。', 'A：海外クラウドは通信遅延が大きく、リアルタイム処理には不向き。また、データの越境移転の法的課題もある。\nB：オンプレミスも選択肢となりうるが、ベッドサイドでのリアルタイム処理にはエッジAIがより適切。\nD：スマートフォンアプリは医療機器としての信頼性や精度の確保が困難。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q1-032', '第1章', 'Transformer', '易', '記憶（知識）', 'Transformerアーキテクチャの中核となる機構として最も適切なものはどれか。', 'Attention機構', '畳み込み演算', '再帰的接続', '決定木分岐', 'A', 'Transformerは、Self-Attention機構を中核としたアーキテクチャである。Attention機構により、入力系列の各要素が他のすべての要素との関連性を計算でき、文脈を考慮した処理が可能となる。この技術革新がGPT、BERT、Claudeなどの大規模言語モデルの基盤となっている。', 'B：畳み込み演算はCNN（畳み込みニューラルネットワーク）の中核技術であり、Transformerとは異なる。\nC：再帰的接続はRNN（再帰型ニューラルネットワーク）の特徴であり、Transformerはこれを使用しない。\nD：決定木分岐は決定木アルゴリズムの構造であり、Transformerとは無関係。', 'AI白書2024（IPA）'),
('Q1-033', '第1章', 'ファインチューニング', '難', '分析', '医療機関が汎用LLMを医療特化型にファインチューニングする際の留意点として最も適切なものはどれか。', '学習データの量を最大化するため、匿名化せずに診療記録を使用する', '学習データには正確な医学情報を使用し、個人情報の適切な処理と倫理審査を行う', 'ファインチューニング後は元の汎用能力が完全に失われるため、慎重に検討する', 'ファインチューニングはAPI提供元でのみ実施可能であり、自組織では行えない', 'C', '医療特化型モデルのファインチューニングでは、学習データの質と倫理的配慮が極めて重要である。診療記録を使用する場合は、個人情報保護法に基づく適切な匿名化処理、倫理審査委員会の承認、患者同意の取得などが必要となる。また、学習データに誤った医学情報が含まれるとモデルの出力も不正確になるため、データの正確性確認も必須である。', 'A：個人情報を匿名化せずに使用することは個人情報保護法に違反し、重大なリスクとなる。\nC：ファインチューニングで汎用能力が完全に失われるわけではない。パラメータの一部を固定するなどの手法で両立も可能。\nD：オープンソースモデルを使用すれば自組織でファインチューニングを実施可能。', '個人情報保護法／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q1-034', '第1章', 'トークン／トークナイズ', '難', '適用', '医療事務担当者がLLMを用いて長文の診療情報提供書を要約する際、「コンテキスト長を超えました」というエラーが発生した。この問題を解決する方法として最も適切なものはどれか。', '入力文書を分割して複数回に分けて処理し、結果を統合する', 'AIモデルのパラメータ数を増やす設定に変更する', '出力の文字数制限を解除する', 'インターネット接続速度を向上させる', 'A', 'コンテキスト長の制限を超えた場合、入力文書を複数のチャンク（部分）に分割して処理し、各チャンクの要約結果を最終的に統合する方法が有効である。これは長文処理の一般的な対処法であり、医療文書のような長文を扱う際に実践的なスキルとなる。', 'B：ユーザー側でパラメータ数を変更することは通常できない。また、パラメータ数とコンテキスト長は別の概念。\nC：出力の文字数制限はコンテキスト長エラーとは別の問題。入力が長すぎることが原因。\nD：通信速度はコンテキスト長の制限とは無関係。', 'AI白書2024（IPA）'),
('Q1-035', '第1章', 'ハルシネーション（幻覚）', '標準', '理解', '生成AIがハルシネーションを起こしやすい状況として最も適切なものはどれか。', '学習データに十分な情報が含まれている一般的な質問に回答する場合', '学習データに含まれていない最新の情報や専門的な知識を求められた場合', 'ユーザーが短い単語で質問した場合', 'AIの応答速度が高速な場合', 'B', 'ハルシネーションは、生成AIが学習データに含まれていない情報を求められた際に発生しやすい。特に、学習データのカットオフ日以降の最新情報、専門性の高いニッチな分野の知識、特定の組織内の情報などについて質問された場合、AIは「尤もらしいが誤った」情報を生成するリスクが高まる。', 'A：学習データに十分な情報がある一般的な質問では、ハルシネーションのリスクは相対的に低い。\nC：質問の長さとハルシネーションの発生には直接的な関係はない。\nD：応答速度とハルシネーションの発生には直接的な関係はない。', 'AI事業者ガイドライン（第1.1版）'),
('Q1-036', '第1章', 'マルチモーダル', '標準', '適用', 'マルチモーダルAIを医療現場で活用する例として最も適切なものはどれか。', '電子カルテの文字入力のみを補助するシステム', '患者の問診内容（テキスト）と皮膚病変の写真（画像）を組み合わせて診断を支援するシステム', '医療従事者のシフト管理のみを行うシステム', '院内の空調を制御するシステム', 'B', 'マルチモーダルAIは、テキスト、画像、音声など複数の種類のデータを統合的に処理できることが特徴である。患者の問診内容（テキスト）と皮膚病変の写真（画像）を組み合わせて診断支援を行うシステムは、複数のモダリティを活用した典型的なマルチモーダルAIの医療応用例である。', 'A：文字入力のみの補助は単一モダリティ（テキスト）の処理であり、マルチモーダルとは言えない。\nC：シフト管理は構造化データの処理であり、マルチモーダルAIの特徴を活かした応用ではない。\nD：空調制御はIoTやビル管理システムの領域であり、マルチモーダルAIの医療応用ではない。', 'AI白書2024（IPA）'),
('Q1-037', '第1章', '機械学習（Machine Learning）', '易', '理解', '機械学習における「教師なし学習」の活用例として最も適切なものはどれか。', '画像が腫瘍か正常かを判定する', '患者を類似した特徴を持つグループに分類する', '過去のデータから将来の売上を予測する', '文章を要約して出力する', 'D', '教師なし学習は、正解ラベルなしでデータのパターンや構造を発見する手法である。患者を類似した特徴（年齢、疾患、検査値など）を持つグループに分類する「クラスタリング」は、教師なし学習の代表的な活用例である。', 'A：腫瘍か正常かの判定は、正解ラベル（腫瘍/正常）を用いた教師あり学習の例。\nC：売上予測は、過去の売上データを正解として用いる教師あり学習（回帰）の例。\nD：文章要約は教師あり学習や生成モデルで行われ、教師なし学習の典型例ではない。', 'AI白書2024（IPA）'),
('Q1-038', '第1章', 'API（Application Programming Interface）', '標準', '理解', '医療機関が生成AIのAPIを利用する際の注意点として適切でないものはどれか。', 'APIに送信するデータに患者の個人情報が含まれないよう注意する', 'API利用規約を確認し、入力データの取り扱いを理解する', 'APIの利用料金体系を把握し、コスト管理を行う', 'APIを利用すれば、出力結果の検証は不要となる', 'D', 'APIを利用しても生成AIの出力にはハルシネーションなどのリスクがあるため、出力結果の検証は必須である。医療分野では特に、誤った情報が患者の安全に影響する可能性があるため、人間による検証を省略することは適切でない。', 'A：患者の個人情報（要配慮個人情報）を外部APIに送信することは、情報漏洩リスクや法的問題があるため注意が必要。\nB：利用規約の確認は重要であり、入力データが学習に使用されるかどうかなどを把握する必要がある。\nC：トークン単位の従量課金など、料金体系を把握してコスト管理を行うことは実務上重要。', 'AI事業者ガイドライン（第1.1版）／医療情報システムの安全管理に関するガイドライン 第6.0版'),
('Q1-039', '第1章', 'オープンソース／プロプライエタリモデル', '難', '評価', '医療機関がAIモデルを選定する際、プロプライエタリ（商用）モデルとオープンソースモデルの比較として最も適切なものはどれか。', 'プロプライエタリモデルは必ずオープンソースモデルより高性能である', 'オープンソースモデルは商用利用が一切禁止されている', '医療機関のニーズに応じて、セキュリティ、コスト、性能、サポート体制を総合的に評価して選定すべきである', 'オープンソースモデルを使用すれば、法的責任から完全に免除される', 'C', 'AIモデルの選定においては、一方が常に優れているわけではなく、医療機関の具体的なニーズに応じた評価が必要である。セキュリティ要件（データを外部に出せるか）、コスト、モデルの性能、ベンダーサポートの有無、法的要件への対応などを総合的に比較検討し、最適な選択を行うべきである。', 'A：性能はモデルやタスクにより異なり、オープンソースモデルがプロプライエタリモデルに匹敵する場合もある。\nB：多くのオープンソースモデルは商用利用可能なライセンスで公開されている（ライセンス条件は確認が必要）。\nD：オープンソースであっても、利用者は適切な使用と結果に対する責任を負う。', 'AI白書2024（IPA）'),
('Q1-040', '第1章', '事前学習（Pre-training）', '易', '記憶（知識）', '大規模言語モデルの事前学習に使用されるデータソースとして一般的なものはどれか。', '特定企業の機密文書のみ', 'インターネット上のウェブページ、書籍、論文などの大量のテキストデータ', '音声データのみ', '画像データのみ', 'B', '大規模言語モデル（LLM）の事前学習には、インターネット上のウェブページ、デジタル化された書籍、学術論文、Wikipediaなどの膨大なテキストデータが使用される。これにより、言語の一般的な構造、知識、文脈理解能力などを獲得する。', 'A：特定企業の機密文書は一般的にLLMの事前学習データには含まれない。公開されている多様なデータが使用される。\nC：音声データのみでは言語モデルの学習には不十分。音声認識モデルとは目的が異なる。\nD：画像データのみではテキストを扱う言語モデルの学習には使用できない。', 'AI白書2024（IPA）'),
('Q1-041', '第1章', '深層学習（Deep Learning）', '標準', '適用', '放射線科の医師が胸部X線画像の異常検出AIの導入を検討している。このAIに使用される深層学習の技術として最も適切なものはどれか。', 'リカレントニューラルネットワーク（RNN）', '畳み込みニューラルネットワーク（CNN）', '決定木アルゴリズム', 'サポートベクターマシン（SVM）', 'B', '畳み込みニューラルネットワーク（CNN）は、画像認識タスクにおいて高い性能を発揮する深層学習アーキテクチャである。畳み込み演算により画像の局所的な特徴を階層的に抽出できるため、胸部X線画像の異常検出などの医療画像解析に広く使用されている。', 'A：RNNは時系列データや自然言語処理に適しており、静止画像の解析には不向き。\nC：決定木は解釈性は高いが、画像認識の性能はCNNに劣る。\nD：SVMは従来の機械学習手法であり、大規模な画像認識では深層学習に劣る。', 'AI白書2024（IPA）'),
('Q1-042', '第1章', 'RAG（検索拡張生成）', '易', '記憶（知識）', 'RAG（検索拡張生成）をファインチューニングと比較した場合の利点として最も適切なものはどれか。', 'モデルの再学習が不要で、知識ベースの更新だけで最新情報に対応できる', 'インターネット接続なしで動作する', 'あらゆる質問に対して100%正確な回答ができる', '計算リソースが全く必要ない', 'A', 'RAGの大きな利点は、LLM自体の再学習（ファインチューニング）を行わずに、参照する知識ベースを更新するだけで最新の情報に対応できることである。医療分野では、ガイドラインや薬剤情報の更新に迅速に対応できる点が有用である。', 'B：RAGは通常、知識ベースへのアクセスが必要であり、完全オフラインでの動作を前提としていない。\nC：RAGでもハルシネーションのリスクは完全には排除できず、100%の正確性は保証されない。\nD：RAGも検索処理やLLMの推論に計算リソースを使用する。', 'AI白書2024（IPA）'),
('Q1-043', '第1章', '基盤モデル／Foundation Model', '標準', '分析', '基盤モデル（Foundation Model）を医療分野で活用する際の課題として最も適切なものはどれか。', '基盤モデルは医療専用に設計されているため、他分野への応用ができない', '基盤モデルは小規模なため、複雑なタスクに対応できない', '汎用的に学習されているため、医療特有の専門用語や概念の理解が不十分な場合がある', '基盤モデルはオープンソースでのみ提供されている', 'C', '基盤モデルは多様なテキストで学習された汎用モデルであるため、医療分野特有の専門用語、略語、疾患概念、治療プロトコルなどの理解が不十分な場合がある。このため、医療応用においてはファインチューニングやRAGによる専門知識の補強、出力の専門家による検証が重要となる。', 'A：基盤モデルは汎用的に設計されており、医療以外の多分野で活用されている。\nB：基盤モデルは大規模であり、複雑なタスクにも対応可能。\nD：基盤モデルにはプロプライエタリ（GPT-4、Claudeなど）とオープンソース（Llamaなど）の両方が存在する。', 'AI白書2024（IPA）／HAIPガイドライン（厚生労働省）'),
('Q1-044', '第1章', 'AIの種類と分類', '難', '分析', '医療機関が導入を検討しているAIシステムについて、「識別系AI」「予測系AI」「生成系AI」のいずれに該当するかを判断する際の基準として最も適切なものはどれか。', 'AIの開発元が日本企業か海外企業かで分類する', 'AIの価格帯で分類する', 'AIが入力データをどのように処理し、どのような出力を生成するかで分類する', 'AIの導入に必要なハードウェアのスペックで分類する', 'C', 'AIの分類は、その機能と処理方式に基づいて行う。識別系AIは入力データを分類・識別し（例：画像が異常か正常か）、予測系AIは将来の数値を予測し（例：再入院リスク）、生成系AIは新しいコンテンツを生成する（例：文書作成）。AIを適切に活用するには、その特性を理解することが重要である。', 'A：開発元の国籍はAIの機能的分類とは関係がない。\nB：価格はAIの機能的分類の基準ではない。\nD：ハードウェア要件はAIの機能的分類とは別の観点。', 'AI白書2024（IPA）'),
('Q1-045', '第1章', '主要生成AIサービス', '標準', '理解', '医療機関が生成AIサービスを選定する際に確認すべき事項として適切でないものはどれか。', '入力データがAIの学習に使用されるかどうかの設定・規約', 'サービス提供元のデータセンターの所在地', 'AIモデルの学習に使用された全データの個別リスト', 'サービスの稼働率や障害時の対応体制', 'C', '大規模言語モデルの学習に使用されたデータの「全リスト」は、データ量が膨大（数兆トークン規模）であるため、通常は公開されておらず、確認することは現実的でない。一方、入力データの取り扱い、データセンターの所在地（越境移転の観点）、サービスの信頼性などは確認すべき重要事項である。', 'A：入力データが学習に使用されるかは、患者情報保護の観点から確認すべき重要事項。\nB：データセンターの所在地は、データの越境移転に関する法的要件の確認に必要。\nD：稼働率や障害対応体制は、医療業務の継続性確保の観点から確認すべき事項。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q2-001', '第2章', '問診支援', '易', '記憶（知識）', 'AI問診システムの主な機能として最も適切なものはどれか。', '患者の症状を聞き取り、可能性のある疾患の候補を提示して医師の診療を支援する', '患者の代わりに最終的な診断を確定する', '患者への処方箋を自動的に発行する', '患者の手術を自律的に実施する', 'A', 'AI問診システムは、患者が入力した症状や既往歴などの情報をもとに、可能性のある疾患の候補リスト（鑑別診断リスト）を生成し、医師の診療判断を支援するツールである。最終的な診断は医師が行い、AIはあくまで支援の役割を担う。', 'B：診断の確定は医師の専門的判断に基づく医行為であり、AIが単独で行うことはできない。\nC：処方箋の発行は医師法に基づく医師の行為であり、AIが自動発行することは認められない。\nD：手術の実施は医師の医行為であり、AIが自律的に行うことは現状では認められていない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-002', '第2章', '臨床意思決定支援（CDS）', '標準', '理解', '臨床意思決定支援システム（CDS：Clinical Decision Support）の説明として最も適切なものはどれか。', '医師の判断を完全に代替し、自動的に治療を実行するシステム', '患者データやエビデンスに基づいて、診断・治療方針の判断を支援する情報を提供するシステム', '病院の経理・会計処理を自動化するシステム', '医療従事者の勤怠管理を行うシステム', 'B', '臨床意思決定支援システム（CDS）は、患者の診療データ、医学文献、診療ガイドラインなどのエビデンスに基づいて、医師の診断や治療方針の決定を支援する情報を提供するシステムである。薬剤の相互作用チェック、検査値に基づくアラート、治療オプションの提示などが機能として含まれる。', 'A：CDSは医師の判断を支援するものであり、判断の代替や治療の自動実行は行わない。\nC：経理・会計処理は医事会計システムの機能であり、CDSとは異なる。\nD：勤怠管理は人事管理システムの機能であり、臨床意思決定支援とは無関係。', 'HAIPガイドライン（厚生労働省）'),
('Q2-003', '第2章', '医療文書作成支援', '易', '理解', '生成AIによる医療文書作成支援の活用例として最も適切なものはどれか。', 'AIが自動生成した診断書をそのまま患者に交付する', 'AIが生成した紹介状の下書きを医師が確認・修正してから発行する', 'AIが診断を確定し、その結果をカルテに自動記録する', 'AIが処方箋を自動発行し、薬局に直接送信する', 'B', '生成AIによる医療文書作成支援は、医師の業務効率化を目的として紹介状、退院サマリー、診療情報提供書等の「下書き」を生成し、医師が内容を確認・修正した上で最終的な文書として使用するものである。AIはあくまで支援ツールであり、文書の最終的な内容に対する責任は医師が負う。', 'A：AIが生成した文書をそのまま交付することは、内容の正確性が保証されないため不適切。\nC：診断の確定は医師の医行為であり、AIが単独で行うことはできない。\nD：処方箋の発行は医師法に基づく医師の行為であり、AIが自動発行することは認められない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-004', '第2章', '患者説明・IC支援', '標準', '適用', '医師がインフォームドコンセント（IC）の説明文書作成に生成AIを活用する場合、最も適切な使用方法はどれか。', 'AIが生成した説明文書を確認せずにそのまま患者に渡す', '患者の疾患に関する説明文書の下書きをAIに生成させ、医師が内容を確認・修正してから使用する', 'AIに患者との面談を代行させ、同意取得まで自動化する', 'AIが推奨する治療法のみを説明し、他の選択肢は提示しない', 'B', 'インフォームドコンセントの説明文書作成にAIを活用する場合、AIが生成した下書きを医師が専門的観点から確認・修正し、患者の状態や理解度に合わせて適切な内容にした上で使用することが適切である。説明と同意取得は医師が直接患者に対して行う必要がある。', 'A：AIの出力にはハルシネーションのリスクがあり、確認なしでの使用は不適切。\nC：ICの説明と同意取得は医師が直接患者に対して行う必要があり、AIが代行することはできない。\nD：ICでは治療の選択肢とリスク・ベネフィットを十分に説明する必要があり、AIの推奨のみの説明は不十分。', 'HAIPガイドライン（厚生労働省）／医師法'),
('Q2-005', '第2章', '看護業務への活用', '標準', '適用', '病棟看護師が生成AIを活用して業務効率化を図る場面として最も適切なものはどれか。', '患者のバイタルサイン異常をAIが検知し、AIの判断のみで医師への報告を省略する', '夜勤帯の申し送り事項をAIに口述入力し、要約された申し送り文を確認してから引き継ぐ', 'AIが提案したケアプランを看護師の判断なしにそのまま実施する', '患者の個人情報を含む看護記録を、無料の汎用AIチャットサービスに入力して要約させる', 'B', '申し送り業務の効率化は生成AIの有力な活用場面である。口述内容をAIが文章化・要約し、看護師がその内容を確認した上で引き継ぐことで、正確性を担保しつつ記録作成の負担を軽減できる。最終確認は必ず人間（看護師）が行う点が重要。', 'A：バイタルサイン異常の検知自体はAIが支援可能だが、医師への報告を省略することは患者安全上許容されない。\nC：ケアプランの作成支援にAIを活用することは可能だが、看護師の専門的判断なしに実施することは不適切。\nD：患者の個人情報を外部の無料AIサービスに入力することは、個人情報保護法上の問題があり不適切。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q2-006', '第2章', '薬剤業務への活用', '易', '記憶（知識）', '薬剤師業務における生成AIの活用例として最も適切なものはどれか。', 'AIが処方箋の内容を自動的に変更する', 'AIが患者への服薬指導文書の下書きを作成し、薬剤師が確認・修正して使用する', 'AIが医師の処方を承認なしに却下する', 'AIが患者に直接薬剤を投与する', 'B', '薬剤師業務において、服薬指導文書や薬歴の下書き作成に生成AIを活用することで、業務効率化が期待できる。ただし、AIの出力は薬剤師が専門的観点から確認・修正した上で使用する必要がある。最終的な責任は薬剤師が負う。', 'A：処方内容の変更は医師の判断に基づくものであり、AIが自動的に行うことはできない。疑義照会が必要な場合は薬剤師が医師に確認する。\nC：処方の承認・却下は医師と薬剤師の専門的判断であり、AIが単独で行うことはできない。\nD：薬剤の投与は医療従事者（医師、看護師等）の行為であり、AIが行うことはできない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-007', '第2章', '患者向け情報提供', '標準', '理解', '生成AIを用いて患者向けの疾患説明資料を作成する際の留意点として最も適切なものはどれか。', '専門用語を多用して医学的な正確性を優先する', '患者の理解度に合わせた平易な表現を用い、医療者が内容を確認してから提供する', 'AIが生成した内容は常に正確なので、確認なしで使用してよい', '著作権の問題を避けるため、参考文献は一切記載しない', 'D', '患者向け情報提供では、患者のヘルスリテラシーに配慮した平易な表現で情報を伝えることが重要である。生成AIで下書きを作成する場合も、医療者が内容の正確性を確認し、患者の理解度に合わせて適切な表現に修正してから提供する必要がある。', 'A：患者向け資料では、専門用語を避けて平易な表現を用いることが推奨される。\nC：AIの出力にはハルシネーションのリスクがあり、医療者による確認は必須。\nD：信頼性の高い情報源を参考文献として示すことで、情報の信頼性を担保できる。', 'HAIPガイドライン（厚生労働省）'),
('Q2-008', '第2章', 'トリアージ支援', '標準', '適用', '救急外来でAIトリアージ支援システムを運用する場合、最も適切な運用方法はどれか。', 'AIの判定結果のみに基づいて患者の診察順序を決定する', 'AIの判定結果を参考にしつつ、最終的な緊急度判定は医療従事者が行う', 'AIの判定結果を患者に直接伝え、待ち時間の目安を通知する', 'AIが軽症と判定した患者は診察せずに帰宅させる', 'B', 'AIトリアージ支援システムは、患者の症状や バイタルサインから緊急度を判定し、医療従事者の意思決定を支援するツールである。ただし、AIの判定には誤りの可能性があるため、最終的な緊急度判定と診察順序の決定は、医師や看護師が専門的判断に基づいて行う必要がある。', 'A：AIの判定のみに依存することは、患者安全上のリスクがあり不適切。\nC：AIの判定結果を直接患者に伝えることは、誤判定時の問題や患者の混乱を招く可能性がある。\nD：AIが軽症と判定しても、実際には重症である可能性があり、診察なしに帰宅させることは危険。', 'HAIPガイドライン（厚生労働省）'),
('Q2-009', '第2章', '音声認識と診療記録', '易', '記憶（知識）', '医療現場における音声認識AIの活用例として最も適切なものはどれか。', '医師の診察中の発話を文字起こしし、カルテ記載の下書きを自動生成する', '患者の会話を無断で録音し、分析する', '音声認識結果を確認なしでそのまま正式なカルテとして保存する', '医師の音声指示のみでAIが自動的に処方箋を発行する', 'A', '音声認識AIは、医師が診察中に発話した内容を自動的に文字起こしし、カルテ記載の下書きを生成することで、記録作成の効率化に寄与する。アンビエント・リスニング技術を活用したシステムも開発されている。ただし、生成された内容は医師が確認・修正する必要がある。', 'B：患者の会話を無断で録音することは、プライバシー侵害であり、同意なく行うことは不適切。\nC：音声認識には誤認識の可能性があり、確認なしで正式なカルテとすることは危険。\nD：処方箋の発行は医師の責任で行う医行為であり、AIが自動発行することは認められない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-010', '第2章', '多言語対応', '標準', '適用', '外国人患者の診療において生成AIを翻訳支援に活用する場合、最も適切な運用方法はどれか。', 'AIによる翻訳結果をそのまま医療通訳として使用し、専門の通訳者は不要とする', '緊急性が低く簡単な説明の補助に活用し、重要な説明や同意取得には専門通訳者を介在させる', 'AIの翻訳精度は完璧なので、医学用語の翻訳も問題なく対応できる', '翻訳AIを使用する際は、患者への説明や同意は不要である', 'D', '生成AIによる翻訳は、簡単な説明や補助的なコミュニケーションには有用だが、医学用語や複雑な説明の翻訳には誤りが生じる可能性がある。重要な医療情報の説明やインフォームドコンセントの取得には、専門の医療通訳者を介在させることが推奨される。', 'A：AI翻訳には誤訳のリスクがあり、専門通訳者の代替として使用することは適切でない。\nC：AI翻訳は完璧ではなく、特に医学専門用語の翻訳には注意が必要。\nD：AIツールの使用に関わらず、患者への適切な説明と同意は必須である。', 'HAIPガイドライン（厚生労働省）'),
('Q2-011', '第2章', '医療事務への活用', '易', '記憶（知識）', '医療事務業務における生成AIの活用例として最も適切なものはどれか。', 'AIがレセプト審査を最終的に承認する', 'AIが患者に直接診療費を請求する', 'レセプト点検の補助や、患者からの問い合わせ対応文書の下書き作成', 'AIが医療費の支払いを患者の口座から自動引き落としする', 'C', '医療事務業務において、生成AIはレセプト点検の補助（記載漏れや誤りのチェック）や、患者からの問い合わせに対する回答文書の下書き作成などに活用できる。これにより業務効率化が期待できるが、最終的な確認・判断は人間（医療事務担当者）が行う必要がある。', 'A：レセプト審査の最終承認は、人間（担当者や審査機関）が行う必要がある。\nB：診療費の請求は医療機関の業務であり、AIが直接患者に請求することは適切でない。\nD：支払いの自動引き落としは金融機関との契約に基づく処理であり、AIの役割ではない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-012', '第2章', '医学研究・論文支援', '標準', '理解', '生成AIを医学研究や論文執筆に活用する際の注意点として最も適切なものはどれか。', 'AIが生成した文章は著作権フリーなので、そのまま自分の論文として投稿してよい', 'AIが引用した参考文献は自動的に正確なので、確認は不要である', 'AIの出力は補助的に活用し、事実の正確性確認と文献の実在確認を研究者が行う', 'AIを使用したことは論文に記載する必要がない', 'C', '生成AIを研究・論文執筆に活用する場合、AIの出力はあくまで補助として位置づけ、事実の正確性、引用文献の実在と内容の確認は研究者自身が責任を持って行う必要がある。AIはハルシネーションにより存在しない文献を引用することがあるため、特に注意が必要である。', 'A：AIが生成した文章をそのまま自分の論文として投稿することは、研究倫理上問題がある。多くの学術誌でAI使用の開示を求めている。\nB：AIは存在しない文献を「捏造」することがあり、参考文献の確認は必須。\nD：多くの学術誌やジャーナルがAI使用の開示を義務付けている。', 'AI白書2024（IPA）'),
('Q2-013', '第2章', '医学教育への活用', '標準', '適用', '医学教育において生成AIを活用する例として最も適切なものはどれか。', 'AIが学生の代わりに臨床実習を行う', '症例シミュレーションのシナリオ作成や、学習者への個別フィードバック生成に活用する', 'AIが学生の成績を最終的に評価・判定する', 'AIが医師国家試験の合否を判定する', 'A', '医学教育において、生成AIは症例シミュレーションのシナリオ作成、試験問題の下書き作成、学習者の回答に対する個別フィードバックの生成などに活用できる。これにより教育の質向上と教員の負担軽減が期待できる。ただし、最終的な教育評価は教員が行う。', 'A：臨床実習は学生が実際の医療現場で経験を積むものであり、AIが代行することはできない。\nC：学生の最終的な成績評価は、教育者（教員）が責任を持って行う必要がある。\nD：国家試験の合否判定は試験委員会が行うものであり、AIが判定することはない。', 'AI白書2024（IPA）'),
('Q2-014', '第2章', 'リハビリテーションへの活用', '易', '記憶（知識）', 'リハビリテーション業務における生成AIの活用例として最も適切なものはどれか。', 'AIがリハビリ訓練を患者に直接実施する', 'リハビリ計画書の下書き作成や、経過記録の要約作成の補助', 'AIが患者のリハビリ終了を最終判断する', 'AIが装具や補助具を患者に処方する', 'B', 'リハビリテーション業務において、生成AIはリハビリ計画書の下書き作成、経過記録の要約、報告書の文章化などの文書作成業務の補助に活用できる。これにより理学療法士・作業療法士の業務効率化が期待できるが、計画の決定や実施は専門職が行う。', 'A：リハビリ訓練の実施は理学療法士・作業療法士などの専門職が行う。\nC：リハビリ終了の判断は、医師やリハビリ専門職が患者の状態を評価して行う。\nD：装具・補助具の処方は医師の指示に基づいて行われ、AIが処方することはできない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-015', '第2章', 'AIチャットボットの医療応用', '難', '分析', '医療機関がAIチャットボットを患者向けに導入する場合のリスクとして最も重要なものはどれか。', 'チャットボットの応答速度が遅いこと', 'チャットボットのユーザーインターフェースがわかりにくいこと', 'チャットボットの回答を患者が鵜呑みにし、適切な受診が遅れる可能性があること', 'チャットボットの維持費用がかかること', 'C', 'AIチャットボットの医療応用における最大のリスクは、患者がAIの回答を過信し、本来必要な受診が遅れることで重篤な状態に陥る可能性である。特に、AIが「様子を見てよい」と判断した場合でも実際には緊急性が高いケースがあり得る。このため、チャットボットの限界を明示し、必要に応じて医療機関への受診を促す仕組みが必要である。', 'A：応答速度は利便性に影響するが、患者安全に関わる最重要のリスクではない。\nB：UIの使いやすさは重要だが、患者の健康・生命に関わるリスクと比較すると優先度は低い。\nD：費用は運営上の課題だが、患者安全のリスクと比較すると優先度は低い。', 'AI事業者ガイドライン（第1.1版）／HAIPガイドライン（厚生労働省）'),
('Q2-016', '第2章', '医療画像解析との連携', '標準', '理解', '画像診断AIとLLM（大規模言語モデル）を連携させた活用例として最も適切なものはどれか。', 'LLMが単独でCT画像から腫瘍を検出する', '画像診断AIが検出した所見をLLMが自然言語で説明する読影レポートを自動生成する', 'LLMが画像診断AIの学習データを自動的に収集する', '画像診断AIがLLMの学習を行う', 'A', '画像診断AI（CNN等）とLLMを連携させることで、画像診断AIが検出した所見（腫瘍の位置、大きさ、特徴など）をLLMが自然言語の読影レポートとして文章化する活用が可能である。これにより放射線科医の読影レポート作成業務の効率化が期待できる。', 'A：LLM単体は画像解析を行わない。画像からの腫瘍検出には専用の画像診断AI（CNN等）が必要。マルチモーダルLLMでも専用AIほどの精度は期待できない。\nC：学習データの収集は人間が適切に設計・管理すべき工程であり、LLMが自動で行うものではない。\nD：画像診断AIがLLMを学習させるという関係性は一般的ではない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-017', '第2章', '医療DXとの関係', '易', '記憶（知識）', '政府が推進する「医療DX」において、生成AIの活用が期待される領域として適切でないものはどれか。', '電子カルテの記載支援', '患者への説明文書の作成支援', '医療従事者の完全な代替', '医療情報の分析・活用支援', 'A', '医療DXにおいて生成AIは、医療従事者の業務を「支援」するツールとして位置づけられている。電子カルテの記載支援、説明文書作成、情報分析などの補助業務には活用が期待されるが、医療従事者を「完全に代替」することは想定されていない。最終的な判断と責任は人間（医療従事者）が担う。', 'A：電子カルテの記載支援は、生成AIの主要な活用領域として期待されている。\nB：患者説明文書の作成支援も、生成AIの有効な活用領域である。\nD：医療情報の分析・活用支援は、AIの強みを活かせる領域として期待されている。', '医療DX推進本部資料／HAIPガイドライン（厚生労働省）'),
('Q2-018', '第2章', '臨床意思決定支援（CDS）', '難', '分析', '臨床意思決定支援システム（CDS）に生成AIを組み込む際に最も重要な考慮事項はどれか。', 'ユーザーインターフェースのデザイン性', 'システムの導入コストの最小化', 'AIが提示する推奨の根拠を医師が確認でき、最終判断は医師が行える設計', 'できるだけ多くの機能を一つのシステムに統合すること', 'C', '生成AIを組み込んだCDSでは、AIが提示する診断・治療の推奨について、その根拠（参照したエビデンス、推論のプロセス）を医師が確認できることが重要である。また、AIはあくまで支援ツールであり、最終的な臨床判断は医師が責任を持って行える設計とすることが必須である。', 'A：UIデザインも重要だが、患者安全に直結する判断支援の信頼性確保が最優先。\nB：コスト最小化は経営上重要だが、医療安全に関わる品質を犠牲にすべきではない。\nD：機能の統合より、各機能の信頼性と根拠の透明性が重要。', 'HAIPガイドライン（厚生労働省）／AI事業者ガイドライン（第1.1版）'),
('Q2-019', '第2章', '問診支援', '標準', '適用', 'クリニックがAI問診システムを導入する際、患者への説明として最も適切なものはどれか。', '「AIが診断しますので、医師の診察は不要です」', '「事前にAIが症状をお伺いし、医師の診察をスムーズにするためのツールです」', '「AIの判定結果がそのまま最終診断となります」', '「AIが処方箋を発行しますので、医師に会う必要はありません」', 'D', 'AI問診システムは、患者の症状を事前に聞き取り、医師の診察を効率化するための支援ツールである。患者には、AIはあくまで診察の補助であり、最終的な診断・治療は医師が行うことを明確に説明する必要がある。', 'A：AIによる診断のみで医師の診察を不要とすることは、医師法に反し不適切。\nC：AI問診の判定結果は参考情報であり、最終診断は医師が行う。\nD：処方箋の発行は医師の行為であり、AIが発行することはできない。', 'HAIPガイドライン（厚生労働省）／医師法'),
('Q2-020', '第2章', '医療文書作成支援', '難', '評価', '生成AIによる退院サマリー作成支援において、医師が確認すべき事項として最も優先度が高いものはどれか。', '文章の読みやすさとフォーマットの統一性', '診断名、治療内容、退院時指示などの医学的内容の正確性', '文字数が適切な範囲に収まっているか', '敬語の使い方が適切か', 'D', '退院サマリーは患者の診療経過を要約した重要な医療文書であり、診断名、実施した治療、退院時の状態、退院後の指示事項などの医学的内容の正確性が最も重要である。AIが生成した内容にハルシネーションによる誤りが含まれていないか、医師が専門的観点から確認することが必須である。', 'A：読みやすさも重要だが、医学的内容の正確性が最優先。\nC：文字数よりも内容の正確性と必要事項の網羅性が重要。\nD：敬語の適切性は文書品質の一要素だが、医学的正確性が最優先。', 'HAIPガイドライン（厚生労働省）'),
('Q2-021', '第2章', '看護業務への活用', '易', '記憶（知識）', '看護記録における生成AIの活用として適切でないものはどれか。', '患者の状態観察の記録文の下書き作成', '申し送り事項の要約作成', 'AIによる看護判断の最終決定', 'ケアプラン文書の下書き作成', 'D', '看護記録の下書き作成、申し送り要約、ケアプラン文書の下書き作成などは、生成AIの有効な活用場面である。しかし、患者のケアに関する看護判断の最終決定は、看護師の専門的知識と患者観察に基づいて行う必要があり、AIに委ねることは適切でない。', 'A：状態観察記録の下書き作成は、看護師が確認・修正することを前提に活用可能。\nB：申し送り要約作成は、業務効率化の観点で有効な活用例。\nD：ケアプラン文書の下書き作成は、看護師が内容を確認・調整することを前提に活用可能。', 'HAIPガイドライン（厚生労働省）'),
('Q2-022', '第2章', '薬剤業務への活用', '標準', '分析', '薬剤師が服薬指導に生成AIを活用する場合のリスクとして最も注意すべきものはどれか。', '服薬指導にかかる時間が短くなること', 'AIが生成した情報に薬剤の相互作用や副作用に関する誤りが含まれる可能性', '患者とのコミュニケーション機会が増えること', '指導内容の文書化が容易になること', 'B', '生成AIには ハルシネーションのリスクがあり、薬剤の相互作用、副作用、禁忌事項などの重要な医薬品情報について誤った内容を生成する可能性がある。誤った情報に基づく服薬指導は患者の健康に直接影響するため、薬剤師はAIの出力を必ず専門知識で検証する必要がある。', 'A：時間短縮はメリットであり、リスクではない。\nC：コミュニケーション機会の増加はメリットとなり得る。\nD：文書化の容易さはメリットであり、リスクではない。', 'AI事業者ガイドライン（第1.1版）'),
('Q2-023', '第2章', '患者説明・IC支援', '標準', '理解', '手術前のインフォームドコンセント説明資料の作成に生成AIを活用する場合、含めるべき内容として最も重要なものはどれか。', '手術室の設備紹介', '手術のリスク・合併症の可能性と、代替治療の選択肢', '担当医師の経歴紹介', '病院の沿革と理念', 'B', 'インフォームドコンセントにおいて最も重要なのは、患者が治療の内容、期待される効果、リスクや合併症の可能性、代替治療の選択肢を理解した上で意思決定できることである。生成AIで説明資料を作成する場合も、これらの医学的に重要な情報が正確に含まれていることを医師が確認する必要がある。', 'A：設備紹介は補助的情報であり、ICの本質的要素ではない。\nC：医師の経歴は参考情報にはなるが、ICの必須内容ではない。\nD：病院の沿革・理念はICの必須内容ではない。', '医師法／HAIPガイドライン（厚生労働省）'),
('Q2-024', '第2章', 'クリニカルパスとAI', '標準', '理解', 'クリニカルパス（診療計画書）の作成・運用における生成AIの活用として最も適切なものはどれか。', 'AIがクリニカルパスを自動的に作成し、医師の承認なしに適用する', '既存のエビデンスに基づいてクリニカルパスの原案を作成し、医療チームがレビュー・修正する', 'AIがパスからの逸脱を判断し、自動的に治療内容を変更する', '患者の同意なくAIがパスの適用を決定する', 'B', 'クリニカルパスの作成において、生成AIは診療ガイドラインやエビデンスに基づいてパスの原案を作成する補助ツールとして活用できる。ただし、最終的なパスの内容は医師を含む医療チームがレビュー・修正し、患者への適用は医師の判断と患者の同意に基づいて行う必要がある。', 'A：医師の承認なしにパスを適用することは、医療安全上不適切。\nC：治療内容の変更は医師の判断に基づくべきであり、AIが自動的に行うことは不適切。\nD：パスの適用には患者への説明と同意が必要。', 'HAIPガイドライン（厚生労働省）'),
('Q2-025', '第2章', 'ヘルスリテラシー支援', '易', '記憶（知識）', '患者のヘルスリテラシーに配慮した情報提供において、生成AIを活用する利点として最も適切なものはどれか。', 'すべての患者に同じ難易度の説明文を提供できる', '患者の理解度に合わせて、説明の表現や難易度を調整した文書を作成できる', '専門用語を多用した正確な医学情報を提供できる', '医療者が患者と直接会話する必要がなくなる', 'C', '生成AIの利点の一つは、同じ医療情報でも患者の理解度や背景に合わせて表現を調整できることである。高齢者向け、小児の保護者向け、医療従事者向けなど、対象に応じた説明文を作成することで、患者の理解促進に寄与できる。', 'A：ヘルスリテラシー支援の目的は、患者個々の理解度に合わせることであり、全員同じでは意味がない。\nC：専門用語の多用は患者の理解を妨げるため、ヘルスリテラシー支援とは逆方向。\nD：AIは補助ツールであり、医療者と患者の直接対話の代替にはならない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-026', '第2章', '栄養管理への活用', '易', '記憶（知識）', '栄養管理業務における生成AIの活用例として最も適切なものはどれか。', 'AIが患者の栄養状態を最終判定する', 'AIが処方された輸液の内容を自動変更する', 'AIが栄養指導資料の下書きを作成し、管理栄養士が確認・修正する', 'AIが経腸栄養剤を自動的に発注する', 'C', '栄養管理業務において、生成AIは栄養指導資料や食事計画の下書き作成などの文書作成支援に活用できる。ただし、最終的な内容は管理栄養士が専門的観点から確認・修正し、患者の個別の状態に合わせて調整する必要がある。', 'A：栄養状態の最終判定は、管理栄養士や医師が専門的評価に基づいて行う。\nB：輸液処方の変更は医師の判断に基づく医療行為であり、AIが自動で行うことはできない。\nD：発注業務には予算管理や在庫確認など、人間の判断が必要な要素がある。', 'HAIPガイドライン（厚生労働省）'),
('Q2-027', '第2章', '創薬・ドラッグリパーパシング', '標準', '理解', 'ドラッグリパーパシング（既存薬再開発）におけるAIの活用として最も適切なものはどれか。', 'AIが既存薬の新たな適応症の候補を予測し、研究者が検証を行う', 'AIが新薬の承認を自動的に行う', 'AIが臨床試験を完全に代替する', 'AIが患者に直接新薬を処方する', 'A', 'ドラッグリパーパシングとは、既存の承認薬を別の疾患の治療に転用することである。AIは大量の医学文献、臨床データ、分子構造情報を分析し、既存薬が有効な可能性のある新たな疾患（適応症）の候補を予測できる。ただし、AIの予測は仮説であり、実際の有効性は研究者による検証と臨床試験で確認する必要がある。', 'B：新薬の承認は規制当局（日本ではPMDA、厚労省）が行うものであり、AIが行うことはない。\nC：臨床試験は人間を対象とした安全性・有効性の検証であり、AIでは代替できない。\nD：処方は医師の医療行為であり、AIが行うことはできない。', 'AI白書2024（IPA）'),
('Q2-028', '第2章', '病院経営分析', '標準', '適用', '病院経営分析に生成AIを活用する場合の適切な用途はどれか。', '経営指標のレポート作成支援と、類似病院とのベンチマーク比較の要約', 'AIの判断のみに基づいて職員の人事異動を決定する', 'AIが病院の経営方針を最終決定する', 'AIが医療費の保険請求を自動で行う', 'A', '病院経営分析において、生成AIは経営指標（稼働率、平均在院日数、診療単価など）のレポート作成、類似規模・機能の病院とのベンチマーク比較の要約などの分析支援に活用できる。ただし、経営判断は病院の経営陣が最終的に行う。', 'B：人事異動は人間（経営陣・人事部門）が総合的に判断すべき事項。\nC：経営方針の決定は経営者・理事会の責任であり、AIに委ねることは不適切。\nD：保険請求は正確性と法的責任が求められ、人間による確認が必要。', 'AI白書2024（IPA）'),
('Q2-029', '第2章', '公衆衛生・疫学', '標準', '理解', '公衆衛生分野における生成AIの活用例として最も適切なものはどれか。', 'AIが感染症の流行を自動的に終息させる', '感染症サーベイランスデータの分析レポート作成や、健康教育資料の作成支援', 'AIがワクチン接種の強制実施を決定する', 'AIが個人の行動を監視して感染者を隔離する', 'B', '公衆衛生分野では、感染症サーベイランスデータの分析・レポート作成、健康教育資料や啓発文書の作成、疫学調査結果の要約などに生成AIを活用できる。これにより保健行政の業務効率化と迅速な情報発信が期待できる。', 'A：感染症の終息は公衆衛生対策や医療介入によるものであり、AIが自動的に終息させることはできない。\nC：ワクチン接種の方針決定は政府・専門家委員会が行い、個人の接種判断は本人の同意に基づく。\nD：個人の監視・隔離は人権に関わる重大事項であり、AIによる自動判断は不適切。', 'AI白書2024（IPA）'),
('Q2-030', '第2章', '患者向け情報提供', '難', '評価', '糖尿病患者向けの食事療法説明資料を生成AIで作成する場合、医療者が確認すべき事項として最も優先度が高いものはどれか。', '資料のデザインが見やすいか', 'カロリー制限や食品交換表の内容が医学的に正確で、個々の患者の状態に適しているか', '資料のページ数が適切か', '使用しているフォントが統一されているか', 'B', '糖尿病の食事療法では、適切なカロリー設定、栄養バランス、食品の選び方などが患者の血糖コントロールに直接影響する。生成AIが作成した資料の内容が医学的に正確であり、かつ個々の患者の病状（腎機能、合併症の有無など）に適しているかを医療者が確認することが最優先である。', 'A：デザインの見やすさも重要だが、医学的内容の正確性が最優先。\nC：ページ数より内容の正確性と必要事項の網羅性が重要。\nD：フォントの統一は体裁の問題であり、内容の正確性確認が優先。', 'HAIPガイドライン（厚生労働省）'),
('Q2-031', '第2章', '臨床意思決定支援（CDS）', '易', '記憶（知識）', 'CDSシステムが提供するアラート機能の例として最も適切なものはどれか。', '病院の駐車場の空き状況の通知', '薬剤の相互作用や重複投与の警告', '病院食のメニュー案内', '職員の出退勤時刻の通知', 'B', 'CDS（臨床意思決定支援）システムのアラート機能は、薬剤の相互作用（飲み合わせの問題）、重複投与（同じ薬の二重処方）、アレルギー歴のある薬剤の処方、検査値の異常などを検知して医師に警告を発する。これにより処方エラーの防止と患者安全の向上に寄与する。', 'A：駐車場情報は施設管理システムの機能であり、CDSとは関係がない。\nC：食事メニューは給食管理システムの機能であり、CDSとは関係がない。\nD：出退勤管理は勤怠管理システムの機能であり、CDSとは関係がない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-032', '第2章', '問診支援', '難', '分析', 'AI問診システムの導入において、システムの精度評価の指標として最も重要なものはどれか。', '問診画面のデザイン評価スコア', '患者の入力にかかる平均時間', '医師の診断結果との一致率（感度・特異度）', 'システムの月額利用料金', 'C', 'AI問診システムの精度評価では、最終的に医師が下した診断とAIが提示した鑑別診断候補がどの程度一致するか（感度：見逃しの少なさ、特異度：誤った候補の少なさ）が最も重要な指標となる。特に医療では見逃しが重大な結果につながるため、感度の高さが重視される。', 'A：デザイン評価は使いやすさに関わるが、システムの医学的精度とは別の指標。\nB：入力時間は利便性の指標だが、精度評価の中核ではない。\nD：料金は経済性の指標であり、精度とは直接関係がない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-033', '第2章', '看護業務への活用', '標準', '適用', 'ICU（集中治療室）の看護師が患者の状態変化の早期発見にAIを活用する場合、最も適切な活用方法はどれか。', 'AIのアラートのみに依存し、ベッドサイドでの患者観察を省略する', 'AIがバイタルサインの異常傾向を検知してアラートを出し、看護師が患者を直接確認する', 'AIのアラートに基づいて、看護師の判断なしに自動的に治療を開始する', 'AIを使用しているので、夜間の巡回を減らす', 'A', 'ICUでのAI活用は、連続モニタリングデータからの異常パターン検知やアラート機能として有効である。ただし、AIのアラートは看護師への注意喚起であり、アラートを受けた看護師が直接患者を確認し、状態を評価することが必要。AIは人間の観察を補助するものであり、代替するものではない。', 'A：AIに依存して患者観察を省略することは、重大な状態変化の見逃しにつながり危険。\nC：治療の開始は医師の指示と看護師の判断に基づくべきであり、自動開始は不適切。\nD：AIがあっても、直接の患者観察（巡回）は必須であり、減らすべきではない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-034', '第2章', '医学研究・論文支援', '易', '記憶（知識）', '系統的レビュー（システマティックレビュー）の作成において、生成AIが補助できる作業として最も適切なものはどれか。', '研究の質の最終評価の決定', '文献の一次スクリーニング（タイトル・抄録の確認）の補助', '結論の導出と公表', '統計解析結果の捏造', 'C', '系統的レビューでは大量の文献をスクリーニングする必要があり、この作業に生成AIを補助的に活用できる。タイトルや抄録に基づいて包含基準を満たす可能性のある文献を効率的に絞り込むことで、研究者の作業負担を軽減できる。ただし、最終的な判断は研究者が行う。', 'A：研究の質の最終評価は、研究者が基準に基づいて責任を持って行う。\nC：結論の導出と公表は研究者の責任であり、AIに委ねることは不適切。\nD：データの捏造は研究不正であり、いかなる場合も許容されない。', 'AI白書2024（IPA）'),
('Q2-035', '第2章', 'AIチャットボットの医療応用', '標準', '理解', '医療機関のウェブサイトに設置するAIチャットボットの適切な機能として最も適切なものはどれか。', '患者の症状から最終診断を行い、処方箋を発行する', '診療時間、予約方法、持ち物などの一般的な問い合わせへの自動応答', '患者の検査結果を解釈して治療方針を指示する', '緊急性の判断を行い、救急車の要請を自動で行う', 'A', '医療機関のAIチャットボットは、診療時間、予約の取り方、初診時の持ち物、アクセス方法などの一般的な問い合わせへの自動応答として有効に活用できる。これにより患者の利便性向上と電話対応業務の軽減が期待できる。医療行為に関わる判断はチャットボットの機能範囲外とすべきである。', 'A：診断と処方は医師の医療行為であり、チャットボットが行うことはできない。\nC：検査結果の解釈と治療方針の指示は医師の判断に基づくべき。\nD：救急車の要請判断は重大な結果を伴う可能性があり、AIの自動判断には委ねられない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-036', '第2章', '薬剤業務への活用', '易', '理解', '生成AIを用いて薬歴（お薬手帳の記録）の要約を作成する場合の留意点として最も適切なものはどれか。', 'AIが要約した内容は常に正確なので、確認は不要である', '薬剤師がAIの出力を確認し、薬剤名、用量、服用方法の正確性を検証する', 'AIが作成した要約をそのまま患者に交付する', '患者の同意なく薬歴情報をAIに入力する', 'A', '薬歴は患者の服薬履歴と安全管理に直結する重要な情報である。AIが生成した要約には、薬剤名の誤り（似た名前の薬との混同）、用量の誤記、服用タイミングの誤りなどが含まれる可能性がある。薬剤師はAI出力を必ず確認し、専門知識に基づいて正確性を検証する必要がある。', 'A：AIの出力には誤りが含まれる可能性があり、特に医薬品情報では確認が必須。\nC：未確認のAI出力をそのまま患者に交付することは、誤情報提供のリスクがあり不適切。\nD：患者情報のAI入力には、個人情報保護の観点から適切な同意と管理が必要。', 'HAIPガイドライン（厚生労働省）'),
('Q2-037', '第2章', '医学教育への活用', '標準', '分析', '医学部の臨床実習前教育において、生成AIを活用した症例シミュレーションを実施する場合の注意点として最も重要なものはどれか。', 'シミュレーションの結果を学生の最終成績に直接反映する', 'AIが生成した症例の医学的妥当性を教員が検証し、不正確な内容が含まれていないか確認する', 'リアリティを高めるため、実在の患者情報をそのまま使用する', 'AIシミュレーションのみで臨床実習を代替する', 'D', '生成AIを用いた症例シミュレーション教材には、医学的に不正確な症状、検査所見、治療経過などが含まれる可能性がある（ハルシネーション）。学生に誤った医学知識を教えることを防ぐため、教員（医師）がAI生成コンテンツの医学的妥当性を必ず検証する必要がある。', 'A：シミュレーション教材の目的は学習であり、成績評価は別の方法で行うべき。\nC：実在の患者情報の使用は個人情報保護違反であり、教育でも許容されない。\nD：AIシミュレーションは補助教材であり、実際の臨床実習は代替できない。', 'AI白書2024（IPA）'),
('Q2-038', '第2章', '医療文書作成支援', '標準', '適用', '診療情報提供書（紹介状）の作成に生成AIを活用する場合、含めるべき情報として最も重要なものはどれか。', '紹介先病院の評判や口コミ', '患者の現在の症状、診断名、実施した検査・治療、紹介目的', '担当医師の趣味や特技', '病院周辺の飲食店情報', 'B', '診療情報提供書（紹介状）は、患者の診療継続のために必要な医療情報を紹介先医療機関に伝える重要な文書である。現在の症状・経過、診断名、実施した検査結果と治療内容、紹介の目的（精査依頼、治療依頼など）を正確に記載することが必須であり、AIを使用する場合もこれらの情報が正確に含まれているか確認が必要。', 'A：紹介先の評判は診療情報とは無関係であり、紹介状に含める内容ではない。\nC：医師個人の情報は診療情報提供には不要。\nD：飲食店情報は医療文書とは無関係。', 'HAIPガイドライン（厚生労働省）'),
('Q2-039', '第2章', 'トリアージ支援', '易', '記憶（知識）', 'トリアージにおける緊急度分類で、一般的に「赤」に分類される状態はどれか。', '軽度の打撲で歩行可能', '生命の危機が迫っており、直ちに処置が必要な状態', '風邪症状で来院', '健康診断の結果について相談したい', 'B', 'トリアージでは緊急度を色で分類することが多い。「赤（Ⅰ度/最優先治療群）」は、生命の危機が迫っており直ちに処置が必要な状態を指す。心肺停止、重度の外傷、ショック状態などが該当する。AIトリアージ支援システムもこのような重症度分類を支援するが、最終判断は医療従事者が行う。', 'A：軽度の打撲で歩行可能は「緑（軽症/待機可能群）」に該当。\nC：風邪症状は通常「緑」または「黄」に該当。\nD：相談目的は緊急性が低く「緑」に該当。', 'HAIPガイドライン（厚生労働省）'),
('Q2-040', '第2章', '音声認識と診療記録', '難', '分析', '診察中の会話を音声認識AIで文字起こしし、カルテの下書きを自動生成するシステム（アンビエント・クリニカル・インテリジェンス）の導入における課題として最も重要なものはどれか。', 'システムの導入費用が高額であること', '音声認識の誤変換や文脈の誤解釈により、誤った医療情報がカルテに記載されるリスク', '医師が話すスピードが遅くなること', '診察室のインテリアを変更する必要があること', 'B', '音声認識による自動カルテ生成では、①専門医学用語の誤認識、②同音異義語の誤変換、③文脈の誤解釈などにより、正確でない医療情報がカルテに記載されるリスクがある。カルテは法的にも重要な診療記録であり、誤った記載は医療過誤や訴訟リスクにつながる可能性があるため、医師による確認が不可欠。', 'A：費用は経営上の課題だが、患者安全に関わる品質リスクがより重要。\nC：話すスピードは運用上の軽微な問題であり、主要な課題ではない。\nD：インテリアの変更は通常不要であり、主要な導入課題ではない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-041', '第2章', '患者向け情報提供', '易', '記憶（知識）', '生成AIを用いて患者向けの検査説明パンフレットを作成する場合、最も重要な確認事項はどれか。', 'パンフレットの色使いがきれいか', '使用している写真の解像度が高いか', '検査の目的、方法、注意事項が医学的に正確に記載されているか', 'パンフレットのサイズがA4であるか', 'C', '患者向け検査説明パンフレットでは、検査の目的（なぜこの検査が必要か）、検査方法（どのように行われるか）、事前の注意事項（食事制限、服薬中止の要否など）が医学的に正確であることが最も重要。誤った情報は患者の安全に直結するため、医療者による内容確認が必須である。', 'A：色使いは視認性に影響するが、医学的正確性が最優先。\nB：写真の解像度は見やすさに関係するが、内容の正確性が優先。\nD：サイズは体裁の問題であり、内容の正確性確認が最優先。', 'HAIPガイドライン（厚生労働省）'),
('Q2-042', '第2章', '多言語対応', '難', '評価', '外国人患者への説明にAI翻訳を使用する際、医学専門用語の翻訳品質を確保するために最も効果的な方法はどれか。', '無料のウェブ翻訳サービスをそのまま使用する', '医療通訳者または多言語対応ができる医療者が、翻訳内容を確認する', '患者が理解したかどうかは確認しない', '翻訳結果をそのまま患者に渡して、読み上げは行わない', 'B', '医学専門用語の翻訳は、一般的なAI翻訳では誤訳のリスクが高い。特に治療に関わる重要な説明では、医療通訳者や多言語対応可能な医療者が翻訳内容を確認し、必要に応じて補足説明を行うことが品質確保に効果的である。', 'A：無料ウェブ翻訳は医学用語の翻訳精度に限界があり、そのままの使用は推奨されない。\nC：患者の理解確認は医療の基本であり、省略すべきではない。\nD：書面を渡すだけでなく、口頭での説明と理解確認が重要。', 'HAIPガイドライン（厚生労働省）'),
('Q2-043', '第2章', '医療画像解析との連携', '易', '記憶（知識）', '医療画像診断AIの活用場面として最も一般的なものはどれか。', 'AIが最終診断を確定し、診断書を自動発行する', 'AIが画像から異常候補を検出し、医師の読影を支援する', 'AIが患者に直接画像診断結果を通知する', 'AIが撮影技師の代わりにX線撮影を実施する', 'B', '医療画像診断AIは、CT、MRI、X線、内視鏡画像などから病変の候補（腫瘍、骨折、出血など）を自動検出し、医師の読影を支援するツールとして活用されている。最終的な診断は放射線科医や担当医が行い、AIはあくまで支援の役割を担う。', 'A：診断の確定と診断書発行は医師の医療行為であり、AIが行うことはできない。\nC：診断結果の通知は医師が患者に説明すべきものであり、AIが直接行うことは不適切。\nD：X線撮影の実施は診療放射線技師の業務であり、AIでは代替できない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-044', '第2章', '医療事務への活用', '標準', '適用', '医療事務担当者が生成AIを用いてレセプト（診療報酬請求書）の点検を行う場合、最も適切な活用方法はどれか。', 'AIの点検結果をそのまま採用し、人間による確認は省略する', 'AIが病名と処置の整合性をチェックした結果を参考に、人間が最終確認を行う', 'AIがレセプトを自動的に審査機関に提出する', 'AIの判断のみで診療報酬を減額する', 'C', 'レセプト点検において、AIは病名と実施した検査・処置の整合性チェック、算定漏れの検出、記載ルールとの照合などを効率的に行える。ただし、レセプト業務は正確性と法的責任が求められるため、AIの点検結果を参考にしつつ、最終確認は人間（医療事務担当者）が行う必要がある。', 'A：AIの点検には誤検出・見逃しの可能性があり、人間による確認の省略は不適切。\nC：レセプト提出は医療機関の責任で行うものであり、AIが自動提出することは不適切。\nD：診療報酬の判断は審査機関が行うものであり、AIが勝手に減額することはできない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-045', '第2章', 'リハビリテーションへの活用', '標準', '理解', '理学療法士がリハビリテーションの経過記録に生成AIを活用する場合の適切な方法はどれか。', 'AIが患者のリハビリの効果を最終評価する', '日々の訓練内容と患者の反応をAIで文章化し、理学療法士が内容を確認・修正する', 'AIの記録をそのまま診療記録として保存する', 'AIがリハビリの終了時期を決定する', 'B', 'リハビリテーションの経過記録作成において、生成AIは日々の訓練内容、患者の動作能力の変化、主観的な訴えなどを文章化する補助ツールとして活用できる。ただし、記録の内容は理学療法士が専門的観点から確認・修正し、正確性を担保した上で保存する必要がある。', 'A：リハビリ効果の評価は理学療法士の専門的判断に基づいて行う。\nC：AIの出力をそのまま診療記録とすることは、誤りが含まれるリスクがあり不適切。\nD：リハビリ終了の判断は、医師と理学療法士が患者の状態を評価して行う。', 'HAIPガイドライン（厚生労働省）'),
('Q2-046', '第2章', '医療DXとの関係', '標準', '理解', '「医療DX」における「全国医療情報プラットフォーム」と生成AIの関係として想定されるものはどれか。', '生成AIがプラットフォーム上のすべての患者情報に自由にアクセスできるようになる', 'プラットフォームに集約された医療情報を、適切なアクセス管理のもとでAI活用に利用できる可能性がある', '生成AIが全国の医療機関の経営を統一的に管理する', 'プラットフォームの構築により、医療機関はAIの利用を禁止される', 'D', '全国医療情報プラットフォームは、医療情報（電子カルテ、処方情報など）を安全に共有・活用するための基盤として構想されている。適切なアクセス管理とセキュリティ確保のもとで、集約された医療情報をAIによる研究や診療支援に活用できる可能性があるが、無制限なアクセスではなく厳格な管理が前提となる。', 'A：患者情報への自由なアクセスは、個人情報保護の観点から認められない。\nC：経営の統一管理はプラットフォームの目的ではなく、AIの役割でもない。\nD：プラットフォーム構築はAI利用を促進する可能性があり、禁止とは逆方向。', '医療DX推進本部資料／厚生労働省'),
('Q2-047', '第2章', '臨床意思決定支援（CDS）', '難', '評価', 'CDS（臨床意思決定支援）システムにおける「アラート疲労」の問題とその対策として最も適切なものはどれか。', 'アラートの数を増やせば増やすほど、医療安全が向上する', '重要度に応じてアラートの優先度を設定し、真に重要な警告が見逃されないようにする', 'アラート機能を完全に無効化し、医師の判断のみに委ねる', 'すべてのアラートに対して同じ緊急度表示を使用する', 'B', 'アラート疲労（Alert Fatigue）とは、過剰なアラートにより医療者がアラートに慣れてしまい、重要な警告を見逃すリスクが高まる現象である。対策として、アラートの重要度・緊急度に応じた優先度設定（ハードストップとソフトアラートの使い分け）、不要なアラートの削減、表示方法の工夫などが有効である。', 'A：アラートの過剰は逆にアラート疲労を招き、重要な警告が無視されるリスクが高まる。\nC：アラート機能の完全無効化は、医療安全を低下させる。\nD：同じ緊急度表示ではアラート疲労を防げず、優先度の区別がつかない。', 'HAIPガイドライン（厚生労働省）'),
('Q2-048', '第2章', '看護業務への活用', '標準', '分析', '看護師が生成AIを用いてケアプランの下書きを作成する場合、特に注意すべき点はどれか。', 'ケアプランの文字数が規定に収まっているか', '患者個別の状態やニーズがAIの一般的な出力に反映されているか確認し、必要に応じて修正する', 'AIが作成したケアプランをそのまま使用する', '他の患者にも同じケアプランを適用できるか確認する', 'B', '生成AIは一般的なケアの内容を提案できるが、患者個別の状態（ADL、既往歴、価値観、家族環境など）を十分に反映できない場合がある。看護師はAIの出力を患者の個別性に照らして確認し、必要に応じて修正・追加を行い、その患者に最適なケアプランに仕上げる必要がある。', 'A：文字数は形式的な問題であり、内容の適切性確認が優先。\nC：AIの出力をそのまま使用することは、患者個別性の欠如につながり不適切。\nD：ケアプランは患者個別に作成すべきであり、他患者への適用を前提とするのは不適切。', 'HAIPガイドライン（厚生労働省）'),
('Q2-049', '第2章', '問診支援', '易', '理解', 'AI問診システムが提示する「鑑別診断リスト」の意味として最も適切なものはどれか。', '患者の最終的な確定診断の結果', '入力された症状から考えられる疾患の候補一覧', '保険適用となる疾患の一覧', '患者が過去にかかった疾患の履歴', 'B', '鑑別診断リストとは、患者が入力した症状や経過情報から、可能性として考えられる疾患の候補一覧を指す。これは医師が診察に入る前の参考情報であり、最終診断ではない。医師はこのリストを参考にしつつ、診察・検査を行って確定診断に至る。', 'A：確定診断は医師の診察・検査に基づいて行われ、AI問診の時点では決定されない。\nC：保険適用疾患リストは別の概念であり、鑑別診断とは異なる。\nD：過去の疾患履歴は既往歴であり、鑑別診断リストとは異なる。', 'HAIPガイドライン（厚生労働省）'),
('Q2-050', '第2章', '医学研究・論文支援', '標準', '適用', '研究者が生成AIを用いて医学論文の英文校正を行う場合の適切な方法はどれか。', 'AIの校正結果をそのまま採用し、提出する', 'AIによる校正後、研究者が内容の正確性と表現の適切性を確認する', '校正にAIを使用したことは一切開示しない', 'AIが提案した表現が元の意味と異なっていても採用する', 'B', '生成AIによる英文校正は効率的だが、①専門用語の不適切な言い換え、②ニュアンスの変化、③文脈の誤解による修正などのリスクがある。研究者はAIの校正結果を確認し、元の意味が正確に保たれているか、医学的な表現として適切かを検証する必要がある。', 'A：AIの校正結果には誤りや不適切な修正が含まれる可能性があり、確認なしの採用は不適切。\nC：多くの学術誌がAI使用の開示を求めており、隠すことは研究倫理上問題がある。\nD：元の意味と異なる表現の採用は、研究内容の誤伝につながり不適切。', 'AI白書2024（IPA）'),
('Q2-051', '第2章', '患者説明・IC支援', '難', '評価', 'がん患者へのインフォームドコンセント説明資料を生成AIで作成する場合、最も重視すべき配慮はどれか。', '専門用語を多用して医学的正確性を高める', '良い面のみを強調して患者を安心させる', '治療選択肢、期待される効果と副作用を正確かつ患者が理解できる表現で記載し、医師が内容を確認する', 'AIの出力をそのまま使用してコストを削減する', 'C', 'がん治療のICでは、患者が治療の選択肢（手術、化学療法、放射線療法など）、各治療の期待される効果、副作用・合併症のリスクを理解した上で意思決定できることが重要。生成AIで資料を作成する場合も、これらの情報が正確に記載され、かつ患者が理解できる表現になっているか医師が確認する必要がある。', 'A：専門用語の多用は患者の理解を妨げ、ICの目的に反する。\nB：良い面のみの強調は正確な情報提供に反し、ICの要件を満たさない。\nD：AIの出力には誤りや不適切な表現が含まれる可能性があり、確認なしの使用は不適切。', 'HAIPガイドライン（厚生労働省）／医師法'),
('Q2-052', '第2章', '薬剤業務への活用', '標準', '適用', '薬剤師が処方監査において薬剤相互作用のチェックにAIを活用する場合、適切な運用方法はどれか。', 'AIが相互作用なしと判定したら、薬剤師の確認は不要', 'AIの検出結果を参考にしつつ、最終判断は薬剤師が専門知識に基づいて行う', 'AIが相互作用ありと判定したら、自動的に処方を却下する', 'AIの判定が医師の処方と異なる場合は、AIを優先する', 'B', '薬剤相互作用のチェックにおいて、AIは大量の薬剤情報を効率的にスクリーニングできる有用なツールである。しかし、AIの検出には見逃しや誤検出の可能性があるため、最終的な判断は薬剤師が専門知識に基づいて行う必要がある。臨床的に問題となる相互作用かどうかの判断には、患者個別の状態も考慮が必要。', 'A：AIの見逃しの可能性があるため、薬剤師の確認は省略できない。\nC：相互作用があっても臨床上許容される場合があり、自動却下は不適切。疑義照会で確認する。\nD：医師の処方を覆す判断は、薬剤師が医師と協議して行うべき。', 'HAIPガイドライン（厚生労働省）'),
('Q2-053', '第2章', 'AIチャットボットの医療応用', '易', '記憶（知識）', '患者向け医療AIチャットボットに実装すべき機能として最も重要なものはどれか。', '天気予報の表示', '緊急性の高い症状を認識し、速やかな受診を促すメッセージの表示', '占いや運勢の提供', 'ゲーム機能の搭載', 'B', '患者向け医療AIチャットボットにおいて最も重要な機能は、患者安全に関わる対応である。胸痛、呼吸困難、意識障害などの緊急性の高い症状を認識し、「すぐに医療機関を受診してください」「救急車を呼んでください」などの適切なメッセージを表示する機能は、患者の命を守るために不可欠。', 'A：天気予報は医療チャットボットの本質的機能ではない。\nC：占いは医療とは無関係であり、医療AIに不適切。\nD：ゲーム機能は医療チャットボットの目的に合致しない。', 'AI事業者ガイドライン（第1.1版）'),
('Q2-054', '第2章', '医療文書作成支援', '易', '記憶（知識）', '生成AIによる医療文書作成支援が有効と考えられる文書はどれか。', '死亡診断書の作成', '退院サマリーの下書き作成', '麻薬処方箋の発行', '医師免許の発行', 'A', '退院サマリーは、患者の入院経過、診断、治療内容、退院時の状態などをまとめた文書であり、生成AIによる下書き作成が業務効率化に有効である。ただし、医師が内容を確認・修正した上で最終化する必要がある。', 'A：死亡診断書は法的効力を持つ重要文書であり、医師が直接作成・署名する必要がある。\nC：麻薬処方箋は厳格な規制のもとで医師が発行するものであり、AIによる自動発行は認められない。\nD：医師免許は国（厚生労働大臣）が発行するものであり、AIとは無関係。', 'HAIPガイドライン（厚生労働省）'),
('Q2-055', '第2章', '医学教育への活用', '難', '分析', '医学部の試験問題作成に生成AIを活用する場合の課題として最も重要なものはどれか。', '問題文のフォント選択', 'AIが生成した問題内容の医学的正確性の確認と、過去問題との重複チェック', '試験用紙の印刷品質', '試験会場の座席配置', 'B', '試験問題作成にAIを活用する場合、①AIが生成した問題・選択肢・解答の医学的正確性（ハルシネーションがないか）、②既存の問題集や過去問との重複・類似（公正性の確保）、③難易度の適切性などを教員が確認する必要がある。誤った問題は学生の学習に悪影響を与える。', 'A：フォント選択は体裁の問題であり、内容の正確性確認が優先。\nC：印刷品質は運営上の問題であり、問題内容の課題ではない。\nD：座席配置は試験運営の問題であり、AI活用の課題ではない。', 'AI白書2024（IPA）'),
('Q2-056', '第2章', '臨床意思決定支援（CDS）', '易', '理解', 'CDSシステムが医師に提示する情報として適切なものはどれか。', '患者の診断を確定する最終判断', 'エビデンスに基づく治療ガイドラインの参照情報や、類似症例の治療経過', '医師の報酬額の計算', '病院の株価情報', 'B', 'CDSシステムは、医師の臨床判断を支援するため、エビデンスに基づく診療ガイドライン、類似症例の治療経過、検査値の基準範囲、薬剤情報などを提示する。これらは医師の意思決定を補助する参考情報であり、最終判断は医師が行う。', 'A：診断の確定判断は医師が行うものであり、CDSが決定することではない。\nC：報酬計算は人事・経理システムの機能であり、CDSとは無関係。\nD：株価情報は金融情報であり、臨床意思決定支援とは無関係。', 'HAIPガイドライン（厚生労働省）'),
('Q2-057', '第2章', '患者向け情報提供', '標準', '分析', '高齢患者向けの服薬説明書を生成AIで作成する場合、特に配慮すべき点はどれか。', '最新の医学論文からの引用を多く含める', '文字サイズは小さくして情報量を増やす', '平易な表現、大きな文字、服用タイミングの明確な記載など、高齢者の理解しやすさに配慮する', '英語併記を必須とする', 'C', '高齢患者向けの服薬説明書では、加齢による視力低下や認知機能の変化に配慮した工夫が必要である。大きな文字、平易な表現、服用タイミング（朝食後、就寝前など）の明確な記載、イラストの活用などにより、患者が正しく服薬できるよう支援する。AIで作成する場合もこれらの配慮が反映されているか確認が必要。', 'A：学術論文の引用は一般患者向け資料には不適切であり、平易な説明が優先される。\nB：小さな文字は高齢者の視認性を低下させ、服薬ミスにつながるリスクがある。\nD：日本語を母語とする高齢者には、英語併記の必要性は低い。', 'HAIPガイドライン（厚生労働省）'),
('Q2-058', '第2章', '医療画像解析との連携', '標準', '理解', '内視鏡検査におけるAI活用の例として最も適切なものはどれか。', 'AIが自動的に内視鏡を操作して検査を実施する', 'AIがリアルタイムで病変候補を検出し、医師の見落とし防止を支援する', 'AIが検査結果を直接患者に通知する', 'AIが内視鏡検査の必要性を最終判断する', 'A', '内視鏡検査AIは、検査中にリアルタイムで画像を解析し、ポリープ、早期がんなどの病変候補を検出して医師に通知することで、見落とし防止を支援する。最終的な診断は内視鏡医が行い、AIは検出支援ツールとして機能する。', 'A：内視鏡の操作は医師が行う医療行為であり、AIが自動操作することは現時点では一般的でない。\nC：検査結果の通知は医師が患者に説明すべきものであり、AIが直接通知することは不適切。\nD：検査の必要性判断は医師が行うものであり、AIが最終決定することは不適切。', 'HAIPガイドライン（厚生労働省）'),
('Q2-059', '第2章', '看護業務への活用', '難', '評価', '入院患者の転倒リスク評価にAIを活用する場合、最も重要な運用上の考慮事項はどれか。', 'AIが低リスクと判定した患者への見守りを減らす', 'AIのリスク評価を参考にしつつ、看護師の観察と判断を組み合わせて予防策を講じる', 'AIの判定結果を患者本人に直接伝える', 'AIのリスク評価に基づいて自動的に患者を拘束する', 'D', '転倒リスク評価AIは、患者の年齢、疾患、薬剤、ADLなどからリスクを算出する補助ツールである。しかし、AIには捉えきれない要素（その日の体調、環境変化への反応など）もあるため、看護師による直接観察と専門的判断を組み合わせ、個別の予防策を講じることが重要。', 'A：AIが低リスクと判定しても、状態は変化するため見守りを減らすことは危険。\nC：リスク評価の伝達は医療者が適切に説明すべきであり、AIが直接伝えることは不適切。\nD：患者拘束は人権に関わる重大な判断であり、AIによる自動決定は絶対に不適切。', 'HAIPガイドライン（厚生労働省）'),
('Q2-060', '第2章', '医療DXとの関係', '易', '記憶（知識）', '「電子処方箋」制度と生成AIの活用可能性として考えられるものはどれか。', '生成AIが処方内容を自動的に決定する', '電子処方箋データを活用した服薬指導文書の作成支援', '生成AIが患者の代わりに薬局で薬を受け取る', '生成AIが保険証の資格確認を行う', 'A', '電子処方箋により処方データがデジタル化されることで、そのデータをもとに生成AIが服薬指導文書の下書きを作成するなど、業務効率化の活用可能性がある。ただし、最終的な服薬指導は薬剤師が患者に直接行う必要がある。', 'A：処方内容の決定は医師の医療行為であり、AIが自動決定することはできない。\nC：薬の受け取りは本人確認を伴う行為であり、AIが代行することはできない。\nD：保険資格確認はオンライン資格確認システムで行われるものであり、生成AIの機能ではない。', '医療DX推進本部資料／厚生労働省'),
('Q3-001', '第3章', '個人情報保護法の基本原則', '易', '記憶（知識）', '個人情報保護法における「利用目的の特定」の原則として最も適切なものはどれか。', '個人情報を取得する際に、できる限り利用目的を特定しなければならない', '利用目的は社内で決定すればよく、本人に通知する必要はない', '利用目的は事後的にいつでも自由に変更できる', '利用目的の特定は大企業のみに義務付けられている', 'A', '個人情報保護法第17条により、個人情報取扱事業者は、個人情報を取り扱うにあたり、その利用目的をできる限り特定しなければならない。医療機関では「診療」「医療費の請求」「他の医療機関への紹介」など、具体的な利用目的を特定して患者に通知・公表することが求められる。', 'B：利用目的は本人に通知または公表することが法律で義務付けられている。\nC：利用目的の変更は、変更前の利用目的と関連性を有すると合理的に認められる範囲に限られる。\nD：利用目的の特定義務は事業者の規模に関わらず適用される。', '個人情報の保護に関する法律 第17条、第18条／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-002', '第3章', '要配慮個人情報', '易', '記憶（知識）', '個人情報保護法における「要配慮個人情報」に該当するものはどれか。', '患者の氏名と住所', '患者の病歴および診療記録', '病院の電話番号', '医師の勤務スケジュール', 'B', '個人情報保護法第2条第3項により、「要配慮個人情報」とは、本人の人種、信条、社会的身分、病歴、犯罪の経歴、犯罪により害を被った事実その他本人に対する不当な差別、偏見その他の不利益が生じないようにその取扱いに特に配慮を要する情報をいう。病歴および診療記録はこれに該当し、取得には原則として本人の同意が必要。', 'A：氏名・住所は「個人情報」に該当するが、それ自体は「要配慮個人情報」には該当しない。\nC：病院の電話番号は法人の情報であり、個人情報にも要配慮個人情報にも該当しない。\nD：医師の勤務スケジュールは個人情報に該当し得るが、病歴等の機微情報ではないため要配慮個人情報には該当しない。', '個人情報の保護に関する法律 第2条第3項／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-003', '第3章', '個人情報の第三者提供', '標準', '理解', '医療機関が患者の個人情報を第三者に提供できる場合として適切でないものはどれか。', '患者本人の同意がある場合', '法令に基づく場合（感染症法に基づく届出など）', '人の生命・身体の保護のために必要で、本人同意を得ることが困難な場合', '医療機関の利益のために必要と判断した場合', 'C', '個人情報の第三者提供は原則として本人の同意が必要だが、①法令に基づく場合、②人の生命・身体・財産の保護に必要で本人同意を得ることが困難な場合、③公衆衛生・児童の健全育成に必要で本人同意を得ることが困難な場合、④国等の事務への協力が必要な場合には例外的に認められる。医療機関の利益のためという理由は認められない。', 'A：本人同意がある場合は、原則として第三者提供が可能。\nB：感染症法に基づく届出など、法令に基づく提供は例外として認められている。\nC：救急患者の家族への連絡など、生命・身体の保護に必要な場合は例外として認められている。', '個人情報の保護に関する法律 第27条／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-004', '第3章', '医療情報システムの安全管理ガイドライン', '標準', '理解', '厚生労働省「医療情報システムの安全管理に関するガイドライン」の目的として最も適切なものはどれか。', '医療機関の経営効率を最大化すること', '医療情報システムの安全管理に関する指針を示し、患者情報の適切な保護を図ること', '医療従事者の給与体系を統一すること', '医療機関の建築基準を定めること', 'B', '「医療情報システムの安全管理に関するガイドライン」は、電子カルテなどの医療情報システムにおける患者情報の安全管理について、技術的・組織的・人的な対策の指針を示したものである。e-文書法や個人情報保護法への対応、サイバーセキュリティ対策などを包括的に定めている。', 'A：経営効率化はガイドラインの主目的ではなく、患者情報の保護が目的。\nC：給与体系は労務管理の領域であり、本ガイドラインの対象外。\nD：建築基準は建築基準法の領域であり、本ガイドラインの対象外。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-005', '第3章', '生成AIサービスへのデータ入力リスク', '標準', '分析', '医療機関の職員が業務で生成AIサービスを利用する際、最もリスクが高い行為はどれか。', '公開されている医学論文の要約をAIに依頼する', '院内で作成した研修資料の誤字チェックをAIに依頼する', '患者の氏名・病名・検査値を含むカルテ情報をそのまま入力し、サマリー作成を依頼する', '一般的な疾患の説明文を生成するようAIに指示する', 'C', '患者の氏名・病名・検査値は要配慮個人情報を含む。これを外部のクラウド型生成AIサービスに入力すると、①入力データがAI事業者のサーバーに送信・保存される可能性、②入力データがモデルの学習に利用される可能性、③第三者への個人情報の提供に該当する可能性があり、個人情報保護法違反のリスクがある。', 'A：公開論文は一般に入手可能な情報であり、個人情報を含まないためリスクは相対的に低い。\nB：院内研修資料は通常、個人情報を含まない一般的な内容でありリスクは低い。\nD：一般的な疾患の説明文の生成は、特定の患者情報を含まないためリスクは低い。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）／個人情報保護法'),
('Q3-006', '第3章', '匿名加工情報／仮名加工情報', '標準', '理解', '個人情報保護法における「匿名加工情報」と「仮名加工情報」の違いとして最も適切なものはどれか。', '匿名加工情報は復元不可能に加工したもの、仮名加工情報は他の情報と照合すれば特定可能なもの', '両者に違いはなく、同じものを指す', '仮名加工情報は復元不可能に加工したもの、匿名加工情報は他の情報と照合すれば特定可能なもの', '匿名加工情報は医療分野専用、仮名加工情報は一般企業専用の概念である', 'A', '匿名加工情報は、特定の個人を識別できないように加工し、かつ当該個人情報を復元できないようにしたものであり、一定のルールのもとで本人同意なく第三者提供が可能。仮名加工情報は、他の情報と照合しない限り特定の個人を識別できないように加工したものであり、内部での分析利用を目的とし、第三者提供は原則禁止。', 'B：両者は異なる概念であり、利用条件や第三者提供の可否が異なる。\nC：説明が逆。匿名加工が復元不可能、仮名加工が照合により特定可能。\nD：両者とも分野を問わず適用される一般的な概念である。', '個人情報の保護に関する法律／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-007', '第3章', '次世代医療基盤法', '標準', '理解', '次世代医療基盤法（医療分野の研究開発に資するための匿名加工医療情報に関する法律）の目的として最も適切なものはどれか。', '医療機関の経営を国が直接管理すること', '医療情報を匿名加工して研究開発に利活用できる仕組みを整備すること', 'すべての医療情報を公開すること', '医療従事者の資格試験を実施すること', 'A', '次世代医療基盤法（2018年施行）は、医療情報を匿名加工し、認定事業者を通じて研究開発に利活用できる仕組みを整備することで、健康・医療に関する先端的研究開発や新産業創出を促進することを目的としている。患者はオプトアウトにより提供を拒否することもできる。', 'A：国による経営管理は本法の目的ではない。\nC：すべての情報を公開するのではなく、匿名加工した上で研究利用を可能にする制度。\nD：資格試験は本法の目的外。医療情報の利活用促進が目的。', '次世代医療基盤法／内閣府'),
('Q3-008', '第3章', '電子カルテとAI連携時の注意点', '標準', '適用', '電子カルテのデータを生成AIに入力して活用する場合、最も重要な注意点はどれか。', '電子カルテの画面デザインを統一すること', '患者の個人情報を適切に匿名化または削除してからAIに入力すること', 'AIの処理速度を最大化すること', '電子カルテのフォントサイズを大きくすること', 'B', '電子カルテには患者の氏名、生年月日、病歴などの要配慮個人情報が含まれる。外部のAIサービスに入力する場合は、これらの個人情報を適切に匿名化または削除し、特定の個人が識別できない状態にしてから利用する必要がある。個人情報をそのまま入力することは、個人情報の第三者提供に該当し得る。', 'A：画面デザインは操作性の問題であり、個人情報保護とは直接関係がない。\nC：処理速度より個人情報の保護が優先される。\nD：フォントサイズは表示の問題であり、AI連携の注意点ではない。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-009', '第3章', '3省2ガイドライン', '易', '記憶（知識）', '医療情報を扱うクラウドサービスに関する「3省2ガイドライン」に含まれるガイドラインはどれか。', '医療情報システムの安全管理に関するガイドライン（厚労省）と、医療情報を取り扱う情報システム・サービスの提供事業者における安全管理ガイドライン（総務省・経産省）', '食品衛生法に基づくガイドラインと医薬品製造に関するガイドライン', '建築基準法に基づくガイドラインと消防法に基づくガイドライン', '労働基準法に基づくガイドラインと雇用保険法に基づくガイドライン', 'A', '3省2ガイドラインとは、厚生労働省の「医療情報システムの安全管理に関するガイドライン」と、総務省・経済産業省の「医療情報を取り扱う情報システム・サービスの提供事業者における安全管理ガイドライン」の2つを指す。医療機関とITベンダーの双方に向けた安全管理の指針を示している。', 'B：食品・医薬品関連のガイドラインは3省2ガイドラインには含まれない。\nC：建築・消防関連のガイドラインは3省2ガイドラインには含まれない。\nD：労働・雇用関連のガイドラインは3省2ガイドラインには含まれない。', '3省2ガイドライン（厚労省・総務省・経産省）'),
('Q3-010', '第3章', '医療情報の定義と範囲', '易', '記憶（知識）', '医療機関が取り扱う「医療情報」に含まれるものとして適切でないものはどれか。', '診療録（カルテ）', 'レセプト（診療報酬明細書）', '検査データ・画像データ', '病院周辺の地図情報', 'D', '医療情報とは、診療録（カルテ）、処方箋、検査データ、画像データ、レセプト、看護記録など、患者の診療に関連する情報を指す。病院周辺の地図情報は患者の診療とは直接関係がなく、医療情報には含まれない。', 'A：診療録（カルテ）は最も基本的な医療情報であり、法律で保存が義務付けられている。\nB：レセプトは診療内容を記載した書類であり、医療情報に含まれる。\nC：検査データ・画像データは診療に不可欠な医療情報である。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-011', '第3章', 'クラウドサービス利用の注意点', '標準', '理解', '医療機関がクラウドサービスを利用して医療情報を管理する場合、データ管理責任に関する記述として最も適切なものはどれか。', 'クラウド事業者にすべての責任が移転するため、医療機関の責任は免除される', 'クラウド事業者が契約に基づきシステムの安全管理を行うが、患者情報の管理責任は医療機関が負う', 'クラウド利用の場合、個人情報保護法は適用されない', 'データセンターの物理的セキュリティは医療機関が直接管理する', 'B', 'クラウドサービスを利用する場合でも、患者の個人情報を管理する責任は医療機関（個人情報取扱事業者）にある。クラウド事業者は委託先として契約に基づき安全管理措置を講じるが、最終的な管理責任は委託元である医療機関が負う。医療機関はクラウド事業者の安全管理状況を監督する義務がある。', 'A：クラウド利用によって医療機関の責任が免除されるわけではない。委託先の監督義務が生じる。\nC：クラウド利用でも個人情報保護法は適用される。\nD：データセンターの物理的セキュリティはクラウド事業者が管理するが、医療機関は契約でその水準を確認する。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-012', '第3章', 'データの越境移転', '標準', '理解', '医療情報を海外のクラウドサービスで取り扱う場合（データの越境移転）に関する記述として最も適切なものはどれか。', '海外のサービスを利用する場合、日本の個人情報保護法は適用されない', '海外の法制度や規制を確認し、個人情報保護法に基づく適切な措置を講じる必要がある', '海外のサービスの方がセキュリティが高いので、積極的に利用すべきである', '患者の同意があれば、どの国にデータを移転しても問題ない', 'D', '医療情報を海外のクラウドサービスで取り扱う場合、個人情報保護法に基づく「外国にある第三者への提供」の規制が適用される。移転先の国の法制度（政府によるアクセスの可能性など）を確認し、適切な契約や本人同意の取得など、法令に基づく措置を講じる必要がある。', 'A：日本の医療機関が取り扱う情報には、海外サービス利用時も日本の個人情報保護法が適用される。\nC：海外サービスのセキュリティが必ずしも高いとは限らず、法的リスクも考慮が必要。\nD：同意があっても、移転先の国の基準や契約条件など、追加の措置が必要な場合がある。', '個人情報保護法 第28条／医療情報システムの安全管理に関するガイドライン 第6.0版'),
('Q3-013', '第3章', 'アクセス制御とログ管理', '易', '記憶（知識）', '医療情報システムにおける「アクセス制御」の目的として最も適切なものはどれか。', 'システムの処理速度を向上させること', '権限のある者だけが必要な情報にアクセスできるようにし、不正アクセスを防ぐこと', 'すべての職員が全患者の情報に自由にアクセスできるようにすること', '患者がインターネットから自由に診療記録にアクセスできるようにすること', 'C', 'アクセス制御とは、情報システムにおいて「誰が」「どの情報に」「どのような操作で」アクセスできるかを管理・制限する仕組みである。医療機関では、職種や担当患者に応じてアクセス権限を設定し、業務上必要な範囲に限定してアクセスを許可することで、不正アクセスや情報漏洩を防止する。', 'A：処理速度向上はパフォーマンス最適化の目的であり、アクセス制御の目的ではない。\nC：全職員が全情報にアクセスできる状態はセキュリティ上問題があり、アクセス制御の目的に反する。\nD：患者の情報アクセスは適切な認証と範囲設定が必要であり、自由なアクセスは不適切。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-014', '第3章', 'オプトアウト／オプトイン', '易', '記憶（知識）', '個人情報の取得・利用に関する「オプトイン」と「オプトアウト」の説明として最も適切なものはどれか。', 'オプトインは本人の事前同意に基づく方式、オプトアウトは本人の拒否がない限り利用する方式', 'オプトインもオプトアウトも同じ意味で使われる', 'オプトアウトは本人の事前同意に基づく方式、オプトインは本人の拒否がない限り利用する方式', 'オプトイン・オプトアウトは医療分野では使用されない概念である', 'A', 'オプトイン（Opt-in）は、本人が積極的に同意した場合にのみ情報を取得・利用する方式。オプトアウト（Opt-out）は、本人が明示的に拒否しない限り情報を取得・利用できる方式。要配慮個人情報の取得は原則オプトイン（本人同意）が必要だが、次世代医療基盤法では一定の条件下でオプトアウト方式が認められている。', 'B：オプトインとオプトアウトは同意取得の方式として異なる概念である。\nC：説明が逆。オプトインが事前同意、オプトアウトが拒否なければ利用。\nD：医療分野でも患者同意の取得方式として使用される重要な概念。', '個人情報保護法／次世代医療基盤法'),
('Q3-015', '第3章', 'インシデント対応', '標準', '適用', '医療機関で患者の個人情報が漏洩した可能性が判明した場合、最初に行うべき対応として最も適切なものはどれか。', '漏洩の事実を隠蔽し、外部に知られないようにする', '被害の拡大防止措置を講じた上で、事実関係の調査と関係者への報告を行う', '責任者の特定と処分を最優先で行う', 'メディア対応のための記者会見を最初に準備する', 'B', '個人情報漏洩が発生した場合、まず被害の拡大防止措置（システムの停止、アクセス権の無効化など）を講じ、事実関係を調査する。その後、個人情報保護委員会への報告、本人への通知、必要に応じて公表などを行う。隠蔽は法令違反となり、より大きな問題につながる。', 'A：漏洩の隠蔽は個人情報保護法違反であり、発覚時にさらなる信頼失墜につながる。\nC：責任者の処分は事後対応であり、最初に行うべきは被害拡大防止と事実調査。\nD：記者会見は事実関係が明らかになった後の対応であり、最初に行うべきではない。', '個人情報保護法／医療情報システムの安全管理に関するガイドライン 第6.0版'),
('Q3-016', '第3章', '医療機関におけるサイバーセキュリティ', '標準', '理解', '医療機関を標的としたランサムウェア攻撃の特徴として最も適切なものはどれか。', '医療機関のデータは価値がないため攻撃対象になりにくい', 'データを暗号化して使用不能にし、復旧と引き換えに身代金を要求する', '攻撃者は常に病院内部の職員である', 'ランサムウェアはインターネット接続がなければ感染しない', 'B', 'ランサムウェアは、感染したシステムのデータを暗号化して使用不能にし、復旧のための復号キーと引き換えに身代金（ランサム）を要求するマルウェアである。医療機関では診療継続への影響が大きく、近年被害が増加している。厚労省も注意喚起を行っている。', 'A：医療データは機密性が高く、攻撃者にとって高価値な標的となっている。\nC：攻撃者は外部のサイバー犯罪者が大半であり、必ずしも内部職員ではない。\nD：USBメモリなど物理媒体経由でも感染する可能性があり、オフラインでも完全には防げない。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-017', '第3章', '個人情報の第三者提供', '難', '分析', '医療機関が患者情報を他の医療機関に提供する場合で、本人同意なく提供できるのはどれか。', '研究目的で大学病院にデータを提供する場合', '紹介状を持参せずに来院した患者について、前医の診療情報を取り寄せる場合', '救急搬送された意識不明患者の情報を、治療に必要な範囲で他院に提供する場合', '患者の情報を製薬会社の営業担当者に提供する場合', 'C', '個人情報保護法では、「人の生命、身体又は財産の保護のために必要がある場合であって、本人の同意を得ることが困難であるとき」は本人同意なく第三者提供が可能とされている。救急搬送された意識不明患者の治療に必要な情報提供は、この例外規定に該当する。', 'A：研究目的の情報提供には原則として本人同意が必要（匿名加工など適切な措置を講じる場合を除く）。\nB：診療情報の取り寄せは患者の利便性のためであり、本人同意が必要。\nD：製薬会社への情報提供は診療目的外であり、本人同意なしには提供できない。', '個人情報保護法 第27条／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-018', '第3章', '暗号化と通信セキュリティ', '易', '記憶（知識）', '医療情報をインターネット経由で送信する際に使用すべき暗号化通信プロトコルはどれか。', 'HTTP', 'FTP', 'HTTPS（TLS/SSL）', 'SMTP', 'C', 'HTTPS（Hypertext Transfer Protocol Secure）は、TLS/SSL暗号化を用いた安全な通信プロトコルであり、通信内容の盗聴や改ざんを防止できる。医療情報のような機密性の高いデータをインターネット経由で送信する際は、HTTPS通信を使用することが推奨される。', 'A：HTTPは暗号化されていない通信であり、機密情報の送信には不適切。\nB：FTPは暗号化されていないファイル転送プロトコルであり、機密情報の送信には不適切。\nD：SMTPはメール送信プロトコルであり、暗号化には別途対策が必要。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-019', '第3章', '生成AIサービスへのデータ入力リスク', '難', '分析', '医療従事者が生成AIサービスを業務利用する際、入力データに関するリスク評価として最も重要な確認事項はどれか。', 'AIサービスの利用料金が安いかどうか', '入力データがAIの学習に使用されるか、データがどこに保存されるか', 'AIの回答が素早いかどうか', 'AIサービスのロゴデザインが適切か', 'A', '生成AIサービスに入力したデータは、サービス提供者のサーバーに送信される。そのデータが①AIモデルの学習に使用されるか、②どこに保存されるか（国内/海外）、③どのくらいの期間保持されるかは、個人情報保護の観点から最も重要な確認事項である。利用規約やプライバシーポリシーで確認する必要がある。', 'A：料金は運用上の考慮事項だが、個人情報保護リスクより優先度は低い。\nC：回答速度は利便性の問題であり、セキュリティリスク評価とは異なる。\nD：ロゴデザインはセキュリティとは無関係。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）／AI事業者ガイドライン'),
('Q3-020', '第3章', '医療情報の二次利用', '標準', '理解', '医療情報の「二次利用」の説明として最も適切なものはどれか。', '患者本人の診療以外の目的で医療情報を利用すること', '同じ患者を2回診療すること', '電子カルテを2台のパソコンで同時に開くこと', '診療報酬を2回請求すること', 'A', '医療情報の二次利用とは、患者本人の診療という本来の目的（一次利用）以外の目的で医療情報を利用することを指す。具体的には、医学研究、公衆衛生、医療政策の立案、医療の質向上のための分析などが該当する。二次利用には適切な同意取得や匿名化などの措置が必要となる。', 'B：同じ患者を複数回診療することは通常の診療行為であり、二次利用ではない。\nC：電子カルテの同時表示は技術的な利用形態であり、二次利用とは異なる概念。\nD：診療報酬の二重請求は不正請求であり、二次利用とは全く異なる。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）／次世代医療基盤法'),
('Q3-021', '第3章', '要配慮個人情報', '標準', '適用', '医療機関の受付担当者が患者の診察券を作成する際、「要配慮個人情報」の取得に関して最も適切な対応はどれか。', '患者の氏名・住所・電話番号のみを聞き取り、病歴は診察時に医師が確認する', '問診票で病歴を聞き取る前に、利用目的を明示し本人の同意を得る', '病歴は本人に聞かず、家族から聞き取る', '要配慮個人情報は一切取得しない', 'D', '要配慮個人情報（病歴など）の取得には、原則として本人の同意が必要である。医療機関では、問診票などで病歴を聞き取る前に、利用目的（診療のため等）を明示し、本人から同意を得る必要がある。多くの医療機関では、初診時に包括的な同意を得る運用をしている。', 'A：氏名等も個人情報であり利用目的の明示は必要。また、病歴は診察前に問診で把握することが一般的。\nC：本人から直接聞き取ることが原則であり、家族からの聞き取りは本人確認の観点から問題がある。\nD：医療機関で診療を行うには病歴等の要配慮個人情報の取得が不可欠。', '個人情報保護法／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-022', '第3章', '医療情報システムの安全管理ガイドライン', '標準', '理解', '「医療情報システムの安全管理に関するガイドライン第6.0版」の構成として正しいものはどれか。', '1編のみで構成されている', '概説編、経営管理編、企画管理編、システム運用編の4編で構成されている', '医師向けと看護師向けの2編で構成されている', '国内向けと海外向けの2編で構成されている', 'B', '医療情報システムの安全管理に関するガイドライン第6.0版は、①概説編（全体像と基本概念）、②経営管理編（経営層向け）、③企画管理編（システム管理者向け）、④システム運用編（運用担当者向け）の4編で構成されている。対象読者に応じた内容が整理されている。', 'A：1編ではなく4編で構成されている。\nC：職種別（医師・看護師）ではなく、役割別（経営層・管理者・運用担当者）で編成されている。\nD：国内・海外という区分ではない。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-023', '第3章', 'アクセス制御とログ管理', '標準', '適用', '電子カルテシステムのアクセスログに記録すべき情報として適切でないものはどれか。', 'アクセスした職員のID', 'アクセスした日時', '閲覧・更新した患者の識別情報', '職員の私的なメール内容', 'D', '電子カルテのアクセスログには、「誰が」「いつ」「どの患者の情報に」「どのような操作を行ったか」を記録する。これにより、不正アクセスの検知や事後調査が可能となる。職員の私的なメール内容は電子カルテシステムとは無関係であり、ログの対象外。', 'A：アクセスした職員のIDは、誰がアクセスしたかを特定するために必須の記録項目。\nB：アクセス日時は、いつアクセスしたかを特定するために必須の記録項目。\nC：閲覧・更新した患者の識別情報は、どの情報にアクセスしたかを特定するために必須。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-024', '第3章', '匿名加工情報／仮名加工情報', '難', '分析', '医療研究目的でデータを利活用する際、「仮名加工情報」を選択するメリットとして最も適切なものはどれか。', '第三者への提供が自由にできる', '匿名加工情報より加工の程度が軽く、データの有用性を保ちやすい', '本人からの開示請求に対応する義務が発生する', '個人情報保護法の規制から完全に外れる', 'D', '仮名加工情報は、氏名等の直接識別子を削除・置換するが、匿名加工情報ほど厳密な加工は不要である。そのため、データの有用性（分析精度など）を保ちやすいというメリットがある。ただし、内部利用に限定され、第三者提供は原則禁止という制約がある。', 'A：仮名加工情報は第三者への提供が原則禁止されており、自由に提供できるわけではない。\nC：仮名加工情報に加工された場合、本人からの開示請求への対応義務は適用除外となる。\nD：仮名加工情報も個人情報保護法の規制対象であり、完全に外れるわけではない。', '個人情報保護法／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-025', '第3章', 'PHR（Personal Health Record）', '易', '記憶（知識）', 'PHR（Personal Health Record）の説明として最も適切なものはどれか。', '医療機関のみが管理する診療記録', '患者自身が自らの健康・医療情報を管理・活用できる仕組み', '保険会社専用の医療費データベース', '製薬会社が管理する臨床試験データ', 'B', 'PHR（Personal Health Record：パーソナルヘルスレコード）とは、患者・個人が自らの健康・医療情報を収集・管理し、自身の健康管理や医療機関との情報共有に活用できる仕組みのことである。スマートフォンアプリやウェブサービスとして提供されることが多い。', 'A：医療機関のみが管理する記録はEHR（Electronic Health Record）に近い概念。PHRは患者が管理の主体。\nC：保険会社専用のデータベースはPHRの定義に該当しない。\nD：製薬会社の臨床試験データは研究データであり、PHRではない。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-026', '第3章', '電子カルテとAI連携時の注意点', '難', '分析', '電子カルテデータを院内のAI分析システムで利用する場合と、外部クラウドのAIサービスで利用する場合の違いとして最も適切なものはどれか。', 'どちらも全く同じリスクであり、対応に違いはない', '外部クラウド利用の場合は、データの外部送信に伴う第三者提供の可能性や委託先管理の観点から追加の検討が必要', '院内システムの方がセキュリティリスクが高い', '外部クラウドの方が常に安全である', 'D', '院内システムでのAI利用は、データが医療機関の管理下に留まる。一方、外部クラウドのAIサービスを利用する場合は、データが外部に送信されるため、個人情報の第三者提供に該当する可能性、委託先としてのクラウド事業者の管理、データの保存場所（国内/海外）などの追加的な検討が必要となる。', 'A：院内と外部では、データの管理主体やリスクが異なるため、対応も異なる。\nC：院内システムが必ずしもリスクが高いわけではなく、適切な管理がされていれば外部より安全な場合もある。\nD：外部クラウドが常に安全とは限らず、契約内容や事業者の体制によって異なる。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-027', '第3章', '次世代医療基盤法', '標準', '適用', '次世代医療基盤法に基づいて患者の医療情報が認定匿名加工医療情報作成事業者に提供される場合、患者の権利として認められているものはどれか。', '医療情報の提供を拒否（オプトアウト）する権利', '認定事業者の経営に参加する権利', '匿名加工された研究成果の報酬を受け取る権利', '認定事業者を自由に選択する権利', 'A', '次世代医療基盤法では、患者（本人）は医療情報の認定事業者への提供を拒否（オプトアウト）する権利が保障されている。医療機関から患者に対して事前に通知が行われ、患者が提供を望まない場合は申し出ることで、自身の情報が提供されないようにすることができる。', 'B：認定事業者の経営参加は法律で保障された患者の権利ではない。\nC：研究成果の報酬を受け取る制度は次世代医療基盤法には規定されていない。\nD：認定事業者の選択は医療機関側の判断であり、患者が選択するものではない。', '次世代医療基盤法／内閣府'),
('Q3-028', '第3章', 'クラウドサービス利用の注意点', '易', '記憶（知識）', 'クラウドサービスの形態として、アプリケーションソフトウェアをインターネット経由で提供するものを何と呼ぶか。', 'IaaS（Infrastructure as a Service）', 'PaaS（Platform as a Service）', 'SaaS（Software as a Service）', 'DaaS（Desktop as a Service）', 'C', 'SaaS（Software as a Service）は、アプリケーションソフトウェアをインターネット経由で提供するクラウドサービスの形態である。ユーザーはソフトウェアをインストールせずにブラウザ等からアクセスして利用できる。医療分野ではクラウド型電子カルテやAIサービスなどがSaaSとして提供されている。', 'A：IaaSはサーバーやストレージなどのインフラを提供するサービス。\nB：PaaSはアプリケーション開発のためのプラットフォームを提供するサービス。\nD：DaaSは仮想デスクトップ環境を提供するサービス。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-029', '第3章', 'インシデント対応', '標準', '理解', '個人情報保護法に基づき、個人情報の漏洩等が発生した場合に個人情報保護委員会への報告が義務付けられる要件はどれか。', '軽微な漏洩であっても全て報告が必要', '要配慮個人情報の漏洩、1000人超の漏洩、不正アクセスによる漏洩などの場合', '従業員100人以上の事業者のみに報告義務がある', '報告は全て任意であり義務はない', 'B', '2022年施行の改正個人情報保護法により、①要配慮個人情報の漏洩、②財産的被害が生じるおそれのある漏洩、③不正アクセスによる漏洩、④1000人を超える漏洩のいずれかに該当する場合、個人情報保護委員会への報告と本人への通知が義務化された。医療機関では病歴等の要配慮個人情報を扱うため、漏洩時は報告義務が生じやすい。', 'A：すべての漏洩に報告義務があるわけではなく、一定の要件に該当する場合に限られる。\nC：事業者の規模に関わらず、要件に該当すれば報告義務が生じる。\nD：一定の要件を満たす漏洩は報告が義務であり、任意ではない。', '個人情報保護法／個人情報保護委員会'),
('Q3-030', '第3章', '生成AIサービスへのデータ入力リスク', '易', '記憶（知識）', '医療従事者が患者情報を生成AIサービスに入力することで発生し得るリスクとして適切でないものはどれか。', '入力データがAIの学習に使用される可能性', '入力データがAI事業者のサーバーに保存される可能性', 'AIの回答精度が100%になる可能性', '入力データが第三者に漏洩する可能性', 'C', '患者情報を生成AIに入力することのリスクとして、データの学習利用、サーバーへの保存、漏洩などがある。しかし、「AIの回答精度が100%になる」ことはリスクではなく、また現実的にも100%の精度は達成されない。むしろハルシネーションにより誤った回答が生成されるリスクがある。', 'A：入力データがAIモデルの学習に利用されるリスクは実際に存在する。利用規約の確認が必要。\nB：入力データがサーバーに保存されるリスクは存在し、データの保管場所・期間の確認が必要。\nD：セキュリティ対策が不十分な場合、第三者への漏洩リスクが存在する。', 'AI事業者ガイドライン（第1.1版）／医療情報システムの安全管理に関するガイドライン 第6.0版'),
('Q3-031', '第3章', '医療機関におけるサイバーセキュリティ', '易', '記憶（知識）', '医療機関がサイバーセキュリティ対策として策定すべき計画はどれか。', 'BCP（事業継続計画）', 'DPC（診断群分類）', 'ICT（情報通信技術）', 'QOL（生活の質）', 'A', 'BCP（Business Continuity Plan：事業継続計画）は、サイバー攻撃や災害などの緊急事態が発生した際に、事業（医療機関では診療）を継続または早期復旧するための計画である。ランサムウェア攻撃などでシステムが停止した場合の対応手順、代替手段などを事前に策定しておくことが重要。', 'B：DPCは入院医療費の包括評価制度であり、セキュリティ対策とは無関係。\nC：ICTは情報通信技術の総称であり、具体的な計画の名称ではない。\nD：QOLは生活の質を表す指標であり、セキュリティ対策とは無関係。', '医療情報システムの安全管理に関するガイドライン 第6.0版（厚生労働省）'),
('Q3-032', '第3章', '個人情報保護法の基本原則', '標準', '理解', '個人情報保護法における「安全管理措置」として医療機関が講じるべき措置に含まれないものはどれか。', '組織的安全管理措置（体制整備、規程策定）', '人的安全管理措置（従業者の教育・監督）', '物理的安全管理措置（入退室管理、機器の盗難防止）', '経営的安全管理措置（株主への報告）', 'D', '個人情報保護法が求める安全管理措置は、①組織的安全管理措置、②人的安全管理措置、③物理的安全管理措置、④技術的安全管理措置の4つに分類される。「経営的安全管理措置」や「株主への報告」は法律で求められる安全管理措置のカテゴリには含まれない。', 'A：組織的安全管理措置は、責任体制の整備や規程の策定など、安全管理措置の一つ。\nB：人的安全管理措置は、従業者の教育・訓練など、安全管理措置の一つ。\nC：物理的安全管理措置は、入退室管理や機器の施錠など、安全管理措置の一つ。', '個人情報保護法／医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-033', '第3章', 'データの越境移転', '難', '評価', '医療機関がグローバルに展開するクラウド型生成AIサービスを利用する際、データの越境移転に関して最も適切な対応はどれか。', '海外にサーバーがあっても、日本語でサービスが提供されていれば問題ない', 'サービス提供者のデータ取扱いポリシー、サーバー所在地、当該国の法制度を確認し、必要に応じて対策を講じる', '越境移転は禁止されているため、すべての海外サービスは利用できない', '従業員が海外出張中にアクセスすることは越境移転に該当しない', 'B', 'グローバルなクラウドサービスを利用する際は、サービス提供者のデータ取扱いポリシー（学習利用の有無、保存期間など）、サーバーの物理的所在地、当該国の法制度（政府によるデータアクセスの可能性など）を確認することが重要。確認の上、契約による保護措置や本人同意の取得など適切な対策を講じる必要がある。', 'A：言語に関わらず、データの物理的な保管場所が重要。日本語サービスでもサーバーは海外の場合がある。\nC：越境移転は禁止されているわけではなく、適切な措置を講じれば可能。\nD：従業員のアクセス場所よりも、データが保管・処理される場所が越境移転の判断基準。', '個人情報保護法 第28条／医療情報システムの安全管理に関するガイドライン 第6.0版'),
('Q3-034', '第3章', '医療情報の定義と範囲', '標準', '分析', '以下の情報のうち、個人情報保護法上の「個人情報」に該当するものはどれか。', '特定の個人を識別できない統計データ', '患者ID、氏名、診療日が記載されたレセプトデータ', '病院全体の年間手術件数', '医薬品の一般的な副作用情報', 'B', '個人情報とは、生存する個人に関する情報であって、氏名、生年月日その他の記述等により特定の個人を識別できるものをいう。患者ID、氏名、診療日が記載されたレセプトデータは特定の患者を識別できるため、個人情報に該当する。さらに診療内容を含むため要配慮個人情報にも該当する。', 'A：個人を識別できない統計データは個人情報に該当しない。\nC：病院全体の手術件数は集計情報であり、特定の個人を識別できないため個人情報ではない。\nD：医薬品の一般的な副作用情報は特定の個人に関する情報ではないため個人情報ではない。', '個人情報保護法 第2条'),
('Q3-035', '第3章', '3省2ガイドライン', '標準', '理解', '3省2ガイドラインにおいて、クラウドサービスを提供するベンダー（事業者）に求められる事項として最も適切なものはどれか。', '医師免許の取得', 'サービスのセキュリティ対策、運用管理体制、障害対応などの安全管理措置', '医療機関の経営への参画', '患者への直接的な医療サービスの提供', 'D', '3省2ガイドラインのうち、総務省・経済産業省の「医療情報を取り扱う情報システム・サービスの提供事業者における安全管理ガイドライン」は、クラウドサービス等を提供するベンダーに対して、セキュリティ対策、運用管理体制、障害時の対応、データのバックアップなどの安全管理措置を求めている。', 'A：ITベンダーに医師免許は不要。医療行為を行うわけではない。\nC：医療機関の経営はベンダーの役割ではない。\nD：患者への医療サービス提供は医療機関の役割であり、ベンダーの役割ではない。', '医療情報を取り扱う情報システム・サービスの提供事業者における安全管理ガイドライン（総務省・経産省）'),
('Q3-036', '第3章', 'データ越境移転', '標準', '理解', '医療データの国外移転（越境移転）に関する説明として、最も適切なものはどれか。', '個人データを外国にある第三者に提供する場合、本人の同意は不要である', '外国にある第三者への提供には、原則として本人の同意が必要であり、移転先国の個人情報保護制度等について情報提供が求められる', 'EU域内への医療データ移転は、GDPRの規定により日本からは一切禁止されている', 'クラウドサービスを利用する場合、サーバーが国外にあっても越境移転には該当しない', 'B', '個人情報保護法第28条では、外国にある第三者への個人データ提供には原則として本人の同意が必要とされています。また、2022年の法改正により、本人同意取得時には移転先国の個人情報保護制度や移転先が講ずる措置等について情報提供することが義務付けられました。医療データは要配慮個人情報を含むことが多く、越境移転には特に慎重な対応が求められます。', 'A: 外国にある第三者への提供には原則として本人同意が必要であり、不要ではありません。C: 日本はEUから十分性認定を受けており、GDPRの下でEU域内へのデータ移転は認められています。D: クラウドサービスのサーバーが国外にある場合、その利用形態によっては越境移転に該当する可能性があります。', '個人情報保護法第28条・個人情報保護委員会ガイドライン'),
('Q3-037', '第3章', 'インシデント対応', '難', '分析', '医療機関で患者の個人データが漏えいした可能性がある場合の対応として、適切でないものはどれか。', '漏えい等の事態を知った後、速やかに事実関係の調査と原因究明を行う', '要配慮個人情報の漏えいが発生した場合、個人情報保護委員会への報告が義務付けられている', '漏えい等の報告は、事態の全容が判明してから行えばよいため、調査完了まで報告を保留する', '本人への通知は、本人の権利利益を保護するために必要な範囲で行う', 'C', '個人情報保護法では、漏えい等が発生した場合の報告は「速報」と「確報」の2段階で行うことが求められています。速報は事態を知った日から概ね3〜5日以内に、その時点で把握している事項を報告します。調査完了を待って報告を保留することは不適切であり、迅速な対応が求められます。', 'A: 漏えい等の事態を知った後、速やかに事実関係の調査と原因究明を行うことは適切な対応です。B: 要配慮個人情報（医療情報を含む）の漏えいは、個人情報保護委員会への報告義務の対象です。D: 本人への通知は、本人が権利利益の侵害に対処できるよう、必要な範囲で行うことが適切です。', '個人情報保護法第26条・個人情報保護委員会「漏えい等の対応とお知らせの実務」'),
('Q3-038', '第3章', '電子カルテとAI連携', '標準', '適用', '電子カルテシステムと生成AIを連携させる際のデータ取り扱いについて、最も適切なものはどれか。', '生成AIへの入力データは学習に使用されないことが保証されていれば、患者の同意なく診療情報を入力してよい', '電子カルテから生成AIに送信するデータは、目的に必要な最小限の情報に限定し、可能な限り匿名化・仮名化を検討する', '院内ネットワーク内であれば、電子カルテと生成AIの連携にセキュリティ対策は不要である', '生成AIの出力結果は常に正確であるため、そのまま電子カルテに記録してよい', 'B', '電子カルテと生成AIを連携させる際は、データ最小化の原則に従い、目的達成に必要な最小限の情報のみを入力することが重要です。また、個人が特定されないよう匿名化や仮名化の措置を検討することで、漏えい時のリスクを軽減できます。医療情報システムの安全管理ガイドラインでも、外部サービスとの連携時には適切なセキュリティ対策が求められています。', 'A: 学習に使用されない場合でも、外部サービスへの診療情報の送信には適切な法的根拠や患者への説明が必要です。C: 院内ネットワークであっても、生成AIとの連携には適切なセキュリティ対策（アクセス制御、暗号化等）が必要です。D: 生成AIの出力にはハルシネーション（誤情報生成）のリスクがあり、必ず医療従事者が内容を確認してから記録すべきです。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-039', '第3章', 'クラウドサービス', '易', '記憶（知識）', '医療機関がクラウドサービスを利用して医療情報を取り扱う際に参照すべきガイドラインとして、最も適切なものはどれか。', '医療情報システムの安全管理に関するガイドライン', '医薬品の臨床試験の実施の基準に関する省令（GCP省令）', '医療広告ガイドライン', '医療法施行規則', 'A', '医療機関がクラウドサービスを利用して医療情報を取り扱う際は、「医療情報システムの安全管理に関するガイドライン」を参照する必要があります。このガイドラインでは、外部のクラウドサービスを利用する際の責任分界、セキュリティ要件、事業者選定の考え方などが示されています。', 'B: GCP省令は医薬品の臨床試験に関する基準であり、クラウドサービス利用とは直接関係しません。C: 医療広告ガイドラインは医療機関の広告に関する規制であり、情報システムの安全管理とは目的が異なります。D: 医療法施行規則は医療法の施行に関する詳細規定であり、クラウドサービスの利用指針ではありません。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-040', '第3章', '生成AIへのデータ入力リスク', '標準', '理解', '医療従事者が業務で汎用の生成AIサービス（ChatGPT等）を利用する際のリスクに関する説明として、適切でないものはどれか。', '入力したデータがAIの学習データとして利用される可能性がある', '入力内容がサービス提供事業者のサーバーに送信・保存される', '患者の氏名や病名を入力すると、個人情報の外部提供に該当する可能性がある', '有料プランを契約すれば、入力データの漏えいリスクは完全に排除される', 'D', '有料プランでは学習への利用をオプトアウトできるサービスもありますが、それによって漏えいリスクが「完全に排除」されるわけではありません。サーバーへのデータ送信、不正アクセス、サービス提供事業者側のセキュリティインシデント等のリスクは依然として存在します。医療情報を外部の生成AIサービスに入力する際は、これらのリスクを十分に理解した上で慎重に判断する必要があります。', 'A: 多くの汎用生成AIサービスでは、デフォルト設定で入力データが学習に利用される可能性があり、適切なリスク説明です。B: 生成AIサービスを利用すると、入力内容はサービス提供事業者のサーバーに送信されるため、適切なリスク説明です。C: 患者の氏名や病名等の個人情報を入力すると、外部サービスへの個人情報の提供に該当する可能性があります。', '医療情報システムの安全管理に関するガイドライン第6.0版・各生成AIサービス利用規約'),
('Q3-041', '第3章', '個人情報保護法の基本原則', '易', '記憶（知識）', '個人情報保護法における「利用目的の特定」の原則に関する説明として、最も適切なものはどれか。', '個人情報の利用目的は、できる限り特定しなければならない', '利用目的は社内で決定すればよく、本人への通知は任意である', '一度特定した利用目的は、いかなる場合も変更することができない', '利用目的の特定は、要配慮個人情報にのみ適用される義務である', 'A', '個人情報保護法第17条では、個人情報取扱事業者は個人情報を取り扱うにあたって、その利用目的をできる限り特定しなければならないと定められています。「医療サービスの提供」のような抽象的な記載ではなく、具体的にどのような目的で利用するかを明確にする必要があります。', 'B: 利用目的は本人に通知または公表することが義務付けられており（法第21条）、任意ではありません。C: 利用目的の変更は、変更前の利用目的と関連性を有すると合理的に認められる範囲内で可能です（法第17条第2項）。D: 利用目的の特定は、要配慮個人情報だけでなく、すべての個人情報に適用される原則です。', '個人情報保護法第17条・第21条'),
('Q3-042', '第3章', 'アクセス制御', '標準', '適用', '病院の医療情報システムにおけるアクセス制御の実装例として、最も適切なものはどれか。', 'すべての医療従事者が全患者の診療記録にアクセスできるよう設定する', '業務上必要な範囲でのみアクセス権限を付与し、職種や担当に応じたロール設定を行う', 'パスワードは覚えやすさを優先し、部署で共通のものを使用する', '緊急時に備えて、管理者権限を多数の職員に付与しておく', 'B', '医療情報システムの安全管理ガイドラインでは、「最小権限の原則」に基づき、業務上必要な範囲でのみアクセス権限を付与することが求められています。職種や担当患者に応じたロールベースアクセス制御（RBAC）を実装することで、不必要な情報へのアクセスを防ぎ、患者のプライバシーを保護します。', 'A: 全医療従事者が全患者の記録にアクセスできる設定は、最小権限の原則に反し、不正アクセスや漏えいのリスクを高めます。C: 共通パスワードの使用は、個人の識別・認証ができず、不正行為の追跡も困難になるため不適切です。D: 管理者権限の広範な付与は、セキュリティリスクを増大させるため、必要最小限の人員に限定すべきです。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-043', '第3章', '仮名加工情報', '難', '分析', '医療機関が保有する診療データを院内での研究目的で二次利用する場合、仮名加工情報として取り扱うことの利点として、適切でないものはどれか。', '利用目的の変更が可能となり、当初想定していなかった研究テーマにも活用できる', '漏えい等が発生した場合の個人情報保護委員会への報告義務が免除される', '本人からの開示請求等への対応義務が適用除外となる', '第三者提供が自由に行えるようになり、他の研究機関とのデータ共有が容易になる', 'D', '仮名加工情報は、原則として第三者提供が禁止されています（法第41条第6項）。仮名加工情報は「他の情報と照合しない限り特定の個人を識別できない」状態であり、提供先で他の情報と照合されると個人が特定される恐れがあるためです。院内利用には適していますが、外部への提供が目的であれば匿名加工情報の作成を検討すべきです。', 'A: 仮名加工情報は利用目的の変更が認められており、院内での新たな研究目的への活用が可能です。これは仮名加工情報の利点です。B: 仮名加工情報は漏えい等報告の対象外とされており、報告義務が免除されます。C: 仮名加工情報には本人からの開示請求等への対応義務が適用除外となります。', '個人情報保護法第41条・第42条'),
('Q3-044', '第3章', '3省2ガイドライン', '易', '理解', '医療情報の取り扱いに関する「3省2ガイドライン」において、医療機関等が遵守すべきガイドラインの発行元として、正しいものはどれか。', '厚生労働省', '経済産業省', '総務省', '文部科学省', 'A', '3省2ガイドラインは、厚生労働省・経済産業省・総務省の3省が発行する2つのガイドラインの総称です。このうち医療機関等が遵守すべきものは、厚生労働省が発行する「医療情報システムの安全管理に関するガイドライン」です。一方、医療情報を扱うシステム事業者向けには、経済産業省・総務省が共同で発行するガイドラインがあります。', 'B: 経済産業省は総務省とともに事業者向けガイドラインを発行していますが、医療機関向けガイドラインの発行元ではありません。C: 総務省も事業者向けガイドラインを経済産業省と共同で発行していますが、医療機関向けではありません。D: 文部科学省は3省2ガイドラインの発行元には含まれていません。', '3省2ガイドライン（厚生労働省・経済産業省・総務省）'),
('Q3-045', '第3章', 'サイバーセキュリティ', '標準', '理解', '医療機関のサイバーセキュリティ対策において、「多層防御」の考え方として最も適切なものはどれか。', '最も強固な1つの防御策に集中して投資し、それが破られなければ安全が保たれる', '複数の異なるセキュリティ対策を組み合わせ、1つの対策が突破されても他の対策で防御する', '外部からの攻撃のみを想定し、ファイアウォールの強化に特化する', 'セキュリティ対策はコストがかかるため、被害発生後の対応に重点を置く', 'B', '多層防御（Defense in Depth）とは、単一のセキュリティ対策に依存せず、ネットワーク、エンドポイント、アプリケーション、データなど複数のレイヤーで異なる防御策を講じる考え方です。1つの防御層が突破されても、次の層で攻撃を阻止できる可能性があり、医療情報システムの安全管理ガイドラインでもこの考え方が推奨されています。', 'A: 単一の防御策に依存すると、それが破られた場合に全ての情報が危険にさらされるため、多層防御の考え方とは異なります。C: 外部攻撃だけでなく、内部不正やヒューマンエラーも考慮した総合的な対策が必要です。D: 予防的対策を軽視し事後対応に重点を置くことは、被害拡大のリスクが高く不適切です。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-046', '第3章', '要配慮個人情報', '標準', '適用', '医療機関において、要配慮個人情報の取得が本人の同意なく認められる場合として、最も適切なものはどれか。', 'マーケティング目的で患者の健康状態を分析する場合', '患者が意識不明で同意できない緊急時に、生命保護のため必要な医療情報を取得する場合', '医療機関の経営効率化のためにデータを活用する場合', '研究機関から依頼があり、学術研究に協力する場合', 'B', '個人情報保護法第20条第2項では、要配慮個人情報の取得には原則として本人の同意が必要ですが、例外として「人の生命、身体又は財産の保護のために必要がある場合であって、本人の同意を得ることが困難であるとき」が挙げられています。患者が意識不明の緊急時に必要な医療情報を取得する場合がこれに該当します。', 'A: マーケティング目的での健康情報の取得は、法令上の例外事由に該当せず、本人同意が必要です。C: 経営効率化は事業者側の都合であり、同意不要の例外事由には該当しません。D: 学術研究目的は一定の例外が認められますが、単に研究機関からの依頼があるだけでは不十分で、要件を満たす必要があります。', '個人情報保護法第20条第2項'),
('Q3-047', '第3章', '医療情報システムの安全管理ガイドライン', '易', '記憶（知識）', '「医療情報システムの安全管理に関するガイドライン第6.0版」の構成として、正しいものはどれか。', '本編のみの単一構成である', '概説編、経営管理編、企画管理編、システム運用編の4編構成である', '技術編と法律編の2編構成である', '基礎編、応用編、実践編の3編構成である', 'B', '医療情報システムの安全管理に関するガイドライン第6.0版は、概説編、経営管理編、企画管理編、システム運用編の4編で構成されています。これは、医療機関等の規模や役割に応じて必要な部分を参照しやすくするための構成であり、経営層向け、システム管理者向け、運用担当者向けなど対象読者を意識した編成となっています。', 'A: 第6.0版は単一構成ではなく、4編構成で改定されました。C: 技術編と法律編という2編構成ではありません。D: 基礎編、応用編、実践編の3編構成ではなく、4編構成です。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-048', '第3章', '第三者提供', '難', '評価', '医療機関が患者の個人データを第三者に提供する場面において、本人同意が不要となる「オプトアウト」による提供が認められないものはどれか。', '患者の住所情報', '患者の氏名と電話番号', '診療記録に含まれる病歴情報', '患者のメールアドレス', 'C', '個人情報保護法第27条第2項のオプトアウトによる第三者提供は、要配慮個人情報には適用されません。診療記録に含まれる病歴情報は要配慮個人情報に該当するため、オプトアウトによる第三者提供は認められず、必ず本人の同意が必要です。2017年の法改正でこの制限が明確化されました。', 'A: 住所情報は要配慮個人情報に該当しないため、所定の手続きを経ればオプトアウトによる第三者提供が可能です。B: 氏名と電話番号は要配慮個人情報に該当しないため、オプトアウトの対象となり得ます。D: メールアドレスも要配慮個人情報には該当しないため、オプトアウトによる提供が認められます。', '個人情報保護法第27条第2項'),
('Q3-049', '第3章', '匿名加工情報', '標準', '理解', '医療データから匿名加工情報を作成する際の加工方法として、適切でないものはどれか。', '患者の氏名を削除する', '生年月日を年代（10歳刻み）に変換する', '希少疾患の病名をそのまま残す', '住所を都道府県レベルに一般化する', 'C', '匿名加工情報の作成では、特定の個人を識別できないように加工することが求められます。希少疾患の病名は、その疾患の患者数が非常に少ないため、他の情報と組み合わせると個人が特定される可能性が高くなります。そのため、希少疾患名をそのまま残すことは適切な加工とはいえず、一般化や削除などの措置が必要です。', 'A: 氏名の削除は匿名加工の基本的な措置であり、適切です。B: 生年月日を年代に変換して一般化することは、個人特定のリスクを下げる適切な加工方法です。D: 住所を都道府県レベルに一般化することは、詳細な住所による特定を防ぐ適切な加工です。', '個人情報保護法第43条・個人情報保護委員会「匿名加工情報の適正な加工」'),
('Q3-050', '第3章', '生成AIへのデータ入力リスク', '易', '記憶（知識）', '医療従事者が生成AIに患者情報を入力する際に最も注意すべき点として、適切なものはどれか。', '生成AIへの入力内容は完全に秘匿されるため、特に注意は不要である', '有料版を使用すれば患者の実名を入力しても問題ない', '入力データが外部サーバーに送信されることを認識し、個人を特定できる情報の入力を避ける', '医療専門の生成AIであれば、どのような患者情報も安全に入力できる', 'C', '生成AIサービスを利用する際、入力したデータは外部のサーバーに送信されます。そのため、患者の氏名、生年月日、住所など個人を特定できる情報の入力は避けるべきです。仮に学習に使用されない設定であっても、通信経路やサーバー上での情報漏えいリスクは存在します。医療情報システムの安全管理ガイドラインでもこの点の注意が求められています。', 'A: 生成AIへの入力内容は外部サーバーに送信されるため、完全に秘匿されるわけではありません。B: 有料版であっても患者の実名等の入力は個人情報保護の観点から不適切です。D: 医療専門の生成AIであっても、外部サービスである以上、個人を特定できる情報の入力には注意が必要です。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-051', '第3章', '電子カルテとAI連携', '難', '分析', '電子カルテに蓄積された診療データを生成AIで分析し、診療支援に活用する際の課題として、最も重要度が高いものはどれか。', '電子カルテのユーザーインターフェースが生成AIに対応していないこと', '生成AIの出力が常に最新の医学知見に基づいているとは限らないこと', '電子カルテのデータ形式が病院ごとに異なり、標準化されていないこと', '患者データの外部送信に伴う個人情報保護とセキュリティの確保', 'D', '電子カルテのデータを生成AIで分析する際、最も重要な課題は患者の個人情報保護とセキュリティの確保です。診療データには要配慮個人情報が含まれており、外部のAIサービスへの送信は個人情報の第三者提供や越境移転に該当する可能性があります。法令遵守とセキュリティ確保なしには、そもそもAI活用を進めることができません。', 'A: UIの対応は技術的課題ですが、個人情報保護ほど根本的な障壁ではありません。B: 医学知見の最新性も重要な課題ですが、まず法的・倫理的な基盤が整っていることが前提です。C: データ形式の標準化は運用上の課題ですが、セキュリティと個人情報保護が優先されます。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-052', '第3章', 'クラウドサービス', '標準', '理解', '医療機関がクラウドサービスを利用する際の「責任分界」に関する説明として、最も適切なものはどれか。', 'クラウド事業者が全ての責任を負うため、医療機関は責任を負わない', '医療機関とクラウド事業者の間で、それぞれが責任を負う範囲を明確に定める必要がある', '医療機関が全ての責任を負うため、クラウド事業者との契約内容は重要ではない', '責任分界は法律で一律に定められており、個別の契約は不要である', 'B', 'クラウドサービス利用においては、医療機関とクラウド事業者の間で責任分界点を明確にすることが重要です。医療情報システムの安全管理ガイドラインでは、どの範囲までが事業者の責任で、どこからが医療機関の責任かを契約等で明確化することを求めています。SaaS、PaaS、IaaSなどサービス形態によって責任範囲が異なります。', 'A: クラウド事業者が全責任を負うわけではなく、医療機関にも管理監督責任等があります。C: 契約内容は責任範囲を決定する重要な要素であり、軽視すべきではありません。D: 責任分界は法律で一律に定められているわけではなく、サービス形態や契約内容によって異なります。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-053', '第3章', 'インシデント対応', '易', '記憶（知識）', '個人情報保護法において、個人データの漏えい等が発生した場合に個人情報保護委員会への報告が義務付けられる事態として、該当しないものはどれか。', '要配慮個人情報が漏えいした場合', '不正アクセスにより個人データが漏えいした場合', '財産的被害が生じるおそれがある個人データが漏えいした場合', '社内でのみ閲覧可能な従業員名簿が誤って社内の別部署に送信された場合', 'D', '個人情報保護委員会への報告が義務付けられるのは、(1)要配慮個人情報の漏えい、(2)不正アクセス等による漏えい、(3)財産的被害のおそれがある漏えい、(4)1,000人超の大規模漏えいの場合です。社内の別部署への誤送信は「漏えい」には該当しますが、上記の報告義務要件に該当しなければ報告義務はありません。', 'A: 要配慮個人情報（病歴等）の漏えいは報告義務の対象です。B: 不正アクセスによる漏えいは報告義務の対象です。C: クレジットカード情報等、財産的被害のおそれがある個人データの漏えいは報告義務の対象です。', '個人情報保護法第26条・個人情報保護委員会規則'),
('Q3-054', '第3章', '個人情報保護法の基本原則', '標準', '適用', '医療機関の受付で、患者から「自分の診療記録を見せてほしい」と請求があった場合の対応として、最も適切なものはどれか。', '診療記録は医療機関の所有物であるため、患者への開示は認められない', '所定の手続きに従い、原則として患者本人に対して保有個人データを開示する', '開示請求には弁護士を通す必要があると説明する', '医師の判断で開示の可否を決めるため、医師に相談するよう伝える', 'B', '個人情報保護法第33条では、本人から保有個人データの開示請求があった場合、事業者は原則として開示しなければならないと定められています。医療機関においても、患者本人からの開示請求に対しては、所定の手続き（本人確認、手数料等）に従い、診療記録を開示することが求められます。', 'A: 診療記録に含まれる個人データは本人に開示請求権があり、医療機関の所有物であることを理由に拒否することはできません。C: 開示請求に弁護士を通す必要はなく、患者本人が直接請求できます。D: 開示は法的義務であり、医師の裁量で可否を決められるものではありません（例外事由に該当する場合を除く）。', '個人情報保護法第33条'),
('Q3-055', '第3章', 'データ越境移転', '難', '評価', '日本の医療機関が海外のクラウドサービスを利用して患者データを保管する場合、個人情報保護の観点から最も重要な確認事項はどれか。', 'クラウドサービスの利用料金が適正かどうか', 'サーバー設置国の個人情報保護制度と、日本の法制度との整合性', 'クラウドサービスの利用者数が十分に多いかどうか', 'クラウドサービスのユーザーインターフェースが日本語に対応しているか', 'B', '海外のクラウドサービス利用時は、データの越境移転に関する規制を考慮する必要があります。サーバー設置国の個人情報保護制度が日本と同等の水準にあるか、または適切な契約等により個人データの適正な取り扱いが確保されているかを確認することが重要です。EUの十分性認定を受けている国への移転か、そうでない場合は追加的な保護措置が必要です。', 'A: 利用料金は経営上の考慮事項ですが、個人情報保護の観点からは最重要ではありません。C: 利用者数は信頼性の一指標にはなりますが、法的な個人情報保護の確認が優先されます。D: 日本語対応は利便性の問題であり、個人情報保護の観点からは重要ではありません。', '個人情報保護法第28条・医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-056', '第3章', 'アクセス制御', '易', '理解', '医療情報システムにおける「認証」と「認可」の違いとして、最も適切なものはどれか。', '認証は利用者の身元を確認すること、認可はその利用者にどの操作を許可するかを決めること', '認証と認可は同じ意味であり、区別する必要はない', '認可は利用者の身元を確認すること、認証はその利用者にどの操作を許可するかを決めること', '認証は管理者が行い、認可は一般ユーザーが行う手続きである', 'A', '認証（Authentication）とは、利用者が本人であることを確認するプロセスです（例：ID・パスワードの入力、生体認証）。認可（Authorization）とは、認証された利用者に対して、どのリソースにアクセスできるか、どの操作が許可されるかを決定するプロセスです。医療情報システムでは両方の仕組みが必要であり、区別して理解することが重要です。', 'B: 認証と認可は異なる概念であり、それぞれ別の目的を持つセキュリティ機能です。C: 認証と認可の説明が逆になっています。D: 認証・認可はシステムが実施するプロセスであり、管理者と一般ユーザーの役割分担とは関係しません。', '医療情報システムの安全管理に関するガイドライン第6.0版'),
('Q3-057', '第3章', 'サイバーセキュリティ', '標準', '適用', '医療機関でランサムウェア攻撃を受け、電子カルテシステムが使用不能になった場合の対応として、最も適切なものはどれか。', '身代金を支払えばデータが復旧するため、速やかに支払いに応じる', '感染拡大を防ぐためネットワークから隔離し、バックアップからの復旧を試みる', '業務を継続するため、感染した端末をそのまま使い続ける', 'セキュリティ事故は外部に知られると信用を失うため、公表せずに対処する', 'C', 'ランサムウェア攻撃を受けた場合、まず感染拡大を防ぐために感染端末やシステムをネットワークから隔離することが重要です。その後、事前に取得していたバックアップからシステムを復旧します。身代金の支払いはデータ復旧を保証せず、犯罪者を助長するため推奨されません。', 'A: 身代金を支払ってもデータが復旧する保証はなく、支払いは犯罪を助長するため推奨されません。C: 感染端末をそのまま使い続けると、感染が拡大し被害が拡大する危険があります。D: サイバー攻撃は関係機関への報告義務がある場合があり、隠蔽は不適切です。', '医療情報システムの安全管理に関するガイドライン第6.0版・厚生労働省サイバーセキュリティ対策'),
('Q3-058', '第3章', '第三者提供', '易', '記憶（知識）', '医療機関から他の医療機関への患者の診療情報提供について、第三者提供の同意が不要となる場合として、最も適切なものはどれか。', '患者の希望により紹介状を発行して別の医療機関に情報提供する場合', '製薬会社からの依頼で患者情報を提供する場合', '保険会社からの照会に応じて患者情報を提供する場合', '医療機関の研究実績を示すため学会で症例発表を行う場合', 'A', '患者本人の希望により紹介状を発行する場合は、本人の意思に基づく情報提供であり、本人の同意があるものとして扱われます。医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンスでも、患者への医療提供に必要な場合の情報提供は適切に行うことが示されています。', 'B: 製薬会社への患者情報提供は、患者本人の同意または法令上の根拠が必要です。C: 保険会社からの照会への対応は、本人同意なしには原則として応じられません。D: 学会での症例発表は、本人が特定されないよう匿名化するか、本人の同意を得る必要があります。', '医療・介護関係事業者における個人情報の適切な取扱いのためのガイダンス'),
('Q3-059', '第3章', '仮名加工情報', '標準', '理解', '仮名加工情報と匿名加工情報の違いに関する説明として、最も適切なものはどれか。', '仮名加工情報は院内での利用に適しており、匿名加工情報は第三者提供が可能である', '仮名加工情報と匿名加工情報は、いずれも第三者提供が自由に認められている', '匿名加工情報は院内利用のみ認められ、仮名加工情報は第三者提供が可能である', '両者に法的な違いはなく、どちらを作成しても同じ効果が得られる', 'A', '仮名加工情報は、他の情報と照合しない限り特定の個人を識別できないように加工したもので、原則として第三者提供が禁止されていますが、院内での分析・研究には活用できます。一方、匿名加工情報は特定の個人を識別できないように加工したもので、一定の手続きを経れば第三者提供が可能です。用途に応じて使い分けることが重要です。', 'B: 仮名加工情報は原則として第三者提供が禁止されており、両者とも自由に提供できるわけではありません。C: 説明が逆です。匿名加工情報が第三者提供可能、仮名加工情報は院内利用向けです。D: 両者は法的な取り扱いが異なり、目的に応じた選択が必要です。', '個人情報保護法第41条・第43条'),
('Q3-060', '第3章', '3省2ガイドライン', '難', '分析', '医療機関が新規にAI搭載の診療支援システムを導入する際、3省2ガイドラインに基づいて確認すべき事項として、最も重要度が高いものはどれか。', 'システムベンダーの従業員数と企業規模', 'システムのユーザーインターフェースのデザイン性', 'システム事業者が適切なセキュリティ対策と管理体制を備えているか', 'システムの導入費用と年間保守費用の妥当性', 'C', '3省2ガイドラインでは、医療情報を扱うシステム事業者に対して、適切なセキュリティ対策と管理体制を求めています。医療機関が新システムを導入する際は、事業者がこれらのガイドラインに準拠した対策を講じているかを確認することが重要です。これは患者の個人情報を守り、安全な医療サービスを提供するための基盤となります。', 'A: 企業規模は信頼性の一指標にはなりますが、セキュリティ対策の実施状況の方が重要です。B: UIのデザイン性は使いやすさに影響しますが、情報セキュリティの観点からは優先度が低いです。D: 費用の妥当性は経営判断として重要ですが、ガイドライン遵守の観点からはセキュリティが優先されます。', '3省2ガイドライン（厚生労働省・経済産業省・総務省）'),
('Q4-001', '第4章', '薬機法とAI', '易', '記憶（知識）', 'AIを搭載した医療機器が「医薬品、医療機器等の品質、有効性及び安全性の確保等に関する法律（薬機法）」の規制対象となるのは、どのような場合か。', 'AIの学習に医療データを使用した場合', '診断や治療の支援など、医療機器としての目的で使用される場合', '医療従事者がAIを使用する場合', 'AIの開発に医療専門家が関与した場合', 'B', '薬機法では、医療機器は「人の疾病の診断、治療若しくは予防に使用されること、又は人の身体の構造若しくは機能に影響を及ぼすことが目的とされている機械器具等」と定義されています。AIを搭載した製品も、診断や治療の支援など医療機器としての目的で使用される場合は薬機法の規制対象となります。', 'A: 学習データに医療データを使用しただけでは、医療機器としての規制対象にはなりません。C: 使用者が医療従事者であることは規制対象の判断基準ではありません。D: 開発に医療専門家が関与したことは規制対象の判断基準ではありません。', '医薬品、医療機器等の品質、有効性及び安全性の確保等に関する法律（薬機法）'),
('Q4-002', '第4章', 'AI事業者ガイドライン', '易', '記憶（知識）', '「AI事業者ガイドライン」の発行元として、正しいものはどれか。', '厚生労働省', '経済産業省・総務省', '文部科学省', 'デジタル庁', 'B', 'AI事業者ガイドライン（第1.1版）は、経済産業省と総務省が共同で策定・公表しています。このガイドラインは、AI開発者、AI提供者、AI利用者それぞれが遵守すべき事項を定めており、医療分野を含む幅広い産業分野でのAI活用を対象としています。', 'A: 厚生労働省は医療情報システムの安全管理ガイドラインを発行していますが、AI事業者ガイドラインの発行元ではありません。C: 文部科学省はAI事業者ガイドラインの発行元ではありません。D: デジタル庁もAI事業者ガイドラインの発行元ではありません。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-003', '第4章', 'HAIPガイドライン', '標準', '理解', '「保健医療分野AI開発加速コンソーシアム」が取りまとめた議論の整理（HAIPガイドライン）の目的として、最も適切なものはどれか。', 'AI医療機器の薬事承認プロセスを簡略化すること', '保健医療分野におけるAI開発・利活用の促進と、安全性・信頼性の確保を両立すること', '外国製AIの日本市場への参入を制限すること', 'AI開発を大企業のみに限定すること', 'B', 'HAIPガイドライン（保健医療分野AI開発加速コンソーシアムの議論の整理）は、保健医療分野におけるAI開発・利活用を促進しつつ、安全性や信頼性を確保するための考え方を示しています。開発から運用までの各段階での留意事項が整理されており、AI技術の社会実装を適切に進めることを目的としています。', 'A: HAIPガイドラインは薬事承認プロセスの簡略化を目的としたものではありません。C: 外国製AIの制限は目的ではなく、国内外問わずAI活用の適正化を図るものです。D: 開発主体の制限は目的ではなく、幅広い主体によるAI開発を想定しています。', '保健医療分野AI開発加速コンソーシアム 議論の整理（厚生労働省）'),
('Q4-004', '第4章', '医療機器規制', '標準', '理解', '医療機器のクラス分類において、AIを搭載した画像診断支援ソフトウェアが該当する可能性が高いクラスはどれか。', 'クラスI（一般医療機器）', 'クラスII（管理医療機器）', 'クラスIII（高度管理医療機器）', '医療機器には該当しない', 'B', 'AI搭載の画像診断支援ソフトウェアは、診断を補助する機能を持つため、多くの場合クラスII（管理医療機器）に分類されます。ただし、診断の最終決定を行うものや、生命に直接影響する可能性が高いものはクラスIII以上になる場合もあります。分類は製品の機能やリスクに応じて個別に判断されます。', 'A: クラスIは聴診器など人体へのリスクが極めて低い機器であり、診断支援AIは通常該当しません。C: クラスIIIは人工心臓弁など高リスク機器であり、一般的な画像診断支援ソフトは該当しないことが多いです。D: 診断支援を目的としたソフトウェアは医療機器に該当します。', '薬機法・医療機器クラス分類'),
('Q4-005', '第4章', 'SaMD', '易', '記憶（知識）', '「SaMD」の正式名称と意味として、正しいものはどれか。', 'Software as a Medical Device：医療機器としてのソフトウェア', 'System and Medical Database：システムと医療データベース', 'Safety and Medical Design：安全性と医療設計', 'Standard of Medical Diagnosis：医療診断の基準', 'A', 'SaMDは「Software as a Medical Device」の略で、「医療機器としてのソフトウェア」を意味します。ハードウェア医療機器の一部として動作するのではなく、それ自体が医療機器として機能するソフトウェアを指します。AI搭載の診断支援システムなどがこれに該当し、薬機法の規制対象となります。', 'B: SaMDは「System and Medical Database」の略ではありません。C: SaMDは「Safety and Medical Design」の略ではありません。D: SaMDは「Standard of Medical Diagnosis」の略ではありません。', '厚生労働省・国際医療機器規制当局フォーラム（IMDRF）'),
('Q4-006', '第4章', 'AI事業者ガイドライン', '標準', '理解', 'AI事業者ガイドラインにおいて定義されている「AI利用者」として、最も適切なものはどれか。', 'AIシステムを開発する技術者', 'AIシステムを他者に提供するサービス事業者', 'AIシステムを業務等に活用する事業者や個人', 'AIの学習データを提供する研究機関', 'C', 'AI事業者ガイドラインでは、AI関連の主体として「AI開発者」「AI提供者」「AI利用者」を定義しています。AI利用者とは、AI提供者から提供されたAIシステム・サービスを業務や日常生活で活用する事業者や個人を指します。医療機関がAI搭載の診断支援システムを使用する場合、医療機関はAI利用者に該当します。', 'A: AIシステムを開発する技術者は「AI開発者」に該当します。B: AIシステムを他者に提供する事業者は「AI提供者」に該当します。D: 学習データの提供者は、AI開発に関与していますが「AI利用者」の定義には該当しません。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-007', '第4章', '医師法とAI', '難', '分析', 'AIによる診断支援と医師法の関係について、最も適切な説明はどれか。', 'AIが高い精度で診断を行えば、医師の確認なしに診断結果を患者に伝えてよい', 'AIの診断結果を参考にしつつ、最終的な診断は医師が責任を持って行う必要がある', 'AIによる診断は医師法の適用外であり、法的規制を受けない', 'AIが診断を行う場合、医師の存在は不要となる', 'D', '医師法では、医業（医行為）は医師が行うものと定められています。AIは診断支援ツールとして活用できますが、最終的な診断・治療の判断は医師が責任を持って行う必要があります。AIの出力はあくまで参考情報であり、医師の判断を代替するものではありません。', 'A: AIの精度に関わらず、診断の最終判断と患者への説明は医師が行う必要があります。C: 医療目的でAIを使用する場合も医師法の枠組みの中で運用される必要があります。D: 診断・治療には医師の関与が必要であり、AIが医師を不要にするものではありません。', '医師法・厚生労働省通知'),
('Q4-008', '第4章', 'PMDA', '易', '記憶（知識）', '医療機器としてのAI製品の承認審査を行う日本の機関として、正しいものはどれか。', '厚生労働省のみ', '独立行政法人医薬品医療機器総合機構（PMDA）', '経済産業省', '日本医師会', 'B', '独立行政法人医薬品医療機器総合機構（PMDA: Pharmaceuticals and Medical Devices Agency）は、医薬品・医療機器の承認審査、安全対策、健康被害救済を行う機関です。AI搭載の医療機器（SaMD等）の承認審査もPMDAが実施します。', 'A: 厚生労働省は薬事行政の監督を行いますが、実際の承認審査はPMDAが実施します。C: 経済産業省はAI政策に関与していますが、医療機器の承認審査は行いません。D: 日本医師会は医師の職能団体であり、医療機器の承認審査機関ではありません。', '独立行政法人医薬品医療機器総合機構（PMDA）'),
('Q4-009', '第4章', '改正薬機法', '標準', '理解', '2020年の薬機法改正で導入された「変更計画（IDATEN）」の目的として、最も適切なものはどれか。', 'AI医療機器の開発を禁止すること', 'AI医療機器の性能向上に伴う変更手続きを迅速化すること', 'すべてのAI医療機器の承認を不要にすること', '外国製AI医療機器の輸入を制限すること', 'C', '2020年の薬機法改正で導入された変更計画（IDATEN: Improvement Design within Approval for Timely Evaluation and Notice）は、AIや機械学習を用いた医療機器の継続的な改良を想定した制度です。承認時に変更計画を提出・承認を受けておくことで、計画に沿った変更は迅速な手続きで市場展開できるようになりました。', 'A: IDATENはAI医療機器の開発を促進するための制度であり、禁止を目的としていません。C: 承認制度は維持されており、すべての承認を不要にするものではありません。D: 輸入制限を目的とした制度ではありません。', '改正薬機法・厚生労働省'),
('Q4-010', '第4章', 'AI事業者ガイドライン', '標準', '適用', 'AI事業者ガイドラインで求められる「透明性」の確保の例として、最も適切なものはどれか。', 'AIのアルゴリズムをすべて一般公開すること', 'AIの判断根拠や限界について、利用者が理解できる形で説明すること', 'AIの開発コストを公開すること', 'AIの開発に関わった従業員名を公開すること', 'C', 'AI事業者ガイドラインでは、透明性の確保として、AIシステムの判断根拠や技術的限界について、利用者が理解し適切に利用できるよう説明することを求めています。必ずしもアルゴリズムの全公開を求めるものではなく、知的財産保護と透明性確保のバランスを考慮した対応が求められます。', 'A: アルゴリズムの全公開は必須ではなく、知的財産保護との両立が認められています。C: 開発コストの公開は透明性確保の主眼ではありません。D: 従業員名の公開は透明性確保の要件には含まれていません。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-011', '第4章', 'HAIPガイドライン', '難', '分析', 'HAIPガイドラインで示されている「AIの品質管理」において、特に重要とされる観点として、適切でないものはどれか。', '学習データの品質確保と偏りの排除', 'AIの判断精度の継続的なモニタリング', 'AIの判断が100%正確であることの保証', 'AIシステムの更新・改善プロセスの管理', 'C', 'AIの品質管理において、100%の正確性を保証することは現実的ではありません。HAIPガイドラインでは、AIの限界を認識した上で、継続的な品質モニタリング、学習データの品質管理、更新プロセスの適切な管理などを通じて品質を確保することを求めています。完璧な精度の保証ではなく、リスクを許容可能な範囲に管理することが重要です。', 'A: 学習データの品質確保と偏りの排除は、AI品質管理の重要な要素です。B: AIの判断精度を継続的にモニタリングすることは品質管理の核心的要素です。D: AIシステムの更新・改善プロセスを適切に管理することは品質維持に不可欠です。', '保健医療分野AI開発加速コンソーシアム 議論の整理（厚生労働省）'),
('Q4-012', '第4章', '臨床研究法', '標準', '理解', '医療AIを用いた臨床研究を実施する際に遵守すべき法令として、最も関連性が高いものはどれか。', '製造物責任法（PL法）', '臨床研究法', '消費者契約法', '不正競争防止法', 'D', '医療AIを用いた臨床研究を実施する場合、臨床研究法の適用を受ける可能性があります。臨床研究法は、特定臨床研究について研究計画の届出、倫理審査委員会による審査、インフォームド・コンセントの取得などを義務付けています。医薬品等の承認申請を目的とする場合は、医薬品の臨床試験の実施の基準（GCP省令）に従う必要があります。', 'A: 製造物責任法は製品の欠陥による被害の責任を定めるものであり、臨床研究の実施要件ではありません。C: 消費者契約法は消費者と事業者間の契約に関する法律であり、臨床研究とは直接関係しません。D: 不正競争防止法は営業秘密の保護等を目的としており、臨床研究の規制法ではありません。', '臨床研究法・厚生労働省'),
('Q4-013', '第4章', '薬機法とAI', '易', '記憶（知識）', '薬機法における医療機器プログラムの定義として、最も適切なものはどれか。', '医療機関で使用されるすべてのソフトウェア', '医療機器としての目的性を有するプログラム', '医療従事者が開発したプログラム', '有料で販売されるプログラム', 'B', '薬機法では、医療機器プログラムを「医療機器のうちプログラムであるもの」と定義しています。つまり、疾病の診断、治療、予防等の医療機器としての目的性を有するプログラムが該当します。単に医療機関で使用されるというだけでは医療機器プログラムには該当しません。', 'A: 医療機関で使用されるすべてのソフトウェアが医療機器プログラムに該当するわけではありません。事務用ソフト等は該当しません。C: 開発者が誰かは医療機器プログラムの定義には関係しません。D: 有料か無料かは医療機器プログラムの定義には関係しません。', '医薬品、医療機器等の品質、有効性及び安全性の確保等に関する法律（薬機法）'),
('Q4-014', '第4章', '国際規格', '標準', '理解', '医療機器の品質マネジメントシステムに関する国際規格として、正しいものはどれか。', 'ISO 9001', 'ISO 13485', 'ISO 27001', 'ISO 14001', 'B', 'ISO 13485は医療機器の品質マネジメントシステム（QMS）に関する国際規格です。医療機器メーカーが製品の設計・開発から製造、市販後管理まで一貫した品質管理を行うための要求事項を定めています。AI搭載医療機器の開発・製造においてもこの規格への適合が求められます。', 'A: ISO 9001は一般的な品質マネジメントシステムの国際規格であり、医療機器専用ではありません。C: ISO 27001は情報セキュリティマネジメントシステムの国際規格です。D: ISO 14001は環境マネジメントシステムの国際規格です。', 'ISO 13485・医療機器品質マネジメントシステム'),
('Q4-015', '第4章', '医療広告規制', '易', '適用', 'AI診断支援システムを導入した医療機関の広告について、医療広告ガイドラインに照らして適切でないものはどれか。', '承認を受けた医療機器を使用していることを記載する', '「AI診断により100%の精度で疾患を発見」と表示する', 'AIによる診断支援を行っていることを事実として記載する', 'AIシステムの製品名を記載する', 'B', '医療広告ガイドラインでは、誇大広告や虚偽広告が禁止されています。「100%の精度」という表現は、AIの技術的限界を無視した虚偽・誇大な表現であり、患者に誤解を与える不適切な広告です。AIシステムを導入していることや、承認を受けた医療機器であること等の事実を記載することは認められます。', 'A: 承認を受けた医療機器の使用という事実を記載することは適切です。C: AIによる診断支援を行っているという事実の記載は適切です。D: AIシステムの製品名を事実として記載することは問題ありません。', '医療広告ガイドライン（厚生労働省）'),
('Q4-016', '第4章', '医療機器規制', '難', '評価', 'AI医療機器の市販後安全対策として、最も重要な取り組みはどれか。', '販売価格を一定に維持すること', '不具合情報の収集・分析と必要な改善措置の実施', '製品パッケージのデザインを定期的に変更すること', '競合製品との性能比較を公表すること', 'B', 'AI医療機器を含む医療機器の市販後安全対策では、使用中に発生した不具合や有害事象の情報を収集・分析し、必要に応じて改善措置（リコール、使用上の注意の改訂等）を実施することが最も重要です。薬機法でも製造販売業者に市販後の安全管理が義務付けられています。', 'A: 販売価格の維持は市販後安全対策の本質的な要素ではありません。C: パッケージデザインの変更は安全対策とは関係ありません。D: 競合製品との比較公表は市販後安全対策の主要な取り組みではありません。', '薬機法・医療機器の製造販売後安全管理基準（GVP）'),
('Q4-017', '第4章', 'AI事業者ガイドライン', '標準', '理解', 'AI事業者ガイドラインで示されている「人間中心のAI」の考え方として、最も適切なものはどれか。', 'AIが全ての意思決定を行い、人間は結果を受け入れるだけでよい', 'AIは人間の能力を補完・拡張するものであり、最終的な判断は人間が行う', 'AIの開発は人間が行うが、運用は完全に自動化される', 'AIの利用を特定の専門家に限定する', 'B', 'AI事業者ガイドラインでは、AIは人間の能力を補完・拡張するツールであり、人間の尊厳や自律を損なうものであってはならないとしています。特に重要な意思決定においては、人間が最終的な判断を行い、責任を持つ「Human-in-the-loop」の考え方が重視されています。', 'A: AIに全ての意思決定を委ねることは人間中心の考え方に反します。C: 運用の完全自動化は人間の関与を排除するものであり、人間中心の考え方とは異なります。D: AIの利用を専門家に限定することは、人間中心のAIの考え方の本質ではありません。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-018', '第4章', '製造物責任', '標準', '適用', 'AI搭載医療機器の欠陥により患者に被害が生じた場合、製造物責任法（PL法）の適用に関する説明として、最も適切なものはどれか。', 'ソフトウェアは製造物に該当しないため、PL法は適用されない', 'AIの判断ミスは製造物の欠陥に該当しないため、PL法は適用されない', 'AI搭載医療機器の欠陥による被害には、PL法が適用される可能性がある', 'PL法は医療機器には適用されない', 'C', '製造物責任法では「製造物」を「製造又は加工された動産」と定義しており、ソフトウェア単体は該当しませんが、ソフトウェアが組み込まれた医療機器全体としては製造物に該当します。AI搭載医療機器に欠陥があり、それにより患者に被害が生じた場合、PL法に基づく責任が問われる可能性があります。', 'A: ソフトウェア単体ではなく、AI搭載医療機器という「製造物」として考えた場合、PL法の適用対象となり得ます。B: AIの設計・開発上の問題が欠陥と認定される可能性はあります。D: 医療機器もPL法の適用対象となります。', '製造物責任法（PL法）'),
('Q4-019', '第4章', 'HAIPガイドライン', '易', '記憶（知識）', 'HAIPガイドラインにおいて、AI開発のライフサイクル全体を通じて重要とされる原則として、適切でないものはどれか。', '安全性の確保', '透明性の確保', '開発コストの最小化', '公平性の確保', 'C', 'HAIPガイドラインでは、保健医療分野のAI開発において、安全性、透明性、公平性、説明責任などを重要な原則として示しています。開発コストの最小化は経営上の課題ではありますが、ガイドラインで重視される原則としては挙げられていません。品質や安全性を犠牲にしてコストを最小化することは適切ではありません。', 'A: 安全性の確保はAI開発において最も重要な原則の一つです。B: AIの判断根拠等を説明できる透明性の確保は重要原則です。D: 学習データやAIの判断における公平性の確保は重要な原則です。', '保健医療分野AI開発加速コンソーシアム 議論の整理（厚生労働省）'),
('Q4-020', '第4章', 'EU AI規制', '難', '分析', 'EU AI法（AI Act）における医療AIの位置づけとして、最も適切なものはどれか。', '医療AIは低リスクに分類され、特別な規制は適用されない', '医療AIは高リスクAIに分類される可能性が高く、厳格な要件が課される', 'EU AI法は医療分野には適用されない', '医療AIはEU域外で開発されたものには適用されない', 'A', 'EU AI法（AI Act）では、AIシステムをリスクレベルに応じて分類しており、医療機器として使用されるAIは「高リスクAI」に分類される可能性が高いです。高リスクAIには、リスク管理システムの構築、データガバナンス、技術文書の作成、透明性確保など厳格な要件が課されます。日本企業がEU市場で医療AIを展開する際にも考慮が必要です。', 'A: 医療AIは健康や安全に影響を与える可能性があるため、低リスクではなく高リスクに分類される可能性が高いです。C: EU AI法は医療分野を含む幅広い分野に適用されます。D: EU市場でサービスを提供する場合、開発地域に関わらずEU AI法が適用されます。', 'EU AI法（AI Act）'),
('Q4-021', '第4章', '医師法とAI', '易', '記憶（知識）', '医師法第17条で規定されている「医業」について、正しい説明はどれか。', '医業とは医師のみが行うことを許される業務をいう', '医業とは病院での業務全般をいう', '医業とは健康に関するアドバイス全般をいう', '医業とは製薬会社での業務をいう', 'A', '医師法第17条では「医師でなければ、医業をなしてはならない」と規定されています。医業とは、医行為（医師の医学的判断及び技術をもってするのでなければ人体に危害を及ぼし、又は危害を及ぼすおそれのある行為）を反復継続の意思をもって行うことをいいます。AIによる診断支援は医師の判断を補助するものであり、AI自体が医業を行うことはできません。', 'B: 病院での業務全般（事務、清掃等）が医業に該当するわけではありません。C: 健康アドバイス全般が医業に該当するわけではありません。D: 製薬会社での業務は医業の定義には該当しません。', '医師法第17条'),
('Q4-022', '第4章', 'SaMD', '標準', '適用', '以下のソフトウェアのうち、SaMD（医療機器プログラム）に該当する可能性が最も高いものはどれか。', '患者の予約管理を行うシステム', 'CT画像から肺がんの疑いがある部位を検出し、医師に提示するソフトウェア', '医療従事者のシフト管理を行うソフトウェア', '病院の会計処理を行うシステム', 'B', 'SaMD（Software as a Medical Device）は、医療機器としての目的性を有するソフトウェアを指します。CT画像から疾患の疑いがある部位を検出し医師に提示するソフトウェアは、診断支援という医療機器としての目的を持つため、SaMDに該当する可能性が高いです。一方、予約管理や会計処理などの事務的なソフトウェアはSaMDには該当しません。', 'A: 予約管理システムは医療行為の支援ではなく、事務処理を目的としているためSaMDには該当しません。C: シフト管理ソフトウェアは労務管理目的であり、SaMDには該当しません。D: 会計処理システムは医療行為とは直接関係のない事務システムです。', '厚生労働省・IMDRF SaMD定義'),
('Q4-023', '第4章', 'AI事業者ガイドライン', '難', '評価', 'AI事業者ガイドラインにおいて、AI開発者が果たすべき責任として、最も重要度が高いものはどれか。', '開発したAIの市場シェアを最大化すること', 'AIの安全性・信頼性を確保し、適切な情報提供を行うこと', '開発期間を最短にすること', '競合他社より先に製品をリリースすること', 'D', 'AI事業者ガイドラインでは、AI開発者の責任として、AIの安全性・信頼性の確保、リスクの特定と対策、AI提供者・利用者への適切な情報提供などが挙げられています。市場シェアや開発スピードよりも、安全で信頼できるAIを開発し、その特性や限界について適切に伝えることが最も重要な責任とされています。', 'A: 市場シェアの最大化は経営目標であり、ガイドラインが求める責任の本質ではありません。C: 開発期間の短縮は効率性の観点では重要ですが、安全性を犠牲にすべきではありません。D: 競合より先にリリースすることよりも、安全性・信頼性の確保が優先されます。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-024', '第4章', '薬機法とAI', '標準', '理解', 'AI医療機器の承認審査において、「学習データの品質」が重視される理由として、最も適切なものはどれか。', '学習データの量が多いほど承認が早く得られるため', '学習データの偏りや品質がAIの判断精度や公平性に直接影響するため', '学習データのコストを把握するため', '学習データの著作権を確認するため', 'C', 'AI医療機器の性能は学習データに大きく依存します。学習データに偏り（特定の性別、年齢、人種等への偏り）があると、AIの判断精度や公平性に影響し、特定の患者群に対して不正確な結果を出す可能性があります。そのため承認審査では、学習データの品質、代表性、偏りの有無などが重要な評価項目となります。', 'A: 学習データの量だけで承認が早まるわけではなく、質が重要です。C: コストの把握は審査の主目的ではありません。D: 著作権の確認は法的には重要ですが、品質評価の主眼ではありません。', 'PMDA・AI医療機器審査指針'),
('Q4-025', '第4章', '国際規格', '易', '記憶（知識）', '医療分野におけるAIの国際的な規制動向に関する説明として、正しいものはどれか。', 'AI医療機器の規制は日本独自のものであり、国際的な動向はない', 'WHO、FDA、EUなど国際機関や各国規制当局でAI医療機器に関する議論が進んでいる', 'AI医療機器に関する国際規格は存在しない', '各国でAI医療機器の規制を撤廃する動きが主流である', 'B', 'AI医療機器に関しては、世界保健機関（WHO）、米国FDA、欧州連合（EU）、国際医療機器規制当局フォーラム（IMDRF）など、国際機関や各国規制当局で活発に議論が行われています。日本も国際的な動向を踏まえながら、AI医療機器の規制環境整備を進めています。', 'A: AI医療機器の規制は日本独自ではなく、世界各国で議論・整備が進んでいます。C: ISO/IECなどでAI関連の国際規格の策定が進んでいます。D: 規制撤廃ではなく、適切な規制の整備が各国で進められています。', 'WHO・FDA・EU各種ガイダンス'),
('Q4-026', '第4章', 'HAIPガイドライン', '標準', '適用', 'HAIPガイドラインに基づき、医療AIの開発段階で実施すべき取り組みとして、最も適切なものはどれか。', '開発完了後に一度だけ性能検証を行う', '開発の各段階で適切な検証を行い、文書化して記録を残す', '検証は医療現場に導入後に初めて行う', '検証は開発者の自己申告のみで十分である', 'B', 'HAIPガイドラインでは、医療AI開発においてライフサイクル全体を通じた品質管理を求めています。設計、開発、検証、バリデーションの各段階で適切なテストを実施し、その結果を文書化して記録を残すことが重要です。これにより、問題発生時のトレーサビリティが確保され、継続的な改善が可能になります。', 'A: 開発完了後の一度の検証だけでは不十分であり、各段階での継続的な検証が必要です。C: 医療現場への導入前に十分な検証を行う必要があります。D: 自己申告のみでは客観性が担保されず、適切な検証とはいえません。', '保健医療分野AI開発加速コンソーシアム 議論の整理（厚生労働省）'),
('Q4-027', '第4章', '医療機器規制', '難', '分析', '「学習型」AI医療機器の規制における特有の課題として、最も適切なものはどれか。', '承認時点と市販後で性能が変化しないため、従来の規制で十分対応できる', '市販後も学習により性能が変化する可能性があるため、継続的な監視と適切な変更管理が必要', '学習型AIは承認の対象外とすべきである', '学習型AIは一度承認されれば、以後の変更は自由に行える', 'B', '学習型AI医療機器は、市販後もデータから学習を続けることで性能が変化する可能性があります。これは従来の医療機器にはない特性であり、継続的なモニタリングと、性能変化に対する適切な変更管理（再審査の要否判断等）が課題となります。IDATENなどの制度はこの課題に対応するために導入されました。', 'A: 学習型AIは性能が変化する可能性があるため、従来の規制だけでは対応が難しい面があります。C: 学習型AIも適切な規制のもとで承認の対象となります。D: 承認後の変更には適切な管理が必要であり、自由に行えるわけではありません。', '厚生労働省・PMDA AI医療機器に関する検討'),
('Q4-028', '第4章', 'AI事業者ガイドライン', '易', '理解', 'AI事業者ガイドラインで重視されている「公平性」の確保に関する説明として、最も適切なものはどれか。', 'AIの利用料金を全ての利用者で均一にすること', 'AIが特定の属性（性別、年齢、人種等）によって不当に差別的な判断をしないようにすること', '全てのAI開発者に同額の開発費用を配分すること', 'AIの利用機会を全国民に強制すること', 'B', 'AI事業者ガイドラインにおける「公平性」とは、AIが性別、年齢、人種、障害の有無などの属性によって不当に差別的な判断や出力をしないことを意味します。学習データの偏りや設計上の問題により、特定のグループに不利益が生じないよう配慮することが求められています。医療AIでは特に、全ての患者に対して公平な判断ができることが重要です。', 'A: 利用料金の均一化は公平性の本質的な意味ではありません。C: 開発費用の均等配分は公平性の定義には含まれません。D: AI利用の強制は公平性とは関係ありません。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-029', '第4章', 'PMDA', '標準', '理解', 'PMDAが実施するAI医療機器の審査において評価される項目として、適切でないものはどれか。', 'AIの性能（感度・特異度等）の妥当性', '学習データの品質と代表性', '開発企業の株価', 'リスクマネジメントの適切性', 'D', 'PMDAによるAI医療機器の審査では、AIの性能（感度・特異度など）、学習データの品質・代表性・偏りの有無、リスクマネジメントの適切性、臨床的有用性などが評価されます。開発企業の株価は医療機器としての品質・安全性・有効性とは直接関係がないため、審査項目には含まれません。', 'A: AIの性能評価は審査の重要な項目です。B: 学習データの品質と代表性はAIの信頼性に直結する重要な評価項目です。D: リスクマネジメントの適切性は医療機器審査において必須の評価項目です。', 'PMDA・医療機器審査ガイドライン'),
('Q4-030', '第4章', '改正薬機法', '易', '記憶（知識）', '2019年の薬機法改正で導入された「先駆け審査指定制度」の対象として、AI医療機器は含まれるか。', 'AI医療機器は一切対象にならない', '画期的な医療機器として要件を満たせば対象となり得る', 'AI医療機器は自動的に全て対象となる', '海外製のAI医療機器のみが対象となる', 'D', '先駆け審査指定制度は、世界に先駆けて日本で開発され、画期的な医薬品・医療機器等の審査を優先的に行う制度です。AI医療機器であっても、画期的な有用性が期待され、その他の要件を満たせば、先駆け審査指定の対象となる可能性があります。ただし、AI医療機器であることのみで自動的に対象になるわけではありません。', 'A: 要件を満たせばAI医療機器も対象となり得ます。C: 全てのAI医療機器が自動的に対象になるわけではなく、要件を満たす必要があります。D: 国産・海外製を問わず、要件を満たせば対象となり得ます。', '改正薬機法・先駆け審査指定制度'),
('Q4-031', '第4章', '医師法とAI', '標準', '適用', 'AIを用いた遠隔診療支援に関する法的な考え方として、最も適切なものはどれか。', 'AIが診断を行えば、医師の関与なく遠隔診療が可能である', '遠隔診療においてもAIは補助ツールであり、診断・治療の判断は医師が行う必要がある', '遠隔診療ではAIの使用が禁止されている', 'AIを使用する場合、対面診療の要件が免除される', 'D', '遠隔診療においても、AIはあくまで医師の診断を支援するツールとして位置づけられます。医師法に基づき、診断・治療の最終判断は医師が行う必要があり、AIがそれを代替することはできません。厚生労働省のオンライン診療指針でも、医師の責任のもとで適切に実施することが求められています。', 'A: AIが診断を行っても、医師の関与なく診療を行うことは医師法に違反します。C: 遠隔診療でのAI使用は禁止されておらず、適切に活用することは可能です。D: AIを使用しても対面診療の要件が自動的に免除されるわけではありません。', '医師法・厚生労働省オンライン診療指針'),
('Q4-032', '第4章', 'EU AI規制', '易', '記憶（知識）', 'EU AI法（AI Act）におけるAIシステムのリスク分類として、正しいものはどれか。', '低リスク、高リスクの2段階分類', '禁止、高リスク、限定リスク、最小リスクの4段階分類', '医療用、非医療用の2分類', '国内用、国際用の2分類', 'B', 'EU AI法では、AIシステムを(1)禁止されるAI、(2)高リスクAI、(3)限定リスクAI（透明性義務あり）、(4)最小リスクAIの4段階に分類しています。医療用AIの多くは高リスクに分類され、適合性評価、技術文書作成、リスク管理システム構築などの厳格な要件が課されます。', 'A: EU AI法は2段階ではなく4段階のリスク分類を採用しています。C: 医療用・非医療用という分類基準ではなく、リスクレベルによる分類です。D: 国内・国際という地域による分類ではありません。', 'EU AI法（AI Act）'),
('Q4-033', '第4章', '製造物責任', '難', '分析', 'AI医療機器の製造物責任に関して、開発者・製造者が責任を軽減できる可能性がある主張として、最も適切なものはどれか。', 'AIの判断は予測不能であり、責任を負えないという主張', '製造物を引き渡した時点の科学・技術水準では欠陥を認識できなかったという「開発危険の抗弁」', '利用者が使用許諾に同意したため、全ての責任が利用者に移転するという主張', 'AIは自律的に判断するため、製造者には一切の責任がないという主張', 'B', '製造物責任法第4条では、「開発危険の抗弁」として、製造物を引き渡した時点の科学・技術水準では欠陥を認識することが不可能であった場合、免責される可能性が規定されています。ただし、この抗弁が認められるハードルは高く、AI医療機器においても、開発時点で予見可能なリスクには適切に対処する義務があります。', 'A: AIの予測不能性を理由に責任を回避することは一般的に認められません。C: 使用許諾への同意だけで製造物責任が完全に移転するわけではありません。D: AIの自律性を理由に製造者責任を完全に否定することはできません。', '製造物責任法第4条'),
('Q4-034', '第4章', '臨床研究法', '標準', '理解', '医療AIの臨床評価を行う際に、「人を対象とする生命科学・医学系研究に関する倫理指針」の遵守が求められる場面はどれか。', '既存の匿名化データのみを用いた性能評価研究', '新たに被験者を募集してAIの診断精度を検証する臨床研究', 'AI医療機器の薬事承認申請のための治験', '社内での技術的な性能ベンチマークテスト', 'A', '「人を対象とする生命科学・医学系研究に関する倫理指針」は、人を対象として、傷病の成因及び病態の理解並びに傷病の予防方法並びに医療における診断方法及び治療方法の改善等を目的として実施される研究に適用されます。新たに被験者を募集してAIの診断精度を検証する研究は、この指針の対象となります。', 'A: 既存の匿名化データのみを用いた研究は、指針の適用対象外となる場合があります。C: 薬事承認申請のための治験はGCP省令が適用されます。D: 社内の技術テストは臨床研究には該当しません。', '人を対象とする生命科学・医学系研究に関する倫理指針'),
('Q4-035', '第4章', 'AI事業者ガイドライン', '易', '記憶（知識）', 'AI事業者ガイドラインにおける「説明責任（アカウンタビリティ）」の意味として、最も適切なものはどれか。', 'AIの技術的な仕組みを全て公開すること', 'AIに関する意思決定や行動について、関係者に対して適切に説明できる状態を維持すること', 'AIの利用料金の内訳を開示すること', 'AIの開発者の経歴を公開すること', 'D', 'AI事業者ガイドラインにおける説明責任（アカウンタビリティ）とは、AIに関する意思決定や行動（開発・提供・利用）について、ステークホルダー（利用者、被影響者、規制当局等）に対して適切に説明できる状態を維持することを意味します。これには、AIの目的、機能、限界、リスク対策等の説明が含まれます。', 'A: 技術的な仕組みの全公開は必須ではなく、知的財産保護とのバランスが認められています。C: 料金内訳の開示は説明責任の主要な要素ではありません。D: 開発者の経歴公開は説明責任の定義には含まれません。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-036', '第4章', '薬機法とAI', '標準', '適用', '医療機器プログラムとして承認を取得したAI診断支援ソフトウェアについて、製造販売業者が行うべき市販後対応として、適切でないものはどれか。', '使用成績調査を実施し、実臨床での有効性・安全性を確認する', '不具合報告を収集・分析し、必要に応じて改善措置を講じる', '承認取得後は性能モニタリングを終了し、新製品開発に注力する', '添付文書の内容を最新の知見に基づいて見直す', 'C', '医療機器の製造販売業者には、市販後も継続的な安全管理が義務付けられています。特にAI医療機器は、実臨床での性能が開発時の検証と異なる可能性があるため、継続的な性能モニタリングが重要です。承認取得後に監視を終了することは適切な市販後対応とはいえません。', 'A: 使用成績調査による実臨床での有効性・安全性確認は適切な市販後対応です。B: 不具合報告の収集・分析と改善措置は製造販売業者の義務です。D: 添付文書の見直しは最新の知見を反映するために必要な対応です。', '薬機法・GVP（製造販売後安全管理基準）'),
('Q4-037', '第4章', 'HAIPガイドライン', '難', '評価', 'HAIPガイドラインにおいて、医療AIの「臨床的妥当性」を評価する際に最も重視すべき観点はどれか。', 'AIの処理速度が十分に高速であること', 'AIの判断が実際の臨床現場で医療の質向上に寄与すること', 'AIのユーザーインターフェースが使いやすいこと', 'AIの開発コストが低いこと', 'D', '臨床的妥当性とは、AIの判断が実際の臨床現場において医療の質向上（診断精度の向上、治療成績の改善、医療従事者の負担軽減等）に貢献するかどうかを指します。技術的な性能が高くても、臨床現場で実際に役立たなければ意味がありません。HAIPガイドラインでは、開発から実装までの各段階で臨床的妥当性の検証を求めています。', 'A: 処理速度は重要な要素ですが、臨床的妥当性の最重要観点ではありません。C: UIの使いやすさは実用性に影響しますが、臨床的妥当性の本質ではありません。D: 開発コストは経営上の考慮事項であり、臨床的妥当性とは異なる概念です。', '保健医療分野AI開発加速コンソーシアム 議論の整理（厚生労働省）'),
('Q4-038', '第4章', '国際規格', '易', '記憶（知識）', 'AI・機械学習を活用した医療機器の品質マネジメントに関連する国際規格として、IEC 62304が定めているものはどれか。', '医療機器ソフトウェアのライフサイクルプロセス', '医療機器の電気安全基準', '医療機器の生物学的安全性評価', '医療機器の滅菌プロセス', 'A', 'IEC 62304は「医療機器ソフトウェア−ソフトウェアライフサイクルプロセス」を定めた国際規格です。医療機器に組み込まれるソフトウェア（AI/機械学習を含む）の開発、保守、リスク管理、構成管理などのプロセス要求事項を規定しています。SaMD（医療機器プログラム）の開発においても参照される重要な規格です。', 'B: 電気安全基準はIEC 60601シリーズで規定されています。C: 生物学的安全性評価はISO 10993シリーズで規定されています。D: 滅菌プロセスはISO 11135やISO 11137などで規定されています。', 'IEC 62304（医療機器ソフトウェア−ソフトウェアライフサイクルプロセス）'),
('Q4-039', '第4章', '医療広告規制', '標準', '理解', '医療機関がAI診断支援システムを広告する際の規制に関する説明として、最も適切なものはどれか。', 'AI技術を使用していることは、どのような表現でも自由に広告できる', '未承認のAI機器であっても、効果をうたう広告が認められる', '医療広告ガイドラインに従い、虚偽・誇大な表現を避ける必要がある', 'AI関連の広告は医療広告規制の対象外である', 'C', '医療機関の広告は医療広告ガイドラインの規制を受けます。AI診断支援システムに関する広告も例外ではなく、虚偽広告、誇大広告、比較広告などが禁止されています。「最先端AI」「100%の精度」などの根拠のない表現や、患者に誤解を与える表現は避ける必要があります。', 'A: AI技術の使用に関する広告も医療広告規制の対象であり、自由に表現できるわけではありません。B: 未承認のAI機器の効果をうたう広告は認められません。D: AI関連の広告も医療広告規制の対象に含まれます。', '医療広告ガイドライン（厚生労働省）'),
('Q4-040', '第4章', 'SaMD', '難', '分析', 'AI搭載SaMDの承認審査において、「性能の一般化可能性」が評価される理由として、最も適切なものはどれか。', '開発に使用したデータと異なる条件でも同等の性能が発揮されるか確認するため', '複数の言語に対応しているか確認するため', '様々なハードウェアで動作するか確認するため', '開発者の技術力を評価するため', 'A', 'AI医療機器の性能は、学習に使用したデータの特性に影響されます。開発時のデータと異なる患者集団（年齢層、人種、撮影機器の違い等）に対しても同等の性能が発揮されるかどうか（一般化可能性）は、実臨床での有用性を左右する重要な評価項目です。特定の条件でのみ高性能を示し、他の条件で性能が低下するAIは臨床的に問題があります。', 'B: 言語対応は国際展開の観点では重要ですが、性能の一般化可能性の主眼ではありません。C: ハードウェア互換性は技術的な検証項目ですが、一般化可能性の本質ではありません。D: 開発者の技術力評価は一般化可能性の評価目的ではありません。', 'PMDA・FDA AI/ML医療機器ガイダンス'),
('Q4-041', '第4章', '医師法とAI', '易', '理解', 'AIによる画像診断支援において、医師の役割として最も適切なものはどれか。', 'AIの出力結果をそのまま患者に伝える', 'AIの出力を参考にしつつ、医学的見地から最終判断を行う', 'AIが誤りの可能性を示した場合のみ確認する', 'AIの判断が正しいことを保証する書類を発行する', 'B', 'AIによる画像診断支援は、医師の診断を補助するものです。医師はAIの出力を参考にしつつ、患者の症状、病歴、他の検査結果なども総合的に考慮し、医学的見地から最終的な診断を行う責任があります。AIの出力をそのまま受け入れるのではなく、専門的な判断を加えることが求められます。', 'A: AIの出力をそのまま伝えることは不適切であり、医師の判断を加える必要があります。C: AIの出力に関わらず、医師は常に最終確認を行う必要があります。D: AIの判断の正しさを保証することは医師の役割ではありません。', '医師法・厚生労働省通知'),
('Q4-042', '第4章', 'AI事業者ガイドライン', '標準', '適用', 'AI事業者ガイドラインに基づき、医療機関（AI利用者）が生成AIを業務に導入する際に検討すべき事項として、適切でないものはどれか。', '生成AIの出力内容の正確性を検証する体制の整備', '患者情報を入力する際のリスクと対策の検討', '生成AIの開発元企業の株式を購入すること', '生成AIの利用に関する職員への教育・研修の実施', 'C', 'AI利用者として医療機関が生成AIを導入する際は、出力の正確性検証体制、患者情報入力時のリスク対策、職員教育などを検討することが重要です。一方、AI開発元企業の株式購入は、AI利用者としての責任とは関係がなく、ガイドラインで求められる検討事項には含まれません。', 'A: 生成AIの出力は誤りを含む可能性があるため、正確性検証体制の整備は重要です。B: 患者情報の入力は個人情報保護の観点から重要な検討事項です。D: 職員が適切にAIを利用できるよう教育・研修を実施することは必要です。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-043', '第4章', 'PMDA', '標準', '理解', 'PMDAが提供する「RS（Regulatory Science）戦略相談」をAI医療機器の開発企業が活用するメリットとして、最も適切なものはどれか。', '相談により承認が自動的に得られる', '開発段階で審査の考え方を確認でき、効率的な開発・申請が可能になる', '相談費用が全額補助される', '競合他社の申請内容を知ることができる', 'A', 'RS戦略相談は、医薬品・医療機器等の開発企業がPMDAと開発段階で相談できる制度です。AI医療機器の場合、学習データの要件、性能評価の方法、臨床試験のデザインなどについて事前に確認することで、承認申請に向けた効率的な開発が可能になります。ただし、相談で承認が保証されるわけではありません。', 'A: 相談により承認が自動的に得られるわけではなく、正式な審査が必要です。C: 相談には所定の手数料が必要であり、全額補助されるわけではありません。D: 競合他社の申請内容は機密情報であり、相談で知ることはできません。', 'PMDA・RS戦略相談'),
('Q4-044', '第4章', '製造物責任', '易', '記憶（知識）', '製造物責任法（PL法）における「欠陥」の定義として、正しいものはどれか。', '製造物に含まれるすべての不具合', '製造物が通常有すべき安全性を欠いていること', '製造物の価格が高すぎること', '製造物のデザインが悪いこと', 'B', '製造物責任法第2条第2項では、「欠陥」を「当該製造物の特性、その通常予見される使用形態、その製造業者等が当該製造物を引き渡した時期その他の当該製造物に係る事情を考慮して、当該製造物が通常有すべき安全性を欠いていること」と定義しています。AI医療機器においても、通常有すべき安全性を欠いている場合は欠陥に該当します。', 'A: 全ての不具合が欠陥に該当するわけではなく、安全性に関わるものが対象です。C: 価格の高さは欠陥の定義には含まれません。D: デザインの良し悪しは、安全性に影響しない限り欠陥には該当しません。', '製造物責任法第2条第2項'),
('Q4-045', '第4章', 'HAIPガイドライン', '標準', '適用', 'HAIPガイドラインに基づく医療AI開発において、「外部検証データセット」を使用する目的として、最も適切なものはどれか。', '開発コストを削減するため', '学習データとは独立したデータでAIの性能を客観的に評価するため', 'AIの学習速度を向上させるため', '競合製品との性能比較を行うため', 'A', '外部検証データセットは、AIの学習に使用したデータとは独立したデータであり、これを用いてAIの性能を評価することで、過学習（オーバーフィッティング）の有無や、未知のデータに対する汎化性能を客観的に確認できます。学習データでのみ評価すると性能を過大評価するリスクがあるため、外部検証は重要です。', 'A: 外部検証データセットの使用はコスト削減が目的ではありません。C: 外部検証は学習後の評価に使用するものであり、学習速度の向上とは関係しません。D: 外部検証の主目的は自社AIの性能評価であり、競合比較ではありません。', '保健医療分野AI開発加速コンソーシアム 議論の整理（厚生労働省）'),
('Q4-046', '第4章', '医療機器規制', '難', '評価', 'AI医療機器の「継続的学習（Continuous Learning）」モデルに対する規制上の課題として、最も重要なものはどれか。', 'AIの学習に多大なコンピューティングリソースが必要なこと', '承認時点からAIの性能が変化する可能性があり、変更管理の仕組みが複雑になること', 'AIの学習データを永久に保存する義務があること', '継続的学習モデルは日本では一切認められていないこと', 'B', '継続的学習モデルでは、市販後も新たなデータから学習を続けるため、承認時点と市販後で性能が変化する可能性があります。これは、従来の医療機器規制では想定されていなかった課題であり、どのような変更であれば再承認が必要か、性能劣化をどう検知するかなど、変更管理の仕組みが複雑になります。', 'A: コンピューティングリソースは技術的・経済的課題ですが、規制上の主要課題ではありません。C: 学習データの永久保存義務という規制は存在しません。D: 日本でも継続的学習モデルに対応する規制の整備が進められており、一切認められていないわけではありません。', 'PMDA・FDA AI/ML医療機器ガイダンス'),
('Q4-047', '第4章', 'AI事業者ガイドライン', '易', '記憶（知識）', 'AI事業者ガイドラインで示されている「AI提供者」の役割として、最も適切なものはどれか。', 'AI開発者からAIシステムを調達し、AI利用者に提供する事業者', 'AIの学習データを収集する専門機関', 'AIの規制を監督する政府機関', 'AIを日常生活で使用する一般消費者', 'A', 'AI事業者ガイドラインでは、AI提供者を「AI開発者が開発したAIシステム・サービスを、AI利用者に対して提供する者」と定義しています。AI提供者は、AI開発者とAI利用者の間に位置し、AIシステムの安全な提供、適切な情報提供、サポート体制の整備などの責任を負います。', 'B: 学習データの収集機関はAI提供者の定義には含まれません。C: 規制監督は政府機関の役割であり、AI提供者とは異なります。D: 一般消費者はAI利用者に該当する可能性がありますが、AI提供者ではありません。', 'AI事業者ガイドライン第1.1版（経済産業省・総務省）'),
('Q4-048', '第4章', '薬機法とAI', '標準', '理解', '医療機器プログラムの製造販売に必要な許可として、正しいものはどれか。', '医療機器製造販売業許可のみ', '医薬品製造販売業許可', '医療機器製造販売業許可と、プログラムの内容に応じた製造業登録', '特別な許可は不要', 'C', '医療機器プログラムの製造販売には、医療機器製造販売業許可が必要です。また、プログラムの設計・開発を行う場合は製造業登録も必要となります。ただし、物理的な製造工程がないプログラムの場合、従来の医療機器とは異なる登録区分が適用されることがあります。クラス分類に応じて必要な手続きが異なります。', 'A: 製造販売業許可だけでなく、製造業登録も必要となる場合があります。B: 医療機器プログラムには医薬品の許可ではなく、医療機器の許可が必要です。D: 医療機器として承認・認証を受けるプログラムには許可が必要です。', '薬機法・医療機器製造販売業許可制度'),
('Q4-049', '第4章', '国際規格', '標準', '理解', '医療機器のリスクマネジメントに関する国際規格ISO 14971がAI医療機器に求めることとして、最も適切なものはどれか。', 'AIの全てのリスクを完全に排除すること', 'リスクの特定、評価、コントロールのプロセスを通じて、リスクを許容可能なレベルに管理すること', 'リスクに関する情報を競合他社に共有すること', 'リスクマネジメントは開発完了後に一度だけ実施すること', 'B', 'ISO 14971は医療機器のリスクマネジメントプロセスを規定した国際規格です。全てのリスクを排除することは現実的ではないため、リスクの特定、分析、評価、コントロール（低減）のプロセスを通じて、リスクを許容可能なレベルに管理することを求めています。AI医療機器においても、このフレームワークに基づいたリスクマネジメントが必要です。', 'A: 全てのリスクを完全に排除することは不可能であり、許容可能なレベルへの管理が求められます。C: 競合他社への情報共有は規格の要求事項ではありません。D: リスクマネジメントは開発から市販後まで継続的に実施する必要があります。', 'ISO 14971（医療機器－リスクマネジメントの適用）'),
('Q4-050', '第4章', '臨床研究法', '難', '分析', 'AI医療機器の臨床試験（治験）と臨床研究の違いとして、最も適切なものはどれか。', '治験はGCP省令、臨床研究は臨床研究法に基づき実施されるという規制枠組みの違いがある', '治験は医師のみが実施でき、臨床研究は誰でも実施できる', '治験と臨床研究に法的な違いはない', '治験はAI医療機器では実施できない', 'A', '治験は薬機法に基づく承認申請のために実施される臨床試験であり、GCP省令（医薬品・医療機器の臨床試験の実施基準）に従って実施されます。一方、臨床研究は臨床研究法や倫理指針に基づいて実施されます。規制枠組み、必要な手続き、監督機関などが異なり、目的に応じて適切な枠組みを選択する必要があります。', 'B: 治験も臨床研究も適切な資格と体制のもとで実施され、誰でも自由にできるわけではありません。C: 治験と臨床研究には明確な法的・規制上の違いがあります。D: AI医療機器でも承認申請のための治験は実施可能です。', '薬機法・GCP省令・臨床研究法'),
('Q4-051', '第4章', 'HAIPガイドライン', '易', '理解', 'HAIPガイドラインが対象とする「保健医療分野のAI」の範囲として、最も適切なものはどれか。', '医療機器として承認されたAIのみ', '診断・治療支援から健康管理、創薬支援まで幅広い医療・ヘルスケア分野のAI', '病院の事務処理を行うAIのみ', '外国で開発されたAIのみ', 'D', 'HAIPガイドライン（保健医療分野AI開発加速コンソーシアムの議論の整理）は、診断支援、治療支援、健康管理、介護支援、創薬支援など、幅広い保健医療分野でのAI活用を対象としています。医療機器として承認されたものに限らず、研究開発段階のAIや、医療機器に該当しないヘルスケアアプリなども視野に入れています。', 'A: 承認済み医療機器に限らず、幅広い保健医療分野のAIが対象です。C: 事務処理AIに限定されるものではありません。D: 国内外を問わず、保健医療分野で使用されるAI全般が対象です。', '保健医療分野AI開発加速コンソーシアム 議論の整理（厚生労働省）'),
('Q4-052', '第4章', '医療広告規制', '標準', '適用', '医療機関がホームページでAI診断システムについて記載する場合、医療広告ガイドラインに照らして問題となる可能性がある表現はどれか。', '当院ではAIを活用した画像診断支援システムを導入しています', '導入しているAI診断システムは〇〇社製です', 'AI診断により見落としゼロを実現しました', 'AIシステムは医師の診断を補助する目的で使用しています', 'C', '「見落としゼロ」という表現は、AIの性能を過大に表現した誇大広告に該当する可能性があります。どのようなAIシステムでも100%の精度を保証することは困難であり、このような表現は患者に誤解を与え、医療広告ガイドラインに違反する恐れがあります。事実に基づいた客観的な記載が求められます。', 'A: AI活用の事実を記載することは問題ありません。B: 製品名の記載は事実の記載であり問題ありません。D: AIの使用目的を正確に説明することは適切です。', '医療広告ガイドライン（厚生労働省）'),
('Q4-053', '第4章', 'PMDA', '難', '評価', 'AI医療機器の承認審査においてPMDAが重視する「臨床的意義」の評価として、最も適切なものはどれか。', 'AIの技術的な新規性のみを評価する', 'AIの導入により患者や医療現場にどのようなメリットがもたらされるかを評価する', 'AI開発企業の収益性を評価する', 'AIの開発に要した期間を評価する', 'D', 'AI医療機器の承認審査では、技術的な性能だけでなく、実際の臨床現場でどのような価値をもたらすか（臨床的意義）が重要な評価項目となります。具体的には、診断精度の向上、診断時間の短縮、医師の負担軽減、患者アウトカムの改善など、患者や医療従事者にとってのメリットが評価されます。', 'A: 技術的新規性も考慮されますが、臨床的意義の評価はより広い視点を含みます。C: 企業の収益性は承認審査の評価項目ではありません。D: 開発期間は承認審査で評価される項目ではありません。', 'PMDA・医療機器審査の考え方'),
('Q4-054', '第4章', 'EU AI規制', '標準', '理解', 'EU AI法で「高リスクAI」に分類された医療AIが満たすべき要件として、適切でないものはどれか。', 'リスク管理システムの構築', 'データガバナンスの確保', '透明性と利用者への情報提供', 'EU域外へのデータ持ち出しの完全禁止', 'D', 'EU AI法で高リスクAIに分類されたシステムには、リスク管理システムの構築、データガバナンス（学習データの品質確保）、透明性の確保、人間による監視、技術文書の作成などが要求されます。一方、EU域外へのデータ持ち出しの完全禁止はAI法の要件ではなく、データの越境移転はGDPR等の別の規制で扱われます。', 'A: リスク管理システムの構築は高リスクAIの要件です。B: 学習データの品質や代表性を確保するデータガバナンスは要件です。C: 透明性と利用者への情報提供は高リスクAIに求められます。', 'EU AI法（AI Act）'),
('Q4-055', '第4章', '改正薬機法', '易', '記憶（知識）', '薬機法に基づく医療機器の製造販売後安全管理（GVP）の目的として、最も適切なものはどれか。', '製造販売した医療機器の売上を向上させること', '製造販売した医療機器の安全性を市販後も継続的に確保すること', '新規医療機器の開発を促進すること', '医療機器の価格を適正化すること', 'D', 'GVP（Good Vigilance Practice：製造販売後安全管理基準）は、医療機器が市販された後も、その安全性を継続的に確保するための基準です。製造販売業者は、不具合や有害事象の情報収集・分析、必要な安全対策の実施、規制当局への報告などを行う義務があります。AI医療機器においても、市販後の性能監視や不具合対応が重要です。', 'A: 売上向上はGVPの目的ではありません。C: 新規開発の促進は別の制度の目的です。D: 価格適正化はGVPの範囲外です。', '薬機法・GVP（製造販売後安全管理基準）'),
('Q5-001', '第5章', 'AIバイアス', '易', '記憶（知識）', '医療AIにおける「バイアス」の説明として、最も適切なものはどれか。', 'AIの処理速度が遅くなること', '学習データや設計に起因し、特定の集団に対して不公平な判断をする傾向', 'AIのプログラムにエラーがあること', 'AIの消費電力が大きいこと', 'D', '医療AIにおけるバイアスとは、学習データの偏り（特定の性別・年齢・人種のデータが少ないなど）や、設計上の問題により、特定の集団に対して不公平または不正確な判断をする傾向を指します。例えば、特定の人種の患者データが少ない場合、そのグループに対する診断精度が低下する可能性があります。', 'A: 処理速度の問題はバイアスとは関係ありません。C: プログラムエラー（バグ）とバイアスは異なる概念です。D: 消費電力はバイアスとは無関係です。', 'AI事業者ガイドライン・HAIPガイドライン'),
('Q5-002', '第5章', 'インフォームド・コンセント', '標準', '理解', '医療AIを用いた診療におけるインフォームド・コンセントの説明として、最も適切なものはどれか。', 'AIを使用することについて患者への説明は不要である', 'AIの技術的詳細を全て患者に説明する義務がある', 'AIを診断支援に使用すること、その特性や限界を患者に説明し、理解を得ることが望ましい', 'AIの使用については医師の判断のみで決定でき、患者の同意は不要である', 'C', '医療AIを用いた診療において、患者に対してAIの使用について適切に説明し、理解を得ることがインフォームド・コンセントの観点から重要です。AIの技術的詳細全てを説明する必要はありませんが、AIを使用すること、その判断の特性や限界、最終判断は医師が行うことなどを分かりやすく説明することが望ましいとされています。', 'A: AIの使用について患者への説明は必要であり、省略すべきではありません。B: 技術的詳細の全てを説明する義務はなく、患者が理解できる範囲での説明が求められます。D: 患者の理解と同意を得ることは医療の基本原則です。', '厚生労働省・医療AI利用に関する通知'),
('Q5-003', '第5章', 'ハルシネーション', '易', '記憶（知識）', '生成AIの「ハルシネーション（幻覚）」とは何か。', 'AIが美しい画像を生成すること', 'AIが事実に基づかない誤った情報をあたかも正しいかのように生成すること', 'AIの処理中に画面がちらつくこと', 'AIが大量のデータを高速で処理すること', 'C', 'ハルシネーション（hallucination）とは、生成AIが事実に基づかない情報や存在しない内容を、あたかも正しい事実であるかのように自信を持って出力する現象です。医療分野では、存在しない研究結果や誤った薬剤情報を生成するリスクがあり、生成AIの出力を鵜呑みにせず、必ず検証することが重要です。', 'A: 美しい画像の生成はハルシネーションとは関係ありません。C: 画面のちらつきは技術的な表示の問題であり、ハルシネーションではありません。D: 高速処理はハルシネーションとは関係ありません。', '生成AI利用に関する各種ガイドライン'),
('Q5-004', '第5章', '説明可能性', '標準', '理解', '医療AIの「説明可能性（Explainability）」が重要とされる理由として、最も適切なものはどれか。', 'AIの処理速度を向上させるため', '医師や患者がAIの判断根拠を理解し、信頼性を評価できるようにするため', 'AIの開発コストを削減するため', 'AIのプログラムサイズを小さくするため', 'A', '医療AIの説明可能性とは、AIがなぜその判断に至ったのかを人間が理解できる形で説明できることを指します。これにより、医師はAIの判断の妥当性を評価でき、患者は自身の診療について理解を深められます。ブラックボックス的なAIは信頼構築が難しく、誤判断の発見も困難になります。', 'A: 説明可能性は処理速度とは直接関係しません。C: 開発コスト削減が説明可能性の主目的ではありません。D: プログラムサイズとは関係がありません。', 'AI事業者ガイドライン・HAIPガイドライン'),
('Q5-005', '第5章', '医療AIの責任所在', '難', '分析', 'AIを用いた診断支援において誤診が発生した場合の責任の考え方として、最も適切なものはどれか。', 'AIが判断したことなので、誰も責任を負わない', '全ての責任はAI開発企業が負う', '最終的な診断判断を行った医師に責任があり、AI開発者・提供者にも状況に応じた責任が生じ得る', '患者が自己責任でAI診療を選択したので、患者に責任がある', 'C', 'AIを用いた診断支援において、最終的な診断判断は医師が行うため、医師には注意義務に基づく責任があります。一方、AI自体に欠陥があった場合は、開発者や提供者にも製造物責任や契約上の責任が生じる可能性があります。責任は一者に集中するのではなく、関与した各主体がそれぞれの立場で責任を負う構造になっています。', 'A: AIの判断であっても、関与した人間や組織に責任が生じます。B: 全責任がAI開発企業のみに帰属するわけではありません。D: 患者の自己責任とすることは不適切です。', '厚生労働省・医療AI責任に関する検討'),
('Q5-006', '第5章', '過信と自動化バイアス', '標準', '理解', '医療AIに対する「自動化バイアス」の説明として、最も適切なものはどれか。', 'AIの計算を自動化することでバイアスを排除できること', 'AIの出力を過信し、自分の判断よりもAIの判断を優先してしまう傾向', 'AIを使用すると業務が自動化されて効率が向上すること', 'AIが自動的にバイアスを検出して修正すること', 'B', '自動化バイアス（Automation Bias）とは、人間が自動化されたシステムやAIの出力を過度に信頼し、自分自身の判断や直感よりもAIの判断を優先してしまう心理的傾向です。医療現場では、AIの誤りを見逃したり、AIが示さなかった異常を見落としたりするリスクがあるため、注意が必要です。', 'A: 計算の自動化とバイアス排除は別の概念です。C: 業務効率化は自動化バイアスの定義ではありません。D: AIが自動的にバイアスを修正することとは異なります。', 'HAIPガイドライン・医療AI倫理に関する研究'),
('Q5-007', '第5章', 'プライバシー保護', '易', '記憶（知識）', '医療AIのプライバシーリスクとして、最も適切なものはどれか。', 'AIの処理速度が低下すること', '学習データから個人が特定される可能性や、入力データの漏えいリスク', 'AIの電力消費量が増大すること', 'AIのユーザーインターフェースが複雑になること', 'D', '医療AIのプライバシーリスクには、学習データに含まれる個人情報から患者が特定される可能性（メンバーシップ推論攻撃など）や、AIへの入力データが外部に漏えいするリスクなどがあります。医療データは要配慮個人情報を含むため、これらのリスクへの対策が特に重要です。', 'A: 処理速度の低下はプライバシーリスクではありません。C: 電力消費量はプライバシーとは関係ありません。D: UIの複雑さはプライバシーリスクではありません。', '医療情報システムの安全管理ガイドライン第6.0版'),
('Q5-008', '第5章', '公平性', '標準', '適用', '医療AIの公平性を確保するための取り組みとして、最も適切なものはどれか。', '学習データを特定の病院からのみ収集する', '学習データに多様な患者集団（年齢、性別、人種等）が含まれるようにする', 'AIの判断を常に医師の判断より優先する', 'AIの開発を特定の国の企業に限定する', 'B', '医療AIの公平性を確保するためには、学習データに多様な患者集団が含まれることが重要です。特定の年齢層、性別、人種に偏ったデータで学習すると、それ以外の患者に対して精度が低下するバイアスが生じます。多様なデータを確保し、サブグループごとの性能評価を行うことで公平性を向上させることができます。', 'A: 特定の病院のみからのデータ収集は偏りを生み、公平性を損なう可能性があります。C: AIの判断を常に優先することは公平性確保とは関係ありません。D: 開発国の限定は公平性とは関係がありません。', 'AI事業者ガイドライン・HAIPガイドライン'),
('Q5-009', '第5章', '患者の自律性', '難', '分析', '医療AIの導入が患者の自律性に影響を与える可能性として、最も適切な懸念はどれか。', 'AIにより治療費が増加すること', 'AIの判断が患者の意思決定に過度に影響し、患者自身が選択する余地が狭まる可能性', 'AIにより診療時間が短縮されること', 'AIにより医師の数が減少すること', 'D', '患者の自律性とは、患者が十分な情報を得た上で自らの意思で医療に関する決定を行う権利です。AIの判断が「科学的・客観的」として強調されすぎると、患者が自分の価値観や希望に基づいて選択する余地が狭まる可能性があります。AIはあくまで意思決定支援のツールであり、最終決定権は患者にあることを尊重する必要があります。', 'A: 治療費の増加は自律性への直接的な懸念ではありません。C: 診療時間の短縮は自律性に関する主要な懸念ではありません。D: 医師数の減少は自律性とは別の問題です。', '医療倫理・患者の権利に関する指針'),
('Q5-010', '第5章', 'リスク管理', '易', '理解', '医療AIのリスク管理における「フェイルセーフ」の考え方として、最も適切なものはどれか。', 'AIが故障しても安全側に動作するよう設計すること', 'AIが故障しないよう完璧に設計すること', 'AIが故障したら全ての業務を停止すること', 'AIの故障を隠蔽して業務を継続すること', 'A', 'フェイルセーフとは、システムに故障や異常が発生した場合でも、安全側に動作するよう設計する考え方です。医療AIの場合、AIが正常に動作しない際には人間（医師）に判断を委ねる、警告を出す、安全な状態で停止するなどの設計が求められます。「AIが完璧」という前提ではなく、故障を想定した設計が重要です。', 'B: 完璧に故障しない設計は現実的ではなく、故障を想定した対策が必要です。C: 全業務停止は安全側とは限らず、状況に応じた対応が必要です。D: 故障の隠蔽は危険であり、フェイルセーフの考え方に反します。', '医療情報システムの安全管理ガイドライン第6.0版'),
('Q5-011', '第5章', 'AIバイアス', '標準', '適用', 'AIの皮膚疾患診断システムにおいて、特定の肌の色の患者に対して精度が低下する問題が発生した。この問題の主な原因として、最も可能性が高いものはどれか。', 'AIのプログラムに計算エラーがあった', '学習データに特定の肌の色の患者の画像が少なかった', 'AIの処理速度が遅かった', '撮影カメラの解像度が低かった', 'B', 'AIの精度が特定の集団（この場合は特定の肌の色の患者）に対して低下する問題は、学習データの偏りが主な原因として考えられます。学習データに多様な肌の色の患者画像が十分に含まれていないと、AIはそれらの患者に対する診断パターンを十分に学習できず、精度が低下します。', 'A: 計算エラーであれば全患者に影響が出るはずで、特定集団のみの精度低下とは整合しません。C: 処理速度は診断精度に直接影響しません。D: カメラ解像度の問題であれば、肌の色に関係なく影響が出るはずです。', 'AI公平性に関する研究・事例'),
('Q5-012', '第5章', '医療倫理四原則', '易', '記憶（知識）', '医療倫理の四原則に含まれないものはどれか。', '自律尊重（Autonomy）', '善行（Beneficence）', '効率性（Efficiency）', '公正（Justice）', 'A', '医療倫理の四原則（ビーチャムとチルドレスによる）は、(1)自律尊重（Autonomy）、(2)善行（Beneficence）、(3)無危害（Non-maleficence）、(4)公正（Justice）の4つです。効率性は医療経営上重要な概念ですが、四原則には含まれません。医療AIの導入においても、これらの倫理原則を考慮することが求められます。', 'A: 自律尊重は四原則の一つで、患者の自己決定権を尊重することです。B: 善行は四原則の一つで、患者の最善の利益を追求することです。D: 公正は四原則の一つで、医療資源の公平な分配などを指します。', '医療倫理四原則（ビーチャム・チルドレス）'),
('Q5-013', '第5章', 'ハルシネーション', '標準', '適用', '医療従事者が生成AIを使用して患者向けの説明資料を作成した。ハルシネーションのリスクに対処するために最も適切な対応はどれか。', '生成AIの出力をそのまま患者に渡す', '生成AIの出力を専門知識に基づいて確認・修正してから使用する', '生成AIが作成したことを患者に伝えれば、そのまま使用してよい', '有料版の生成AIを使用すればハルシネーションは発生しない', 'B', '生成AIはハルシネーション（誤情報の生成）のリスクがあるため、出力をそのまま使用することは危険です。特に医療情報は患者の健康に直接影響するため、医療従事者が専門知識に基づいて内容を確認し、必要に応じて修正してから使用することが重要です。', 'A: 確認なしにそのまま渡すことはハルシネーションによる誤情報提供のリスクがあります。C: AIが作成したことを伝えても、内容の正確性は担保されません。D: 有料版でもハルシネーションは発生する可能性があります。', '生成AI利用に関するガイドライン'),
('Q5-014', '第5章', '説明可能性', '難', '分析', 'ディープラーニングを用いた医療AIの「ブラックボックス問題」への対策として、最も適切なものはどれか。', 'AIの使用を完全に禁止する', '説明可能AI（XAI）技術を活用し、AIの判断根拠を可視化する', 'AIの判断を全て医師が追認することで説明責任を果たす', '患者にAIの使用を説明しないことで問題を回避する', 'B', 'ブラックボックス問題とは、ディープラーニングなどの複雑なAIモデルにおいて、なぜその判断に至ったかを人間が理解しにくいことを指します。説明可能AI（XAI: Explainable AI）技術を活用することで、AIがどの特徴に注目して判断したかを可視化し、医師が判断の妥当性を評価できるようになります。', 'A: AIの全面禁止は現実的ではなく、有用なAI技術の活用を妨げます。C: 追認だけでは判断根拠が不明なままで、本質的な解決にはなりません。D: 説明をしないことは問題の回避ではなく、倫理的に不適切です。', 'HAIPガイドライン・XAI技術'),
('Q5-015', '第5章', 'リスク管理', '標準', '理解', '医療AIの導入におけるリスクアセスメントの目的として、最も適切なものはどれか。', 'AIの導入コストを最小化すること', 'AIに関連するリスクを特定・評価し、適切な対策を講じること', 'AIの市場シェアを拡大すること', 'AIの開発期間を短縮すること', 'C', 'リスクアセスメントとは、AIの導入に伴うリスク（誤診、個人情報漏えい、システム障害等）を体系的に特定し、その発生可能性と影響度を評価し、適切な対策を講じるプロセスです。医療AIでは患者の安全に直結するため、リスクアセスメントは特に重要です。', 'A: コスト最小化はリスクアセスメントの主目的ではありません。C: 市場シェア拡大はリスクアセスメントの目的ではありません。D: 開発期間短縮はリスクアセスメントとは関係ありません。', 'ISO 14971・医療機器リスクマネジメント'),
('Q5-016', '第5章', 'インフォームド・コンセント', '難', '評価', 'AI診断支援を使用する際のインフォームド・コンセントにおいて、患者に説明すべき内容として、最も重要度が高いものはどれか。', 'AIを開発した企業の会社概要', 'AIの判断には限界があり、最終判断は医師が行うこと', 'AIの学習に使用したデータの詳細な統計情報', 'AIシステムの価格と導入コスト', 'C', '患者へのインフォームド・コンセントにおいて最も重要なのは、AIはあくまで診断を支援するツールであり、判断には限界がある可能性があること、そして最終的な診断・治療の判断は医師が責任を持って行うことを理解してもらうことです。これにより、患者はAIの役割を正しく理解し、医師との信頼関係を維持できます。', 'A: 開発企業の会社概要は、患者が意思決定するために必須の情報ではありません。C: 学習データの詳細な統計情報は専門的すぎて患者の理解には適していません。D: 価格やコストは患者の医療判断に直接関係しません。', '医療倫理・インフォームド・コンセント指針'),
('Q5-017', '第5章', '過信と自動化バイアス', '標準', '適用', '医師がAI診断支援システムを使用する際に、自動化バイアスを防ぐための適切な対策はどれか。', 'AIの出力を常に100%信頼して診断を行う', 'AIの出力を参考にしつつ、独自の臨床判断も必ず行い、両者を照合する', 'AIの使用を完全に中止する', 'AIの出力を見る前に患者を帰宅させる', 'B', '自動化バイアスを防ぐためには、AIの出力を参考にしつつも、医師自身の臨床知識や経験に基づく独自の判断を必ず行い、両者を照合することが重要です。AIと医師の判断が異なる場合は、その理由を検討することで、より正確な診断につながります。', 'A: AIを100%信頼することは自動化バイアスそのものであり、対策になりません。C: AIの使用中止は過剰な対応であり、有用なツールの活用を妨げます。D: 診療を完了せずに帰宅させることは不適切です。', '医療AI利用に関する研究'),
('Q5-018', '第5章', '公平性', '難', '分析', '医療AIの公平性評価において、「サブグループ分析」が重要とされる理由として、最も適切なものはどれか。', 'AIの処理速度を測定するため', '全体の精度が高くても、特定の患者集団で精度が低下していないか確認するため', 'AIの開発コストを算出するため', 'AIのユーザーインターフェースを評価するため', 'B', 'サブグループ分析とは、年齢層、性別、人種などの属性ごとにAIの性能を評価することです。全体の精度が高くても、特定のサブグループ（例：高齢者、特定の人種）で精度が著しく低下している場合、そのグループの患者に不利益が生じます。公平性を確保するためには、全体評価だけでなくサブグループ分析が不可欠です。', 'A: 処理速度測定はサブグループ分析の目的ではありません。C: 開発コスト算出とは関係ありません。D: UI評価はサブグループ分析の目的ではありません。', 'AI公平性評価・FDA/PMDA指針'),
('Q5-019', '第5章', '医療AIの責任所在', '易', '理解', '医療機関がAI診断支援システムを導入する際に負う責任として、最も適切なものはどれか。', 'AIの出力結果に対する責任は全てAI開発企業が負う', '適切なシステムの選定、運用管理、職員教育などの管理責任', 'AI開発企業の経営に関する責任', 'AIを使用する患者の自己責任のみ', 'B', '医療機関がAI診断支援システムを導入する場合、適切なシステムの選定（信頼性、実績の確認）、適正な運用管理、職員への教育・訓練、不具合発生時の対応体制整備などの管理責任を負います。AI利用者としての責任を果たすことで、安全で効果的なAI活用が可能になります。', 'A: 全責任が開発企業にあるわけではなく、医療機関にも管理責任があります。C: AI開発企業の経営に医療機関が責任を負うことはありません。D: 患者の自己責任のみとすることは不適切です。', 'AI事業者ガイドライン・医療機関管理者の責務'),
('Q5-020', '第5章', 'プライバシー保護', '標準', '適用', '医療AIの学習データを作成する際の「差分プライバシー」技術の目的として、最も適切なものはどれか。', 'AIの学習速度を向上させること', '学習データから個人を特定することを数学的に困難にすること', 'AIの出力精度を向上させること', 'AIの消費電力を削減すること', 'D', '差分プライバシー（Differential Privacy）は、データにノイズを加えることで、個々のデータポイント（患者）の存在がモデルの出力に与える影響を最小化し、学習データから個人を特定することを数学的に困難にする技術です。医療AIでは患者のプライバシー保護に活用されています。', 'A: 差分プライバシーは学習速度向上を目的としていません。C: プライバシー保護が目的であり、精度向上ではありません（むしろトレードオフの関係）。D: 消費電力とは関係ありません。', 'プライバシー保護技術・差分プライバシー'),
('Q5-021', '第5章', '患者の自律性', '標準', '理解', 'AIを用いた医療において「Human-in-the-loop」の原則が重要とされる理由として、最も適切なものはどれか。', '人間がAIの電源を管理するため', '重要な意思決定において人間が最終的な判断と責任を持つため', '人間がAIのプログラムを作成するため', '人間がAIの販売を担当するため', 'B', 'Human-in-the-loop（人間参加型）とは、AIの判断プロセスに人間が介在し、特に重要な意思決定においては人間が最終的な判断と責任を持つという原則です。医療AIにおいては、AIの出力を医師が確認・評価し、最終的な診断・治療の決定を行うことで、患者の安全と人間の責任を確保します。', 'A: 電源管理はHuman-in-the-loopの本質ではありません。C: プログラム作成は開発段階の話であり、運用時の原則ではありません。D: 販売担当はHuman-in-the-loopの意味ではありません。', 'AI事業者ガイドライン・EU AI法'),
('Q5-022', '第5章', 'AIバイアス', '易', '記憶（知識）', '医療AIにおける「選択バイアス」の説明として、最も適切なものはどれか。', 'AIが選択肢を提示する際に偏りが生じること', '学習データの収集段階で特定の患者群が過剰または過少に含まれること', '医師がAIを選択的に使用すること', '患者がAIによる診療を選択すること', 'B', '選択バイアス（Selection Bias）とは、学習データの収集段階で生じる偏りを指します。例えば、特定の病院のデータのみを使用した場合、その病院を受診する患者層（地域、経済状況等）に偏りが生じます。また、重症患者や特定の疾患を持つ患者が過剰に含まれるなどの偏りも選択バイアスです。', 'A: 選択肢提示の偏りは選択バイアスの定義ではありません。C: 医師の使用判断は選択バイアスとは異なります。D: 患者の選択は選択バイアスの定義には該当しません。', 'AI公平性・バイアスに関する研究'),
('Q5-023', '第5章', '説明可能性', '標準', '適用', '画像診断AIが「この画像には異常が疑われます」と出力した。説明可能性の観点から望ましいAIの追加機能はどれか。', '結論のみをより大きな文字で表示する', '異常が疑われる領域をハイライト表示し、類似症例を提示する', '出力の信頼度を暗号化して表示する', 'AIの学習に使用した全データを一覧表示する', 'B', '説明可能性を高めるためには、AIがなぜその判断に至ったかを視覚的に示すことが有効です。異常が疑われる領域をハイライト表示することで、医師はAIがどこに注目したかを把握でき、判断の妥当性を評価できます。また、類似症例の提示により、AIの判断根拠をより深く理解できます。', 'A: 文字を大きくしても説明可能性は向上しません。C: 暗号化は説明可能性を低下させます。D: 全学習データの一覧は実用的ではなく、説明可能性向上に直結しません。', 'XAI（説明可能AI）技術'),
('Q5-024', '第5章', 'リスク管理', '難', '評価', '医療AIの導入に際して、リスクと便益のバランスを評価する際に最も重要な考慮事項はどれか。', 'AIの導入コストが最小であること', 'AI導入による患者への便益が、想定されるリスクを上回ること', 'AIの処理速度が最速であること', 'AI開発企業の知名度が高いこと', 'A', '医療AIの導入においては、AIがもたらす便益（診断精度向上、早期発見、医師の負担軽減など）と、想定されるリスク（誤診、プライバシー侵害、システム障害など）を比較評価することが重要です。便益がリスクを上回り、患者にとって正味のメリットがあると判断される場合に導入が正当化されます。', 'A: コスト最小化よりも、リスクと便益のバランスが優先されます。C: 処理速度はリスク・便益評価の主要因ではありません。D: 企業の知名度は臨床的なリスク・便益評価とは関係ありません。', '医療機器リスクマネジメント・ISO 14971'),
('Q5-025', '第5章', '医療倫理四原則', '標準', '適用', '医療AIの活用において「無危害（Non-maleficence）」の原則を実践する例として、最も適切なものはどれか。', 'AIの導入により医療費を削減する', 'AIの誤診リスクを最小化するための検証と監視を行う', 'AIの使用を全ての患者に平等に提供する', '患者にAIの使用について説明し同意を得る', 'B', '無危害（Non-maleficence）の原則は「患者に害を与えない」ことを意味します。医療AIにおいては、誤診や不適切な推奨による患者への害を防ぐため、AIの精度検証、継続的な性能監視、適切な使用環境の整備などを行うことがこの原則の実践です。', 'A: 医療費削減は善行や公正に関連しますが、無危害の直接的実践ではありません。C: 平等な提供は公正（Justice）の原則に関連します。D: 説明と同意は自律尊重（Autonomy）の原則に関連します。', '医療倫理四原則'),
('Q5-026', '第5章', 'ハルシネーション', '易', '理解', '生成AIのハルシネーションが医療分野で特に問題となる理由として、最も適切なものはどれか。', '生成される文章が長くなりすぎるため', '誤った医療情報が患者の健康被害につながる可能性があるため', '生成に時間がかかりすぎるため', '出力される情報量が少なすぎるため', 'D', '生成AIのハルシネーションは、事実に基づかない誤った情報を生成する現象です。医療分野では、誤った薬剤情報、存在しない治療法、不正確な診断情報などが生成された場合、それを信じた患者や医療従事者の判断に影響し、健康被害につながる可能性があります。このため、医療分野では特に注意が必要です。', 'A: 文章の長さはハルシネーションの本質的な問題ではありません。C: 生成時間は別の問題であり、ハルシネーションとは異なります。D: 情報量の少なさはハルシネーションの問題ではありません。', '生成AI利用に関する注意喚起'),
('Q5-027', '第5章', 'インフォームド・コンセント', '標準', '適用', 'AIを用いた診断を受けた患者が「なぜAIはそう判断したのか」と質問した場合、医師の対応として最も適切なものはどれか。', 'AIの判断理由は専門的すぎるため説明を拒否する', 'AIの出力に基づき、分かりやすい言葉で判断根拠を説明する努力をする', 'AIの判断は絶対なので疑問を持たないよう伝える', 'AIメーカーに直接問い合わせるよう患者に伝える', 'C', '患者には自分が受ける医療について理解する権利があり、AIを用いた診断についても同様です。医師はAIの出力（注目した領域、類似症例との比較など）に基づいて、専門用語を避けながら患者が理解できる言葉で説明する努力をすべきです。完璧な説明ができなくても、誠実に対応することが信頼関係構築につながります。', 'A: 説明を拒否することは患者の権利を尊重していません。C: AIの判断が絶対というのは不正確であり、疑問を持つことは当然の権利です。D: 医師としての説明責任を果たさず、不適切な対応です。', '医療倫理・インフォームド・コンセント'),
('Q5-028', '第5章', '過信と自動化バイアス', '難', '分析', '医療AIに対する過信を防ぐための組織的な取り組みとして、適切でないものはどれか。', 'AIの限界や誤りの可能性についての継続的な教育', 'AIの判断と医師の判断が異なった事例の定期的なレビュー', 'AIの精度を100%と説明し、全幅の信頼を置くよう指導する', 'AIの性能データ（感度・特異度等）の透明な共有', 'C', 'AIの精度を100%と説明し全幅の信頼を置くよう指導することは、過信を助長し、自動化バイアスを強化する不適切な取り組みです。どのようなAIにも限界があり、誤りの可能性を認識した上で適切に活用することが重要です。過信を防ぐためには、限界の教育、事例レビュー、データの透明な共有が有効です。', 'A: 限界についての教育は過信を防ぐ適切な取り組みです。B: 判断が異なった事例のレビューはAIの特性理解に役立ちます。D: 性能データの共有は適切な期待値設定に貢献します。', '医療AI導入に関するベストプラクティス'),
('Q5-029', '第5章', '公平性', '易', '記憶（知識）', '医療AIの公平性に関する「代表性の問題」とは何か。', 'AIを代表する広報担当者が不在であること', '学習データが実際に使用される患者集団を十分に反映していないこと', 'AI開発企業の代表者が医療の専門家でないこと', 'AIの出力結果を代表して説明する人がいないこと', 'B', '代表性の問題とは、AIの学習に使用されたデータが、実際にAIが使用される患者集団を十分に代表していない（反映していない）状況を指します。例えば、欧米の患者データで学習したAIをアジアの患者に適用すると、人種による身体的特性の違いから精度が低下する可能性があります。', 'A: 広報担当者の有無は代表性の問題ではありません。C: 企業代表者の専門性は代表性の問題とは異なります。D: 説明担当者の問題は代表性の問題ではありません。', 'AI公平性・データの代表性'),
('Q5-030', '第5章', 'リスク管理', '標準', '理解', '医療AIの「ドリフト」（性能劣化）が発生する原因として、最も適切なものはどれか。', 'AIのハードウェアが物理的に劣化すること', '医療環境や患者集団の変化により、学習データと実際のデータに乖離が生じること', 'AIの電源が不安定であること', 'AIのユーザーインターフェースが古くなること', 'A', 'AIのドリフト（Drift）とは、時間経過とともにAIの性能が劣化する現象です。主な原因は、学習時のデータと実運用時のデータの分布が変化することです。医療では、新しい検査機器の導入、患者集団の変化、疾患の傾向変化などにより、学習データとの乖離が生じ、精度が低下する可能性があります。', 'A: ハードウェアの物理的劣化はドリフトの主原因ではありません。C: 電源の不安定さはドリフトとは異なる問題です。D: UIの古さは性能劣化とは関係ありません。', 'AI監視・ドリフト検出'),
('Q5-031', '第5章', '説明可能性', '易', '記憶（知識）', '医療AIの説明可能性を高めるための技術「LIME」や「SHAP」の目的として、最も適切なものはどれか。', 'AIの処理速度を向上させること', 'AIの個々の予測に対して、どの特徴が判断に寄与したかを示すこと', 'AIの学習データ量を増やすこと', 'AIのセキュリティを強化すること', 'B', 'LIME（Local Interpretable Model-agnostic Explanations）やSHAP（SHapley Additive exPlanations）は、AIの個々の予測に対して、入力データのどの特徴がその判断に寄与したかを数値化して示す技術です。これにより、ブラックボックス的なAIの判断根拠を理解しやすくなります。', 'A: これらの技術は処理速度向上を目的としていません。C: 学習データ量の増加とは関係ありません。D: セキュリティ強化を目的とした技術ではありません。', 'XAI（説明可能AI）技術'),
('Q5-032', '第5章', '医療AIの責任所在', '標準', '適用', 'AI診断支援システムが誤った診断提案を出し、医師がそれを採用して患者に害が生じた場合、責任の所在に関する考え方として最も適切なものはどれか。', 'AIの提案を採用した医師に全責任がある', '医師の注意義務と、AI開発者・提供者の製品責任が複合的に検討される', 'AIには意思がないため、誰にも責任はない', '患者がAI診療を受けることに同意したため、患者の自己責任である', 'C', 'AI診断支援における責任は複合的に検討されます。医師には、AIの出力を批判的に評価し適切な診断を行う注意義務があります。一方、AIに欠陥（設計不良、不十分な検証等）があった場合は、開発者・提供者にも製造物責任や契約上の責任が生じ得ます。個々の事案に応じて、それぞれの責任割合が判断されます。', 'A: 医師だけでなく、AI開発者・提供者の責任も検討されます。C: AIに意思がなくても、関与した人間や組織に責任が生じます。D: 患者の同意を得ていても、医療提供者の責任は免除されません。', '医療AI責任論・製造物責任法'),
('Q5-033', '第5章', 'プライバシー保護', '難', '分析', '医療AIの学習に用いたデータから患者を特定する攻撃手法として、「メンバーシップ推論攻撃」がある。この攻撃の内容として、最も適切なものはどれか。', 'AIのパスワードを推測して不正アクセスすること', '特定の個人のデータがAIの学習に使われたかどうかを推測すること', 'AIの開発チームのメンバーを特定すること', 'AIのユーザーアカウントを乗っ取ること', 'C', 'メンバーシップ推論攻撃（Membership Inference Attack）とは、AIモデルの出力を分析することで、特定の個人のデータがそのモデルの学習に使用されたかどうかを推測する攻撃手法です。医療AIの場合、ある患者のデータが学習に使われたことが判明すると、その患者が特定の疾患を持っていることが推測される可能性があり、プライバシー上の問題となります。', 'A: パスワード推測は別のセキュリティ攻撃であり、メンバーシップ推論攻撃ではありません。C: 開発チームの特定は別の問題です。D: アカウント乗っ取りはメンバーシップ推論攻撃ではありません。', 'AIプライバシー攻撃・防御技術'),
('Q5-034', '第5章', '患者の自律性', '標準', '理解', '医療AIが治療方針を提案する際に、患者の自律性を尊重するために重要な点はどれか。', 'AIの提案が最善であるため、患者は従うべきと伝える', 'AIの提案を含む複数の選択肢を示し、患者自身が決定できるよう支援する', 'AIの提案を患者に知らせずに医師が決定する', 'AIの提案に反対する患者は治療を受けられないと伝える', 'A', '患者の自律性を尊重するためには、AIの提案を唯一の選択肢として押し付けるのではなく、AI提案を含む複数の選択肢とそれぞれのメリット・デメリットを説明し、患者が自分の価値観に基づいて決定できるよう支援することが重要です。医師は情報提供と意思決定支援を行い、最終決定は患者に委ねます。', 'A: AIの提案を強制することは自律性の侵害です。C: 患者に情報を提供しないことは自律性を無視しています。D: 患者の選択を制限することは自律性に反します。', '医療倫理・患者の自律性'),
('Q5-035', '第5章', 'AIバイアス', '難', '評価', '医療AIにおけるバイアスを軽減するための技術的アプローチとして、適切でないものはどれか。', '学習データのリサンプリングにより、少数派グループの代表性を高める', '公平性制約を損失関数に組み込み、学習時にバイアスを抑制する', 'AIの出力を後処理して、グループ間の結果を均等化する', 'バイアスの存在を隠蔽し、ユーザーに知らせない', 'D', 'バイアスの存在を隠蔽することは、バイアスの軽減にはなりません。むしろ、バイアスの存在を認識し、透明性を持って対処することが重要です。技術的なバイアス軽減アプローチには、データレベル（リサンプリング）、アルゴリズムレベル（公平性制約）、後処理レベル（出力調整）などがあり、これらを組み合わせて対処します。', 'A: リサンプリングは少数派グループの影響を高める有効な手法です。B: 公平性制約を損失関数に組み込むことは学習時のバイアス軽減に有効です。C: 後処理による結果の均等化も公平性向上の一手法です。', 'AI公平性・バイアス軽減技術'),
('Q5-036', '第5章', '医療倫理四原則', '標準', '適用', '医療AIの導入において「善行（Beneficence）」の原則を実践する例として、最も適切なものはどれか。', 'AIの導入コストを最小限に抑える', 'AIによる早期診断で患者の予後を改善する', 'AI利用について患者の同意を得る', 'AIを使った診療を全患者に平等に提供する', 'B', '善行（Beneficence）の原則は「患者に善を行う」ことを意味します。医療AIにおいては、AIを活用して診断精度を向上させ、疾患の早期発見や適切な治療選択を可能にし、結果として患者の予後を改善することが善行の実践です。患者に具体的な利益をもたらすことがこの原則の核心です。', 'A: コスト削減は経営上の利点であり、善行の原則の直接的実践ではありません。C: 患者の同意は自律尊重の原則に関連します。D: 平等な提供は公正の原則に関連します。', '医療倫理四原則'),
('Q5-037', '第5章', 'リスク管理', '易', '理解', '医療AI導入時の「リスクコミュニケーション」の目的として、最も適切なものはどれか。', 'AIのリスクを隠蔽すること', 'AIのリスクについて関係者と情報を共有し、相互理解を促進すること', 'AIのリスクを誇張して導入を阻止すること', 'AIのリスクを無視して導入を推進すること', 'D', 'リスクコミュニケーションとは、AIに関連するリスクについて、医療従事者、患者、経営層、規制当局などの関係者と情報を共有し、相互理解を促進するプロセスです。リスクを適切に伝えることで、関係者がリスクを理解した上で意思決定でき、適切なリスク管理につながります。', 'A: リスクの隠蔽はリスクコミュニケーションの目的に反します。C: 誇張して導入を阻止することは適切なコミュニケーションではありません。D: リスクの無視は危険であり、リスクコミュニケーションの目的ではありません。', 'リスクコミュニケーション'),
('Q5-038', '第5章', 'ハルシネーション', '難', '分析', '生成AIのハルシネーションを軽減するための技術的アプローチとして、最も有効なものはどれか。', '生成AIの出力文字数を制限する', '検索拡張生成（RAG）により、信頼できる情報源を参照させる', '生成AIの処理速度を向上させる', '生成AIのフォントサイズを大きくする', 'B', '検索拡張生成（RAG: Retrieval-Augmented Generation）は、生成AIが回答を生成する際に、信頼できる外部データベースや文書を検索・参照させる技術です。これにより、AIは学習時の知識だけでなく、最新かつ正確な情報に基づいて回答を生成でき、ハルシネーションのリスクを軽減できます。医療分野では医学文献や診療ガイドラインを参照させることが有効です。', 'A: 文字数制限はハルシネーション軽減に直接効果がありません。C: 処理速度向上はハルシネーションとは無関係です。D: フォントサイズはハルシネーションと関係ありません。', 'RAG技術・生成AI信頼性向上'),
('Q5-039', '第5章', '過信と自動化バイアス', '易', '記憶（知識）', '医療AIへの過信による問題として、適切でないものはどれか。', '医師がAIの誤りを見逃す', 'AIが示さなかった異常を医師が見落とす', '医師の臨床スキルが向上する', '医師がAIの出力を確認せずに受け入れる', 'C', 'AIへの過信による問題には、AIの誤りを見逃す、AIが示さなかった異常を見落とす、批判的思考なしにAI出力を受け入れるなどがあります。一方、「医師の臨床スキルが向上する」は過信による問題ではなく、むしろAIを適切に活用した場合の利点です。過信は逆にスキル低下につながる可能性があります。', 'A: AIの誤りを見逃すことは過信による典型的な問題です。B: AIが示さなかった異常の見落としは過信による問題です。D: 確認せずに受け入れることは過信の表れです。', '自動化バイアス・医療AI利用の注意点'),
('Q5-040', '第5章', 'インフォームド・コンセント', '標準', '理解', 'AIを用いた診療におけるインフォームド・コンセントで、患者に伝えることが望ましい内容として、適切でないものはどれか。', 'AIを診断の補助として使用すること', 'AIの判断には限界がある可能性があること', '最終的な診断判断は医師が行うこと', 'AIのプログラムコードの詳細', 'D', 'インフォームド・コンセントでは、患者が理解し意思決定できる範囲の情報提供が重要です。AIの使用、その限界、医師の役割などは患者に伝えるべき情報ですが、プログラムコードの詳細は専門的すぎて患者の理解や意思決定には役立たないため、必ずしも伝える必要はありません。', 'A: AIを診断補助として使用することは患者に伝えるべき重要な情報です。B: AIの判断の限界について伝えることは重要です。C: 医師が最終判断を行うことを説明することは重要です。', 'インフォームド・コンセント指針'),
('Q5-041', '第5章', '公平性', '易', '理解', '医療AIの公平性評価において、「偽陰性率」のグループ間格差が問題となる理由として、最も適切なものはどれか。', 'AIの処理速度に影響するため', '特定のグループで疾患が見逃される割合が高くなり、健康格差につながるため', 'AIの開発コストが増加するため', 'AIのユーザーインターフェースが複雑になるため', 'B', '偽陰性率とは、実際に疾患がある人を「異常なし」と判定する割合です。この率にグループ間格差があると、特定のグループ（例：特定の人種、性別）で疾患が見逃される確率が高くなり、診断の遅れや治療機会の喪失につながります。これは健康格差を拡大させる深刻な公平性の問題です。', 'A: 偽陰性率は処理速度とは関係ありません。C: 開発コストとは直接関係しません。D: UIの複雑さとは関係ありません。', 'AI公平性評価指標'),
('Q5-042', '第5章', 'リスク管理', '標準', '適用', '医療AIのインシデント発生時の対応として、最も適切な初動対応はどれか。', 'インシデントを隠蔽し、通常業務を継続する', '関係者への報告と患者安全の確保を最優先に行う', 'AI開発企業の責任追及を最優先に行う', 'マスコミ対応を最優先に行う', 'A', '医療AIでインシデントが発生した場合、最優先すべきは患者安全の確保です。同時に、院内の関係者（医療安全管理者、情報システム部門等）への速やかな報告を行い、被害拡大の防止と原因究明に着手します。隠蔽や責任追及の優先は不適切であり、まず患者を守ることが重要です。', 'A: 隠蔽は問題を深刻化させ、不適切な対応です。C: 責任追及より患者安全と原因究明が先です。D: マスコミ対応より患者安全が優先されます。', '医療安全管理・インシデント対応'),
('Q5-043', '第5章', '説明可能性', '難', '評価', '医療AIの説明可能性と性能（精度）の関係について、最も適切な説明はどれか。', '説明可能性を高めると、AIの精度は必ず向上する', '高精度なAIは常に説明可能性も高い', '説明可能性と精度はトレードオフの関係にある場合があり、バランスの判断が必要', '説明可能性と精度は全く無関係である', 'C', '一般に、高精度を実現するディープラーニングモデルは複雑でブラックボックス性が高く、説明可能性が低い傾向があります。一方、説明しやすい単純なモデルは精度が劣る場合があります。医療AIでは、用途に応じて説明可能性と精度のバランスを判断することが重要です。高リスクな判断には説明可能性が、スクリーニングには精度が重視される場合があります。', 'A: 説明可能性を高めても精度が向上するとは限りません。B: 高精度モデル（深層学習等）は説明可能性が低いことが多いです。D: 両者には関係性があり、完全に無関係ではありません。', 'XAI・精度と説明可能性のトレードオフ'),
('Q5-044', '第5章', 'プライバシー保護', '標準', '適用', '医療AIの開発において「フェデレーテッドラーニング（連合学習）」が注目される理由として、最も適切なものはどれか。', '学習速度を大幅に向上させるため', '各医療機関のデータを集約せずに、分散したままAIを学習できるためプライバシーリスクが低減されるため', 'AIの開発コストを削減するため', 'AIの精度を100%保証するため', 'B', 'フェデレーテッドラーニング（連合学習）は、各医療機関がデータを外部に出さずに、学習済みモデルのパラメータのみを共有してAIを協調学習する手法です。患者データが各機関内に留まるため、データ集約に伴うプライバシーリスクを大幅に軽減できます。医療分野では、複数機関のデータを活用しつつプライバシーを守る方法として注目されています。', 'A: 学習速度向上は主目的ではなく、むしろ通信コストで遅くなる場合もあります。C: コスト削減が主目的ではありません。D: 精度を100%保証するものではありません。', 'フェデレーテッドラーニング・プライバシー保護技術'),
('Q5-045', '第5章', '医療AIの責任所在', '難', '分析', '医療AIの運用において「ガバナンス体制」を構築する目的として、最も重要なものはどれか。', 'AI開発企業の利益を最大化すること', 'AIの適切な利用、監視、改善のための組織的な管理体制を確立すること', 'AIの導入を遅らせること', 'AIに関する情報を外部に漏らさないこと', 'B', 'AIガバナンス体制の目的は、AIの適切な利用方針の策定、継続的な性能監視、問題発生時の対応プロセス、責任の所在の明確化など、組織としてAIを適切に管理・運用するための体制を確立することです。これにより、AIの恩恵を享受しながらリスクを適切に管理し、患者安全と信頼を確保できます。', 'A: 企業利益最大化はガバナンス体制の目的ではありません。C: 導入を遅らせることではなく、適切に導入・運用することが目的です。D: 情報漏洩防止は重要ですが、ガバナンスの主目的ではありません。', 'AIガバナンス・医療機関のAI管理体制'),
('Q6-001', '第6章', 'プロンプトエンジニアリング', '易', '記憶（知識）', '生成AIへの指示文（プロンプト）を工夫して、望ましい出力を得る技術を何と呼ぶか。', 'プログラミング', 'プロンプトエンジニアリング', 'データマイニング', 'ネットワーキング', 'B', 'プロンプトエンジニアリング（Prompt Engineering）とは、生成AIに対する指示文（プロンプト）を工夫・最適化することで、より正確で有用な出力を引き出す技術です。医療分野では、適切なプロンプトを設計することで、患者説明資料の作成や文献検索などの業務効率を向上させることができます。', 'A: プログラミングはソフトウェア開発のためのコード記述であり、プロンプト設計とは異なります。C: データマイニングはデータからパターンを発見する技術です。D: ネットワーキングは通信やコネクション構築を指す言葉です。', '生成AI活用ガイドライン'),
('Q6-002', '第6章', 'Few-shot学習', '標準', '理解', '生成AIに対して「Few-shotプロンプティング」を行う利点として、最も適切なものはどれか。', 'AIの処理速度が向上する', '例を示すことで、AIが期待される出力形式やスタイルを理解しやすくなる', 'AIの消費電力が削減される', 'AIの学習データが自動的に更新される', 'A', 'Few-shotプロンプティングとは、生成AIに対してタスクの指示とともに、いくつかの入出力例（例：質問と回答のペア）を示す手法です。これにより、AIは期待される出力の形式、スタイル、内容の方向性を理解しやすくなり、より適切な回答を生成できるようになります。', 'A: Few-shotは処理速度向上とは直接関係しません。C: 消費電力削減の効果はありません。D: 学習データの更新とは異なる概念です。', 'プロンプトエンジニアリング技術'),
('Q6-003', '第6章', '医療文書作成支援', '易', '適用', '看護師が生成AIを使って患者向け説明資料を作成する際の注意点として、最も適切なものはどれか。', '生成AIの出力をそのまま患者に渡してよい', '生成AIの出力を専門的知識に基づいて確認・修正してから使用する', '患者情報を生成AIに入力して、個別の説明資料を作成する', '説明資料作成に生成AIは一切使用すべきでない', 'A', '生成AIはハルシネーション（誤情報生成）のリスクがあるため、出力をそのまま使用することは危険です。看護師は専門的知識に基づいて内容の正確性を確認し、必要に応じて修正してから患者に提供すべきです。また、患者個人情報を入力することはプライバシーリスクがあり避けるべきです。', 'A: 確認なしにそのまま使用することはリスクがあります。C: 患者情報を外部AIに入力することはプライバシー上問題があります。D: 適切に使用すれば業務効率化に有用であり、一切使用禁止とする必要はありません。', '医療従事者向け生成AI利用指針'),
('Q6-004', '第6章', 'プロンプトエンジニアリング', '標準', '適用', '医師が生成AIに「糖尿病の治療について教えて」と質問するより、効果的なプロンプトはどれか。', '糖尿病について', '2型糖尿病の成人患者への初期治療薬の選択基準について、日本のガイドラインに基づいて箇条書きで説明してください', '糖尿病とは', '病気の治療', 'B', '効果的なプロンプトは、具体的で明確な指示を含むものです。選択肢Bは、対象（2型糖尿病の成人患者）、内容（初期治療薬の選択基準）、根拠（日本のガイドライン）、形式（箇条書き）を明示しており、AIが期待に沿った回答を生成しやすくなります。曖昧な質問よりも具体的な指示が効果的です。', 'A: 「糖尿病について」は漠然としており、期待する回答が得られにくいです。C: 「糖尿病とは」も抽象的で、どのような情報を求めているか不明確です。D: 「病気の治療」は範囲が広すぎて、有用な回答が得られにくいです。', 'プロンプトエンジニアリング・ベストプラクティス'),
('Q6-005', '第6章', '出力の検証', '易', '記憶（知識）', '生成AIの出力を検証する際に重要な観点として、適切でないものはどれか。', '出力内容の事実確認（ファクトチェック）', '出力された情報の出典・根拠の確認', '出力された文章の文字数', '医学的・科学的な正確性の確認', 'C', '生成AIの出力を検証する際に重要なのは、内容の正確性、事実関係、根拠の妥当性、医学的・科学的な正確性などです。文字数は形式的な要素であり、内容の質や正確性の検証においては重要な観点ではありません。むしろ、文字数が少なくても正確な情報が含まれていることが重要です。', 'A: ファクトチェックは生成AIの出力検証において重要な観点です。B: 出典・根拠の確認は信頼性評価に不可欠です。D: 医学的・科学的正確性の確認は医療分野では特に重要です。', '生成AI出力の検証方法'),
('Q6-006', '第6章', 'Chain-of-Thought', '標準', '理解', '生成AIのプロンプト技法「Chain-of-Thought（思考の連鎖）」の効果として、最も適切なものはどれか。', 'AIの回答速度が向上する', 'AIに段階的に推論させることで、複雑な問題に対する回答精度が向上する', 'AIの消費メモリが削減される', 'AIの学習データが自動更新される', 'D', 'Chain-of-Thought（CoT）プロンプティングは、AIに対して「ステップバイステップで考えてください」などと指示し、段階的な推論過程を明示させる技法です。これにより、単純に答えだけを出力させるよりも、複雑な問題や論理的推論を要するタスクにおいて回答精度が向上することが報告されています。', 'A: CoTは回答速度向上を目的としたものではなく、むしろ推論過程を出力する分、回答は長くなる傾向があります。C: メモリ削減とは関係ありません。D: 学習データの更新とは異なる概念です。', 'プロンプトエンジニアリング技術・CoT'),
('Q6-007', '第6章', '医療文書作成支援', '標準', '適用', '医師が生成AIを使用して診療情報提供書（紹介状）の下書きを作成する場合、最も適切な利用方法はどれか。', '患者のカルテ情報をそのまま生成AIに入力し、紹介状を自動生成させる', '一般的な紹介状の文例を参考に生成させ、医師が患者情報を加えて完成させる', '生成AIが作成した紹介状をそのまま患者に渡す', '患者の保険証番号を含めて生成AIに紹介状を作成させる', 'D', '患者のカルテ情報や個人識別情報を外部の生成AIに入力することはプライバシーリスクがあります。適切な利用方法は、生成AIで一般的な紹介状の文例や構成を参考にし、医師が患者固有の情報を自身で追記して完成させることです。最終的な内容確認と責任は医師が担います。', 'A: カルテ情報をそのまま入力することはプライバシーリスクがあります。C: 確認なしにそのまま渡すことは不適切です。D: 保険証番号などの個人識別情報の入力は避けるべきです。', '医療従事者向け生成AI利用指針'),
('Q6-008', '第6章', '文献検索・要約', '易', '理解', '医療従事者が生成AIを使って医学文献を要約させる際の注意点として、最も適切なものはどれか。', '生成AIは常に最新の論文を参照しているため、追加確認は不要である', '生成AIの要約が元文献の内容を正確に反映しているか、原典で確認する必要がある', '生成AIは医学文献を要約できないため、使用すべきでない', '要約は生成AIが行い、引用も生成AIに任せてよい', 'C', '生成AIは文献を要約することができますが、ハルシネーションにより元文献にない内容を含めたり、重要な情報を省略したりする可能性があります。そのため、生成AIの要約を鵜呑みにせず、必ず原典で内容を確認することが重要です。また、生成AIには知識のカットオフ日があり、最新論文を参照していない場合もあります。', 'A: 生成AIには知識のカットオフ日があり、最新論文を参照しているとは限りません。C: 適切に使用すれば文献要約に有用です。D: 引用は正確性が重要であり、生成AIに任せるべきではありません。', '生成AI利用における注意事項'),
('Q6-009', '第6章', 'プロンプトエンジニアリング', '難', '分析', '医療分野で生成AIを活用する際に、「ロールプロンプティング」が有効な理由として、最も適切なものはどれか。', 'AIの処理速度が向上するため', '「あなたは医療専門家です」等と役割を設定することで、専門的な視点からの回答を促せるため', 'AIの消費電力が削減されるため', 'AIが自動的に最新情報を検索するため', 'D', 'ロールプロンプティングとは、「あなたは〇〇の専門家です」のように、生成AIに特定の役割を設定する手法です。医療分野では「あなたは循環器内科の専門医です」などと設定することで、その専門領域に適した知識や表現を用いた回答を引き出しやすくなります。ただし、これはあくまで出力の傾向を調整するものであり、内容の検証は依然として必要です。', 'A: ロールプロンプティングは処理速度向上を目的としていません。C: 消費電力とは関係ありません。D: 自動的な最新情報検索機能とは異なります。', 'プロンプトエンジニアリング技術'),
('Q6-010', '第6章', '出力の検証', '標準', '適用', '生成AIが「この薬剤の副作用は〇〇です」と出力した場合、医療従事者が取るべき対応として、最も適切なものはどれか。', '生成AIの出力を信頼し、そのまま患者に説明する', '添付文書や医薬品情報データベースで出力内容の正確性を確認する', '生成AIは医療情報を扱えないため、使用を中止する', '他の生成AIサービスで同じ質問をして、回答が一致すれば正しいと判断する', 'D', '生成AIの出力する薬剤情報にはハルシネーションのリスクがあります。副作用情報は患者安全に直結するため、必ず公式の情報源（添付文書、医薬品情報データベース、PMDAのサイト等）で確認する必要があります。生成AIの出力はあくまで参考情報として扱い、正式な情報源での検証が不可欠です。', 'A: 確認なしにそのまま患者に説明することは危険です。C: 適切に使用し検証すれば有用であり、使用中止は過剰反応です。D: 複数AIで一致しても正しいとは限らず、公式情報源での確認が必要です。', '医療情報の検証方法'),
('Q6-011', '第6章', '患者コミュニケーション', '易', '適用', '医療従事者が患者向けの説明資料を生成AIで作成する際、読みやすさを向上させるための適切なプロンプト指示はどれか。', '専門用語を多用して作成してください', '医療の専門知識がない人にも分かるよう、平易な言葉で説明してください', 'できるだけ短く1行で説明してください', '英語で作成してください', 'B', '患者向けの説明資料は、医療の専門知識がない人でも理解できるよう、平易な言葉で作成することが重要です。プロンプトに「医療の専門知識がない人にも分かるよう」と指定することで、生成AIは専門用語を避け、分かりやすい表現を使った文章を生成しやすくなります。', 'A: 専門用語の多用は患者の理解を妨げます。C: 1行では十分な説明ができません。D: 日本の患者向けには日本語が適切です。', '患者向け説明資料作成の指針'),
('Q6-012', '第6章', 'Few-shot学習', '標準', '適用', '医師が生成AIを使って「症例報告の要約」を作成させたい場合、Few-shotプロンプティングの活用例として最も適切なものはどれか。', '「症例報告を要約してください」とだけ指示する', '2〜3件の症例報告要約の例を示してから、新しい症例報告の要約を依頼する', '可能な限り長い指示文を作成する', 'AIに症例報告の原文を読み上げさせる', 'B', 'Few-shotプロンプティングでは、期待する出力の例を示すことで、AIがその形式やスタイルを理解しやすくなります。症例報告の要約を作成させる場合、2〜3件の良い要約例を示してから新しい症例報告を渡すことで、AIは期待される要約の構成、長さ、含めるべき情報などを学習し、より適切な要約を生成できます。', 'A: 例なしの指示ではAIが期待する形式を理解しにくいです。C: 指示文の長さと出力品質は必ずしも比例しません。D: 読み上げはFew-shotプロンプティングとは異なります。', 'プロンプトエンジニアリング・Few-shot'),
('Q6-013', '第6章', '業務効率化', '易', '理解', '医療現場で生成AIを業務効率化に活用できる場面として、適切でないものはどれか。', '会議の議事録作成支援', '患者説明資料の下書き作成', '医師の診断の代替', '医学文献の要約作成', 'C', '生成AIは会議議事録、説明資料、文献要約などの文書作成業務の効率化に活用できます。しかし、医師の診断を代替することは医師法に抵触する可能性があり、また生成AIの信頼性の観点からも不適切です。診断は医師の専門的判断であり、AIはあくまで支援ツールとして位置づけられるべきです。', 'A: 議事録作成は適切な活用場面です。B: 説明資料の下書き作成は適切な活用場面です。D: 文献要約は（検証を前提に）適切な活用場面です。', '医療従事者向け生成AI活用ガイド'),
('Q6-014', '第6章', 'プロンプトエンジニアリング', '難', '分析', '生成AIへのプロンプトにおいて「制約条件」を明示することの利点として、最も適切なものはどれか。', 'AIの処理速度が向上する', '「200文字以内」「箇条書きで」などの条件により、用途に適した形式の出力が得られる', 'AIの学習データが更新される', 'AIの消費電力が削減される', 'B', 'プロンプトに制約条件（文字数制限、出力形式、含めるべき/含めない情報など）を明示することで、用途に適した形式の出力が得られます。例えば「200文字以内で」と指定すれば簡潔な要約が、「箇条書きで」と指定すれば視認性の高いリストが得られます。医療現場では、限られた時間で情報を把握する必要があるため、制約条件の活用は重要です。', 'A: 制約条件は処理速度向上を目的としていません。C: 学習データの更新とは関係ありません。D: 消費電力とは関係ありません。', 'プロンプトエンジニアリング・ベストプラクティス'),
('Q6-015', '第6章', '生成AI利用ポリシー', '標準', '理解', '医療機関が生成AI利用ポリシーを策定する際に含めるべき内容として、適切でないものはどれか。', '生成AIに入力してよい情報と入力禁止の情報の区分', '生成AIの出力を使用する際の検証プロセス', '生成AIを使用する職員の服装規定', 'インシデント発生時の報告・対応手順', 'C', '医療機関の生成AI利用ポリシーには、入力情報の制限、出力の検証プロセス、インシデント対応手順、責任の所在、利用可能なサービスの指定などが含まれるべきです。職員の服装規定は生成AI利用とは無関係であり、利用ポリシーに含める内容としては不適切です。', 'A: 入力情報の区分は個人情報保護の観点から重要な内容です。B: 出力の検証プロセスは品質確保のために必要です。D: インシデント対応手順は安全管理上重要です。', '医療機関における生成AIガバナンス'),
('Q6-016', '第6章', '医療文書作成支援', '標準', '適用', '薬剤師が生成AIを使って患者向けの服薬指導資料を作成する際、プロンプトに含めるべき情報として、最も適切なものはどれか。', '患者の氏名と住所', '説明対象の薬効分類、想定する読者層、含めたい情報項目', '患者の健康保険証番号', '処方医の携帯電話番号', 'B', '服薬指導資料を作成する際のプロンプトには、薬効分類（例：降圧薬）、想定する読者層（高齢者向け、など）、含めたい情報項目（用法用量、副作用、注意事項など）を明示することで、適切な資料が生成されます。患者個人を特定する情報（氏名、住所、保険証番号など）は入力すべきではありません。', 'A: 患者の氏名と住所は個人情報であり、入力すべきではありません。C: 保険証番号は個人識別情報であり、入力禁止です。D: 処方医の連絡先は不要であり、個人情報に該当する可能性があります。', '医療従事者向け生成AI利用指針'),
('Q6-017', '第6章', '文献検索・要約', '難', '評価', '生成AIを医学文献のシステマティックレビューに活用する際の限界として、最も重要なものはどれか。', '生成AIは文献を日本語に翻訳できない', '生成AIには知識のカットオフ日があり、最新の文献を網羅的に検索できない可能性がある', '生成AIは医学用語を理解できない', '生成AIは表形式のデータを出力できない', 'D', 'システマティックレビューでは、対象分野の文献を網羅的に検索することが重要です。しかし、生成AIには学習データのカットオフ日があり、それ以降に発表された最新の論文は含まれていません。また、特定のデータベースを直接検索する機能がない場合、網羅的な文献収集には限界があります。正式なシステマティックレビューにはPubMed等の専門データベースの利用が必要です。', 'A: 生成AIは多言語翻訳が可能です。C: 生成AIは医学用語を一定程度理解できます。D: 生成AIは表形式のデータも出力可能です。', '生成AIの限界・システマティックレビュー方法論'),
('Q6-018', '第6章', '出力の検証', '易', '記憶（知識）', '生成AIの「知識のカットオフ日」について、正しい説明はどれか。', '生成AIが1日に処理できる質問の上限数', '生成AIの学習データに含まれる最新の情報の日付であり、それ以降の情報は含まれていない', '生成AIの利用契約が終了する日', '生成AIのメンテナンス終了予定日', 'D', '知識のカットオフ日（Knowledge Cutoff Date）とは、生成AIモデルの学習データに含まれる情報の最新日付を指します。この日付以降に発生した出来事や発表された論文などの情報はモデルの学習に含まれておらず、AIはそれらについて正確に回答できません。医療分野では新しい研究やガイドライン改訂があるため、この点に注意が必要です。', 'A: 1日の質問上限とは異なる概念です。C: 利用契約の終了日ではありません。D: メンテナンス終了日でもありません。', '生成AIの基本概念'),
('Q6-019', '第6章', '業務効率化', '標準', '適用', '看護師が申し送り事項を整理するために生成AIを活用する場合、適切な利用方法はどれか。', '患者名と詳細な病状を入力して、申し送り文を生成させる', '一般的な申し送りの構成例を生成させ、それを参考に自分で内容を作成する', '生成AIに申し送りの内容を判断させ、重要度を決定してもらう', '患者のバイタルデータを入力して、異常値を判定させる', 'B', '申し送りに生成AIを活用する適切な方法は、構成例やテンプレートを生成させ、それを参考に自分で内容を作成することです。患者個人を特定する情報の入力はプライバシーリスクがあり避けるべきです。また、申し送りの重要度判断や異常値判定は専門職の判断が必要であり、AIに委ねるべきではありません。', 'A: 患者名と病状の入力はプライバシーリスクがあります。C: 重要度の判断は看護師の専門的判断が必要です。D: 異常値判定は医療行為に関わり、AIに委ねるべきではありません。', '看護業務における生成AI活用指針'),
('Q6-020', '第6章', 'プロンプトエンジニアリング', '標準', '理解', '生成AIへのプロンプトで「否定的な指示」（〜しないでください）よりも「肯定的な指示」（〜してください）が推奨される理由として、最も適切なものはどれか。', '否定的な指示はAIが処理できないため', '肯定的な指示の方が、期待する出力を明確に伝えやすいため', '否定的な指示は消費電力が増加するため', '否定的な指示は著作権に違反するため', 'B', '「専門用語を使わないでください」よりも「小学生にも分かる言葉で説明してください」のように、肯定的な指示の方が期待する出力を明確に伝えられます。否定的な指示は「何を避けるか」は示しますが「何をするか」が曖昧になりがちです。肯定的な指示により、AIはより具体的な方向性を持って出力を生成できます。', 'A: AIは否定的な指示も処理できますが、効果が限定的です。C: 消費電力とは関係ありません。D: 著作権とは関係ありません。', 'プロンプトエンジニアリング・ベストプラクティス'),
('Q6-021', '第6章', '患者コミュニケーション', '難', '評価', '医師が生成AIを使って患者への病状説明資料を作成した。この資料を患者に提供する前に最も重要な確認事項はどれか。', '資料の文字数が適切かどうか', '医学的内容の正確性と、患者の個別状況への適合性', '資料の色使いが見やすいかどうか', '資料のファイルサイズが小さいかどうか', 'B', '生成AIで作成した医療情報を患者に提供する前に最も重要なのは、医学的内容の正確性（ハルシネーションがないか）と、患者の個別状況への適合性（その患者に当てはまる内容か）を確認することです。誤った情報や不適切な情報が患者の判断に影響を与える可能性があるため、専門家としての確認が不可欠です。', 'A: 文字数は形式的な要素であり、内容の正確性より優先度は低いです。C: 色使いは読みやすさに関係しますが、内容の正確性が最優先です。D: ファイルサイズは技術的な問題であり、医学的正確性より優先度は低いです。', '医療情報の品質管理'),
('Q6-022', '第6章', 'Chain-of-Thought', '標準', '適用', '医師が生成AIに複雑な鑑別診断の考え方を整理させたい場合、Chain-of-Thoughtプロンプティングの適切な使用例はどれか。', '「鑑別診断を教えて」と端的に質問する', '「症状から考えられる疾患を、ステップバイステップで論理的に推論してください」と指示する', '「最も確率の高い診断名だけを答えてください」と指示する', '「はい」か「いいえ」で答えられる質問をする', 'B', 'Chain-of-Thought（CoT）プロンプティングでは、「ステップバイステップで」「段階的に」「論理的に推論して」などの指示を加えることで、AIに推論過程を明示させます。鑑別診断のような複雑な推論タスクでは、思考過程を示させることで、より論理的で検証可能な出力が得られ、どの段階で誤りがあるか確認しやすくなります。', 'A: 端的な質問ではCoTの効果が得られません。C: 結論だけを求めるのはCoTとは逆のアプローチです。D: はい/いいえの質問は推論過程を引き出せません。', 'プロンプトエンジニアリング・CoT技法'),
('Q6-023', '第6章', '生成AI利用ポリシー', '易', '理解', '医療機関で生成AIを業務利用する際に、組織として決めておくべきルールとして最も重要なものはどれか。', '生成AIを使用する端末の画面サイズ', '生成AIに入力してはいけない情報の範囲と、出力の検証責任', '生成AIを使用する時間帯', '生成AIの利用回数の上限', 'B', '医療機関で生成AIを業務利用する際に最も重要なルールは、個人情報保護の観点から入力禁止情報を明確にすることと、出力の品質を確保するために誰が検証責任を負うかを定めることです。これにより、プライバシーリスクの軽減と情報の正確性確保が可能になります。', 'A: 画面サイズは利用ルールの本質的な要素ではありません。C: 使用時間帯は運用上の問題であり、最重要ではありません。D: 利用回数上限は必須のルールではありません。', '医療機関における生成AI利用ポリシー'),
('Q6-024', '第6章', '出力の検証', '標準', '適用', '生成AIに「高血圧治療ガイドライン2019の推奨」について質問したところ、回答が得られた。この回答を業務に使用する前に行うべき検証として、最も適切なものはどれか。', '回答の文字数が十分かどうか確認する', '実際のガイドライン原本と照合し、内容の正確性を確認する', '別の生成AIサービスで同じ質問をして、回答が一致するか確認する', '回答の文章が読みやすいか確認する', 'B', '生成AIは、存在しないガイドラインの内容を生成したり、実際のガイドラインと異なる内容を出力したりする可能性があります。特定のガイドラインの推奨事項を確認する場合は、必ず実際のガイドライン原本と照合し、内容が正確かどうかを検証する必要があります。', 'A: 文字数は内容の正確性とは関係ありません。C: 複数のAIで一致しても、原典と異なる可能性があります。D: 読みやすさは形式の問題であり、正確性検証とは別です。', 'エビデンスに基づく医療情報の検証'),
('Q6-025', '第6章', '業務効率化', '難', '分析', '医療機関が生成AIを業務効率化に導入する際、最も大きな効果が期待できる業務領域はどれか。', '診断の自動化', '定型的な文書作成や情報整理などの事務的業務', '手術の実施', '注射の実施', 'B', '生成AIは文章の生成・要約・翻訳などに優れており、定型的な文書作成、会議議事録の整理、患者説明資料の下書きなどの事務的業務において大きな効率化効果が期待できます。一方、診断や手術、注射などの医療行為は専門的判断や技術が必要であり、生成AIで代替することは適切ではありません。', 'A: 診断は医師の専門的判断が必要であり、自動化の対象としては適切ではありません。C: 手術は身体的技術を伴い、生成AIの対象外です。D: 注射も身体的行為であり、生成AIとは無関係です。', '医療DX・生成AI活用事例'),
('Q6-026', '第6章', 'プロンプトエンジニアリング', '易', '記憶（知識）', '生成AIへのプロンプトにおける「コンテキスト」の役割として、最も適切なものはどれか。', 'AIの処理速度を向上させる', '背景情報や状況を提供し、より適切な回答を引き出す', 'AIの消費電力を削減する', 'AIの学習データを更新する', 'B', 'コンテキスト（文脈）とは、プロンプトに含める背景情報や状況説明のことです。例えば「私は内科医です」「高齢患者向けの説明を作成しています」といった情報を提供することで、AIはより状況に適した回答を生成できます。コンテキストが不足すると、AIは汎用的な回答しか生成できません。', 'A: コンテキストは処理速度向上を目的としていません。C: 消費電力とは関係ありません。D: 学習データの更新とは異なります。', 'プロンプトエンジニアリングの基本'),
('Q6-027', '第6章', '医療文書作成支援', '標準', '適用', '医療事務職が生成AIを使って患者向けの受診案内文書を作成する場合、適切な対応はどれか。', '生成AIに患者の個人情報を入力して、個別の案内文を作成させる', '一般的な受診案内のテンプレートを生成させ、内容を確認してから使用する', '生成AIの出力をそのまま全患者に配布する', '生成AIに診療予約の管理を任せる', 'C', '医療事務職が生成AIを活用する適切な方法は、一般的な受診案内のテンプレートや文例を生成させ、内容の正確性を確認してから使用することです。患者の個人情報を入力することはプライバシーリスクがあり避けるべきです。また、確認なしの配布や、予約管理などの業務システムとしての利用は不適切です。', 'A: 個人情報の入力はプライバシーリスクがあります。C: 確認なしの配布は内容の正確性を保証できません。D: 予約管理は業務システムの範疇であり、生成AIの適切な用途ではありません。', '医療機関における生成AI活用指針'),
('Q6-028', '第6章', '文献検索・要約', '標準', '理解', '生成AIを使って医学論文の要約を作成させる際の適切なプロンプト指示はどれか。', 'この論文について教えてください', 'この論文の目的、方法、結果、結論を200文字程度で要約してください', 'この論文は正しいですか', 'この論文を暗記してください', 'A', '効果的なプロンプトは、具体的な構成（目的、方法、結果、結論）と分量（200文字程度）を指定することで、期待する形式の要約を得られます。漠然とした質問や、AIが答えられない質問（正否の判断、暗記の要求など）は適切ではありません。', 'A: 「教えてください」は漠然としており、期待する形式の要約が得られにくいです。C: 論文の正否判断は複雑な専門的評価が必要であり、AIに任せるべきではありません。D: AIは「暗記」という行為はできず、不適切な指示です。', '医学文献の効果的な要約方法'),
('Q6-029', '第6章', '生成AI利用ポリシー', '難', '評価', '医療機関で生成AI利用教育を実施する際に、最も重要な教育内容はどれか。', '生成AIの技術的な仕組み（ニューラルネットワークの構造など）の詳細', '生成AIの限界とリスク、入力禁止情報、出力の検証方法', '生成AIを開発した企業の歴史', '生成AIの市場動向と株価', 'A', '医療機関で生成AIを安全に活用するためには、職員が生成AIの限界（ハルシネーション、知識のカットオフなど）、入力してはいけない情報（個人情報など）、出力の検証方法を理解することが最も重要です。技術的な詳細や企業情報は実務上の利用には必須ではありません。', 'A: 技術的詳細は利用者教育として必須ではありません。C: 企業の歴史は実務利用に直結しません。D: 市場動向や株価は業務利用とは関係ありません。', '医療従事者向け生成AI教育'),
('Q6-030', '第6章', '出力の検証', '易', '理解', '生成AIの出力を医療業務に活用する際の基本姿勢として、最も適切なものはどれか。', '生成AIは常に正確なので、出力をそのまま信頼してよい', '生成AIは一切信用できないので、使用すべきでない', '生成AIの出力を参考にしつつ、専門知識に基づいて内容を検証する', '生成AIの出力は、上司が確認すれば自分で検証する必要はない', 'C', '生成AIの出力は参考情報として有用ですが、ハルシネーションや古い情報のリスクがあるため、そのまま信用することは危険です。一方で、一切使用しないのは有用なツールの活用機会を逃すことになります。適切な姿勢は、出力を参考にしつつ、専門知識に基づいて内容を検証することです。', 'A: 生成AIは常に正確とは限らず、検証が必要です。B: 適切に使用すれば業務効率化に有用であり、一切使用禁止は過剰です。D: 利用者自身が内容を理解し検証する責任があります。', '生成AI利用の基本原則'),
('Q6-031', '第6章', '患者コミュニケーション', '標準', '適用', '外国人患者への説明資料を作成するために生成AIの翻訳機能を活用する場合、最も適切な対応はどれか。', '生成AIの翻訳をそのまま患者に渡す', '翻訳の正確性を可能な範囲で確認し、重要な内容は通訳を介して補足する', '翻訳機能は信頼できないため、外国語での説明は一切行わない', '患者に翻訳内容の責任を負わせる同意書に署名させる', 'B', '生成AIの翻訳は便利ですが、医療専門用語や微妙なニュアンスが正確に伝わらない可能性があります。適切な対応は、翻訳の正確性を可能な範囲で確認し、特に重要な内容（同意事項、注意事項など）は医療通訳を介して補足することです。翻訳を全く使わないのは不便であり、患者に責任転嫁するのは不適切です。', 'A: 確認なしにそのまま渡すのは誤訳のリスクがあります。C: 翻訳を一切行わないのは外国人患者への対応として不十分です。D: 医療機関側の責任を患者に転嫁することは不適切です。', '外国人患者対応・医療通訳ガイドライン'),
('Q6-032', '第6章', 'プロンプトエンジニアリング', '難', '分析', '生成AIに医学的な質問をした際、「私はAIであり、医療アドバイスを提供することはできません」という回答が返ってきた。この場合の適切な対応はどれか。', '別の生成AIサービスを使用して同じ質問をする', '「一般的な医学情報として」「教育目的で」などの文脈を明示してプロンプトを修正する', '生成AIは医療情報を一切扱えないと判断し、使用を諦める', 'AIの制限を解除するハッキング手法を試みる', 'B', '生成AIは安全性の観点から、医療アドバイスの直接提供を制限している場合があります。「一般的な医学情報として」「医学生への教育目的で」「専門家が確認することを前提に」などの文脈を明示することで、AIは情報提供に応じる場合があります。ただし、得られた情報は必ず専門家が確認する必要があります。', 'A: 別のサービスでも同様の制限がある可能性があります。C: プロンプトの工夫で対応できる場合があります。D: ハッキングは利用規約違反であり、絶対に行ってはいけません。', '生成AIの安全機能とプロンプト設計'),
('Q6-033', '第6章', '業務効率化', '易', '理解', '生成AIを医療従事者の継続教育に活用する方法として、最も適切なものはどれか。', '生成AIに医師国家試験の問題を作成させ、解答も全てAIに任せる', '学習内容の要約作成や、疑問点の整理に活用し、公式教材で内容を確認する', '生成AIの出力のみで資格試験の勉強を完結させる', '生成AIに資格の合否を判定させる', 'B', '生成AIは継続教育において、学習内容の要約作成、疑問点の整理、練習問題の作成などの補助ツールとして有用です。ただし、内容の正確性を担保するため、必ず公式教材や信頼できる情報源で確認することが重要です。生成AIのみに依存した学習や、資格判定への使用は不適切です。', 'A: 解答を全てAIに任せることは学習効果が低く、内容の正確性も保証されません。C: 生成AIのみで試験勉強を完結させるのは、誤情報のリスクがあります。D: 資格の合否判定は正式な機関が行うものであり、AIに任せるべきではありません。', '生涯教育における生成AI活用'),
('Q6-034', '第6章', 'Few-shot学習', '標準', '理解', 'Few-shotプロンプティングにおいて、提示する例の数について正しい説明はどれか。', '例は多ければ多いほど常に良い結果が得られる', '2〜5個程度の質の高い例を示すことが効果的であり、多すぎると逆効果になる場合もある', '例は1個だけ示すのが最も効果的である', '例を示す必要はない', 'D', 'Few-shotプロンプティングでは、2〜5個程度の質の高い例を示すことが効果的とされています。例が少なすぎるとパターンを理解しにくく、多すぎるとトークン数の制限やノイズの増加により効果が低下する場合があります。重要なのは例の「数」よりも「質」であり、期待する出力を明確に示す例を選ぶことが大切です。', 'A: 例は多すぎると逆効果になる場合があります。C: 1個の例（One-shot）より複数の例（Few-shot）の方が効果的な場合が多いです。D: 例を示さないのはZero-shotであり、Few-shotとは異なります。', 'プロンプトエンジニアリング・Few-shot技法'),
('Q6-035', '第6章', '出力の検証', '難', '評価', '医療機関で生成AIを導入・運用する際の成功要因として、最も重要なものはどれか。', '最新かつ最も高価な生成AIサービスを導入すること', '明確な利用目的、適切なガバナンス体制、継続的な教育と改善のサイクル', 'できるだけ多くの業務に生成AIを適用すること', '生成AIの導入を全職員に強制すること', 'B', '医療機関で生成AIを成功裏に導入・運用するためには、(1)何のために使うかの明確な目的設定、(2)入力禁止情報や出力検証などのガバナンス体制の整備、(3)職員への継続的な教育と、運用状況を踏まえた改善のサイクルが重要です。高価なサービスや多くの業務への適用、強制よりも、適切な管理体制の構築が成功の鍵です。', 'A: 高価であることが成功を保証するわけではなく、目的に適したサービス選択が重要です。C: むやみに多くの業務に適用するより、効果的な領域に絞ることが重要です。D: 強制ではなく、理解と納得に基づく活用が望ましいです。', '医療DX・生成AI導入の成功事例');